const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formType, setFormType] = useState<TransactionType>(TransactionType.SALE);

  // Load data from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('easyin_transactions_v1');
    if (saved) {
      try {
        setTransactions(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse transactions", e);
        setTransactions(MOCK_DATA);
      }
    } else {
      setTransactions(MOCK_DATA);
    }
  }, []);

  // Save data on change
  useEffect(() => {
    localStorage.setItem('easyin_transactions_v1', JSON.stringify(transactions));
  }, [transactions]);

  const handleNavigate = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleAddTransaction = (type: TransactionType) => {
    setFormType(type);
    setEditingTransaction(null);
    setViewState('form');
  };

  const handleEditTransaction = (transaction: Transaction) => {
    setFormType(transaction.type);
    setEditingTransaction(transaction);
    setViewState('form');
  };

  const handleDeleteTransaction = (id: string) => {
    // Confirmation handled in TransactionList
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
  };

  const renderContent = () => {
    if (activeTab === 'dashboard') {
      return <Dashboard transactions={transactions} />;
    }

    if (activeTab === 'ai-insights') {
      return <AiAdvisor transactions={transactions} />;
    }

    if (activeTab === 'reports') {
      return <Reports transactions={transactions} />;
    }

    if (activeTab === 'sales' || activeTab === 'purchase') {
      const type = activeTab === 'sales' ? TransactionType.SALE : TransactionType.PURCHASE;

      if (viewState === 'form') {
        return (
          <TransactionForm 
            type={type} 
            initialData={editingTransaction}
            onSave={handleSaveTransaction}
            onCancel={() => setViewState('list')}
          />
        );
      }

      return (
        <TransactionList 
          type={type}
          transactions={transactions}
          onAdd={() => handleAddTransaction(type)}
          onEdit={handleEditTransaction}
          onDelete={handleDeleteTransaction}
        />
      );
    }

    return <div>Page not found</div>;
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, TransactionType } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  const doc = new jsPDF();

  // Company Header
  doc.setFontSize(22);
  doc.setTextColor(37, 99, 235); // Blue-600
  doc.text("Balvi Print Hub", 14, 20);

  doc.setFontSize(10);
  doc.setTextColor(100, 100, 100);
  doc.text("Professional Printing Solutions", 14, 25);
  doc.text("Mumbai, Maharashtra", 14, 30);
  // Add more company details if needed

  // Invoice Details Right Side
  const rightX = 140;
  doc.setFontSize(16);
  doc.setTextColor(0, 0, 0);
  doc.text(transaction.type === TransactionType.SALE ? "INVOICE" : "PURCHASE ORDER", rightX, 20);

  doc.setFontSize(10);
  doc.setTextColor(100, 100, 100);
  doc.text(`Invoice No: ${transaction.invoiceNumber}`, rightX, 30);
  doc.text(`Date: ${transaction.date}`, rightX, 35);
  doc.text(`Status: ${transaction.status}`, rightX, 40);

  // Divider
  doc.setDrawColor(200, 200, 200);
  doc.line(14, 45, 196, 45);

  // Bill To
  doc.setFontSize(12);
  doc.setTextColor(0, 0, 0);
  doc.text("Bill To:", 14, 55);
  doc.setFontSize(11);
  doc.setFont(undefined, 'bold');
  doc.text(transaction.partyName, 14, 61);
  doc.setFont(undefined, 'normal');
  doc.setFontSize(10);
  doc.setTextColor(80, 80, 80);

  if (transaction.partyAddress) {
    const splitAddress = doc.splitTextToSize(transaction.partyAddress, 80);
    doc.text(splitAddress, 14, 66);
  }

  // Table
  const tableColumn = ["#", "Description", "Material", "Size (AxB)", "SqFt", "Qty", "Rate", "Amount"];
  const tableRows = transaction.items.map((item, index) => {
    const sizeStr = item.sizeA > 0 && item.sizeB > 0 ? `${item.sizeA} x ${item.sizeB}` : "-";
    const sqFtStr = item.sqFt > 0 ? item.sqFt.toString() : "-";
    return [
      index + 1,
      item.description,
      item.material || "-",
      sizeStr,
      sqFtStr,
      item.quantity,
      item.rate,
      item.amount.toFixed(2)
    ];
  });

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 85,
    theme: 'grid',
    headStyles: { fillColor: [37, 99, 235], textColor: 255 }, // Blue header
    styles: { fontSize: 9, cellPadding: 3 },
    columnStyles: {
      0: { cellWidth: 10 }, // #
      1: { cellWidth: 50 }, // Description
      2: { cellWidth: 30 }, // Material
      3: { cellWidth: 20 }, // Size
      4: { cellWidth: 15 }, // SqFt
      5: { cellWidth: 15 }, // Qty
      6: { cellWidth: 20 }, // Rate
      7: { cellWidth: 25, halign: 'right' }, // Amount
    },
    foot: [
        [
            "", 
            "", 
            "",
            "", 
            "", 
            "Total", 
            "", 
            transaction.subTotal.toFixed(2)
        ]
    ]
  });

  // Totals Section
  const lastTableY = (doc as any).lastAutoTable?.finalY || 150;
  const finalY = lastTableY + 10;

  // Box for totals
  doc.setFillColor(248, 250, 252);
  doc.rect(130, finalY - 5, 70, 30, 'F');

  doc.setFontSize(10);
  doc.setTextColor(70, 70, 70);

  doc.text(`Sub Total:`, 140, finalY);
  doc.text(`${transaction.subTotal.toFixed(2)}`, 190, finalY, { align: "right" });

  doc.text(`Tax Total:`, 140, finalY + 7);
  doc.text(`${transaction.totalTax.toFixed(2)}`, 190, finalY + 7, { align: "right" });

  doc.setFontSize(12);
  doc.setTextColor(0, 0, 0);
  doc.setFont(undefined, 'bold');
  doc.text(`Grand Total:`, 140, finalY + 16);
  doc.text(`${transaction.grandTotal.toFixed(2)}`, 190, finalY + 16, { align: "right" });

  // Footer
  doc.setFontSize(9);
  doc.setFont(undefined, 'normal');
  doc.setTextColor(150, 150, 150);
  doc.text("Thank you for your business!", 105, 280, { align: "center" });
  doc.text("Generated via EasyIn", 105, 285, { align: "center" });

  doc.save(`${transaction.invoiceNumber}.pdf`);
};

