import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Calculator } from 'lucide-react';
import { LineItem, Transaction, TransactionType } from '../types';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData }) => {
  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`${type === TransactionType.SALE ? 'INV' : 'PUR'}-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Calculate SqFt: Size A * Size B
        if (field === 'sizeA' || field === 'sizeB') {
           updated.sqFt = Number((updated.sizeA * updated.sizeB).toFixed(2));
        }

        // Calculate Amount: Total SqFt * Rate * Qty
        // If dimensions are provided (Size A & Size B > 0), use the SqFt formula
        // Otherwise treat as standard Qty * Rate
        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;

        let baseAmount = 0;
        if (isDimensional) {
           baseAmount = updated.sqFt * updated.rate * updated.quantity;
        } else {
           baseAmount = updated.quantity * updated.rate;
        }

        updated.amount = Number(baseAmount.toFixed(2));

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { 
      id: Date.now().toString(), 
      description: '', 
      material: '',
      sizeA: 0, 
      sizeB: 0, 
      sqFt: 0, 
      quantity: 1, 
      rate: 0, 
      unit: 'sqft', 
      amount: 0 
    }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(i => i.id !== id));
    }
  };

  const calculateTotals = () => {
    const subTotal = items.reduce((acc, item) => {
        const isDimensional = item.sizeA > 0 && item.sizeB > 0;
        const base = isDimensional 
            ? item.sqFt * item.rate * item.quantity 
            : item.quantity * item.rate;
        return acc + base;
    }, 0);

    const grandTotal = subTotal;
    return { subTotal, grandTotal };
  };

  const handleSave = () => {
    if (!partyName) {
      alert("Please enter a client name");
      return;
    }
    const totals = calculateTotals();
    const transaction: Transaction = {
      id: initialData ? initialData.id : Date.now().toString(),
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      subTotal: totals.subTotal,
      grandTotal: totals.grandTotal,
      status
    };
    onSave(transaction);
  };

  const totals = calculateTotals();

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full">
      {/* Header Bar */}
      <div className="border-b border-slate-200 p-4 lg:p-6 flex justify-between items-center bg-slate-50">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <ArrowLeft size={20} className="text-slate-600" />
          </button>
          <div>
            <h2 className="text-xl font-bold text-slate-900">
              {initialData ? 'Edit' : 'New'} {type === TransactionType.SALE ? 'Sale' : 'Purchase'}
            </h2>
            <p className="text-sm text-slate-500">
               {type === TransactionType.SALE ? 'Create invoice for client' : 'Record purchase bill'}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-md border border-slate-200">
              <label className="text-sm font-medium text-slate-600">Status:</label>
              <select 
                value={status} 
                onChange={(e) => setStatus(e.target.value as 'PAID' | 'UNPAID')}
                className={`text-sm font-bold bg-transparent outline-none ${status === 'PAID' ? 'text-green-600' : 'text-red-600'}`}
              >
                <option value="PAID">PAID</option>
                <option value="UNPAID">UNPAID</option>
              </select>
           </div>
           <button 
            onClick={handleSave}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium shadow-sm"
           >
            <Save size={18} />
            <span className="hidden sm:inline">Save</span>
          </button>
        </div>
      </div>

      {/* Main Form Content */}
      <div className="p-4 lg:p-6 space-y-6 flex-1 overflow-y-auto">
        {/* Invoice Header Fields */}
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 p-4 bg-slate-50 rounded-xl border border-slate-200">
          <div className="md:col-span-4 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">
                Client Name <span className="text-red-500">*</span>
            </label>
            <input 
              type="text" 
              value={partyName}
              onChange={(e) => setPartyName(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
              placeholder="e.g. Balvi Print Hub"
            />
          </div>

          <div className="md:col-span-2 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">Invoice No</label>
            <input 
              type="text" 
              value={invoiceNumber}
              onChange={(e) => setInvoiceNumber(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            />
          </div>

          <div className="md:col-span-2 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">Date</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            />
          </div>

          <div className="md:col-span-4 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">Address / Second Area</label>
            <input 
              type="text" 
              value={partyAddress}
              onChange={(e) => setPartyAddress(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
              placeholder="Enter details..."
            />
          </div>
        </div>

        {/* Items Table */}
        <div className="border border-slate-200 rounded-lg overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full min-w-[1000px]">
              <thead>
                <tr className="bg-slate-100 border-b border-slate-200 text-left text-xs font-bold text-slate-600 uppercase tracking-wider">
                  <th className="py-3 px-3 w-8">#</th>
                  <th className="py-3 px-3 w-48">Description</th>
                  <th className="py-3 px-3 w-32">Material</th>
                  <th className="py-3 px-3 w-20">Size A</th>
                  <th className="py-3 px-3 w-20">Size B</th>
                  <th className="py-3 px-3 w-24 bg-blue-50/50">Total SqFt</th>
                  <th className="py-3 px-3 w-20">Qty</th>
                  <th className="py-3 px-3 w-24">Rate</th>
                  <th className="py-3 px-3 text-right w-32">Amount</th>
                  <th className="py-3 px-3 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {items.map((item, index) => (
                  <tr key={item.id} className="group hover:bg-slate-50">
                    <td className="py-2 px-3 text-slate-400 text-sm">{index + 1}</td>
