const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formType, setFormType] = useState<TransactionType>(TransactionType.SALE);

  // Load data from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('easyin_transactions_v1');
    if (saved) {
      try {
        setTransactions(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse transactions", e);
        setTransactions(MOCK_DATA);
      }
    } else {
      setTransactions(MOCK_DATA);
    }
  }, []);

  // Save data on change
  useEffect(() => {
    localStorage.setItem('easyin_transactions_v1', JSON.stringify(transactions));
  }, [transactions]);

  const handleNavigate = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleAddTransaction = (type: TransactionType) => {
    setFormType(type);
    setEditingTransaction(null);
    setViewState('form');
  };

  const handleEditTransaction = (transaction: Transaction) => {
    setFormType(transaction.type);
    setEditingTransaction(transaction);
    setViewState('form');
  };

  const handleDeleteTransaction = (id: string) => {
    // Confirmation handled in TransactionList
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
  };

  const renderContent = () => {
    if (activeTab === 'dashboard') {
      return <Dashboard transactions={transactions} />;
    }

    if (activeTab === 'ai-insights') {
      return <AiAdvisor transactions={transactions} />;
    }

    if (activeTab === 'reports') {
      return <Reports transactions={transactions} />;
    }

    if (activeTab === 'sales') {
      const type = TransactionType.SALE;

      if (viewState === 'form') {
        return (
          <TransactionForm 
            type={type} 
            initialData={editingTransaction}
            onSave={handleSaveTransaction}
            onCancel={() => setViewState('list')}
          />
        );
      }

      return (
        <TransactionList 
          type={type}
          transactions={transactions}
          onAdd={() => handleAddTransaction(type)}
          onEdit={handleEditTransaction}
          onDelete={handleDeleteTransaction}
        />
      );
    }

    return <div>Page not found</div>;
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Calculator } from 'lucide-react';
import { LineItem, Transaction, TransactionType } from '../types';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData }) => {
  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [isEstimate, setIsEstimate] = useState(false);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
      setIsEstimate(initialData.isEstimate || false);
    } else {
      setInvoiceNumber(`${type === TransactionType.SALE ? 'INV' : 'PUR'}-${Math.floor(1000 + Math.random() * 9000)}`);
      setIsEstimate(false);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Calculate SqFt: Size A * Size B
        if (field === 'sizeA' || field === 'sizeB') {
           updated.sqFt = Number((updated.sizeA * updated.sizeB).toFixed(2));
        }

        // Calculate Amount: Total SqFt * Rate * Qty
        // If dimensions are provided (Size A & Size B > 0), use the SqFt formula
        // Otherwise treat as standard Qty * Rate
        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;

        let baseAmount = 0;
        if (isDimensional) {
           baseAmount = updated.sqFt * updated.rate * updated.quantity;
        } else {
           baseAmount = updated.quantity * updated.rate;
        }

        updated.amount = Number(baseAmount.toFixed(2));

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { 
      id: Date.now().toString(), 
      description: '', 
      material: '',
      sizeA: 0, 
      sizeB: 0, 
      sqFt: 0, 
      quantity: 1, 
      rate: 0, 
      unit: 'sqft', 
      amount: 0 
    }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(i => i.id !== id));
    }
  };

  const calculateTotals = () => {
    const subTotal = items.reduce((acc, item) => {
        const isDimensional = item.sizeA > 0 && item.sizeB > 0;
        const base = isDimensional 
            ? item.sqFt * item.rate * item.quantity 
            : item.quantity * item.rate;
        return acc + base;
    }, 0);

    const grandTotal = subTotal;
    return { subTotal, grandTotal };
  };

  const handleSave = () => {
    if (!partyName) {
      alert("Please enter a client name");
      return;
    }
    const totals = calculateTotals();
    const transaction: Transaction = {
      id: initialData ? initialData.id : Date.now().toString(),
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      subTotal: totals.subTotal,
      grandTotal: totals.grandTotal,
      status,
      isEstimate
    };
    onSave(transaction);
  };

  const totals = calculateTotals();

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full">
      {/* Header Bar */}
      <div className="border-b border-slate-200 p-4 lg:p-6 flex flex-col md:flex-row justify-between items-start md:items-center bg-slate-50 gap-4">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <ArrowLeft size={20} className="text-slate-600" />
          </button>
          <div>
            <h2 className="text-xl font-bold text-slate-900">
              {initialData ? 'Edit' : 'New'} {type === TransactionType.SALE ? (isEstimate ? 'Estimate' : 'Sale') : 'Purchase'}
            </h2>
            <p className="text-sm text-slate-500">
               {type === TransactionType.SALE 
                  ? (isEstimate ? 'Create cost estimate' : 'Create invoice for client') 
                  : 'Record purchase bill'}
            </p>
          </div>
        </div>
        <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
           {/* Document Type Selector */}
           {type === TransactionType.SALE && (
             <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-md border border-slate-200">
                <label className="text-sm font-medium text-slate-600">Type:</label>
                <select 
                  value={isEstimate ? 'ESTIMATE' : 'INVOICE'} 
                  onChange={(e) => setIsEstimate(e.target.value === 'ESTIMATE')}
                  className="text-sm font-bold bg-transparent outline-none text-slate-800"
                >
                  <option value="INVOICE">Invoice</option>
                  <option value="ESTIMATE">Estimate</option>
                </select>
             </div>
           )}

           <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-md border border-slate-200">
              <label className="text-sm font-medium text-slate-600">Status:</label>
              <select 
                value={status} 
                onChange={(e) => setStatus(e.target.value as 'PAID' | 'UNPAID')}
                className={`text-sm font-bold bg-transparent outline-none ${status === 'PAID' ? 'text-green-600' : 'text-red-600'}`}
              >
                <option value="PAID">PAID</option>
                <option value="UNPAID">UNPAID</option>
              </select>
           </div>
           <button 
            onClick={handleSave}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium shadow-sm ml-auto md:ml-0"
           >
            <Save size={18} />
            <span className="hidden sm:inline">Save</span>
          </button>
        </div>
      </div>

      {/* Main Form Content */}
      <div className="p-4 lg:p-6 space-y-6 flex-1 overflow-y-auto">
        {/* Invoice Header Fields */}
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 p-4 bg-slate-50 rounded-xl border border-slate-200">
          <div className="md:col-span-4 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">
                Client Name <span className="text-red-500">*</span>
            </label>
            <input 
              type="text" 
              value={partyName}
              onChange={(e) => setPartyName(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
              placeholder="e.g. Balvi Print Hub"
            />
          </div>

          <div className="md:col-span-2 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">
                {isEstimate ? 'Estimate No' : 'Invoice No'}
            </label>
            <input 
              type="text" 
              value={invoiceNumber}
              onChange={(e) => setInvoiceNumber(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            />
          </div>

          <div className="md:col-span-2 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">Date</label>
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
            />
          </div>

          <div className="md:col-span-4 space-y-2">
            <label className="text-xs uppercase tracking-wider font-semibold text-slate-500">Address / Second Area</label>
            <input 
              type="text" 
              value={partyAddress}
              onChange={(e) => setPartyAddress(e.target.value)}
              className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
              placeholder="Enter details..."
            />
          </div>
        </div>

        {/* Items Table */}
        <div className="border border-slate-200 rounded-lg overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full min-w-[1000px]">
              <thead>
                <tr className="bg-slate-100 border-b border-slate-200 text-left text-xs font-bold text-slate-600 uppercase tracking-wider">
                  <th className="py-3 px-3 w-8">#</th>
                  <th className="py-3 px-3 w-48">Description</th>
                  <th className="py-3 px-3 w-32">Material</th>
                  <th className="py-3 px-3 w-20">Size A</th>
                  <th className="py-3 px-3 w-20">Size B</th>
                  <th className="py-3 px-3 w-24 bg-blue-50/50">Total SqFt</th>
                  <th className="py-3 px-3 w-20">Qty</th>
                  <th className="py-3 px-3 w-24">Rate</th>
                  <th className="py-3 px-3 text-right w-32">Amount</th>
                  <th className="py-3 px-3 w-10"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {items.map((item, index) => (
                  <tr key={item.id} className="group hover:bg-slate-50">
                    <td className="py-2 px-3 text-slate-400 text-sm">{index + 1}</td>
                    <td className="py-2 px-3">
                      <input 
                        type="text" 
                        value={item.description}
                        onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                        placeholder="Item Name / Desc"
                        className="w-full bg-transparent border border-transparent hover:border-slate-200 focus:border-blue-500 rounded px-2 py-1.5 focus:outline-none focus:ring-0 transition-colors"
                      />
                    </td>
                    <td className="py-2 px-3">
                      <input 
                        type="text" 
                        value={item.material || ''}
                        onChange={(e) => handleItemChange(item.id, 'material', e.target.value)}
                        placeholder="Material Type"
                        className="w-full bg-transparent border border-transparent hover:border-slate-200 focus:border-blue-500 rounded px-2 py-1.5 focus:outline-none focus:ring-0 transition-colors"
                      />
                    </td>
                    <td className="py-2 px-3">
                      <input 
                        type="number" 
                        min="0"
                        placeholder="0"
                        value={item.sizeA || ''}
                        onChange={(e) => handleItemChange(item.id, 'sizeA', parseFloat(e.target.value) || 0)}
                        className="w-full bg-transparent border border-slate-200 rounded px-2 py-1.5 text-center focus:border-blue-500 outline-none text-sm"
                      />
                    </td>
                    <td className="py-2 px-3">
                      <input 
                        type="number" 
                        min="0"
                        placeholder="0"
                        value={item.sizeB || ''}
                        onChange={(e) => handleItemChange(item.id, 'sizeB', parseFloat(e.target.value) || 0)}
                        className="w-full bg-transparent border border-slate-200 rounded px-2 py-1.5 text-center focus:border-blue-500 outline-none text-sm"
                      />
                    </td>
                    <td className="py-2 px-3 bg-blue-50/30">
                      <div className="flex items-center gap-1 text-slate-700 font-medium justify-center">
                        {item.sqFt > 0 ? item.sqFt : '-'}
                      </div>
                    </td>
                    <td className="py-2 px-3">
                       <input 
                        type="number" 
                        min="1"
                        value={item.quantity}
                        onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 0)}
                        className="w-full bg-transparent border border-slate-200 rounded px-2 py-1.5 text-center focus:border-blue-500 outline-none text-sm font-semibold"
                      />
                    </td>
                    <td className="py-2 px-3">
                      <input 
                        type="number" 
                        min="0"
                        value={item.rate || ''}
                        onChange={(e) => handleItemChange(item.id, 'rate', parseFloat(e.target.value) || 0)}
                        className="w-full bg-transparent border border-slate-200 rounded px-2 py-1.5 text-right focus:border-blue-500 outline-none text-sm"
                      />
                    </td>
                    <td className="py-2 px-3 text-right font-bold text-slate-900">
                      {item.amount.toFixed(2)}
                    </td>
                    <td className="py-2 px-3 text-center">
                      <button 
                        onClick={() => removeItem(item.id)}
                        className="text-slate-300 hover:text-red-500 hover:bg-red-50 p-1.5 rounded transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="p-3 bg-slate-50 border-t border-slate-200">
             <button 
              onClick={addItem}
              className="flex items-center gap-2 text-blue-600 font-semibold hover:bg-blue-100 px-4 py-2 rounded-lg transition-colors text-sm"
            >
              <Plus size={16} />
              Add Another Line
            </button>
          </div>
        </div>

        {/* Footer Calculation Section */}
        <div className="flex flex-col md:flex-row justify-between pt-4">
           <div className="text-xs text-slate-500 max-w-md space-y-2">
               <p><strong>Calculation Logic:</strong></p>
               <p>1. If Size A & Size B are entered: <code>(Size A × Size B) = SqFt</code></p>
               <p>2. Then: <code>SqFt × Rate × Qty = Amount</code></p>
               <p>3. If sizes are 0, standard <code>Qty × Rate</code> applies.</p>
           </div>

           <div className="w-full md:w-96 bg-slate-50 rounded-xl p-6 border border-slate-200 space-y-3">
              <div className="flex justify-between text-slate-600 text-sm">
                <span>Sub Total</span>
                <span className="font-medium">{totals.subTotal.toFixed(2)}</span>
              </div>
              <div className="h-px bg-slate-200 my-2"></div>
              <div className="flex justify-between text-slate-900 font-bold text-xl items-center">
                <span>Grand Total</span>
                <span>₹ {totals.grandTotal.toFixed(2)}</span>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Plus, Search, Filter, FileText, Download, Edit, Trash2 } from 'lucide-react';
import { Transaction, TransactionType } from '../types';
import { generateInvoicePDF } from '../utils/pdfGenerator.ts';

interface TransactionListProps {
  type: TransactionType;
  transactions: Transaction[];
  onAdd: () => void;
  onEdit: (t: Transaction) => void;
  onDelete: (id: string) => void;
}

export const TransactionList: React.FC<TransactionListProps> = ({ type, transactions, onAdd, onEdit, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filtered = transactions.filter(t => 
    t.type === type && 
    (t.partyName.toLowerCase().includes(searchTerm.toLowerCase()) || 
     t.invoiceNumber.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const handleDownload = (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    try {
      generateInvoicePDF(t);
    } catch (error) {
      console.error("PDF Generation Error:", error);
      alert("Failed to generate PDF. Check console for details.");
    }
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this transaction?")) {
      onDelete(id);
    }
  };

  const handleEdit = (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    onEdit(t);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">{type === TransactionType.SALE ? 'Sales Invoices & Estimates' : 'Purchase Bills'}</h1>
          <p className="text-slate-500">Manage your {type === TransactionType.SALE ? 'sales' : 'purchases'} and billing.</p>
        </div>
        <button 
          onClick={onAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium shadow-sm shadow-blue-200"
        >
          <Plus size={20} className="pointer-events-none" />
          <span>New {type === TransactionType.SALE ? 'Invoice / Estimate' : 'Bill'}</span>
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        {/* Filters Bar */}
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
           <div className="relative flex-1 max-w-md">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
             <input 
                type="text" 
                placeholder="Search by party or invoice no..." 
                className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>
           <div className="flex gap-2">
             <button className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50">
                <Filter size={16} className="pointer-events-none" />
                <span className="hidden sm:inline">Filter</span>
             </button>
             <button className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50">
                <FileText size={16} className="pointer-events-none" />
                <span className="hidden sm:inline">Export</span>
             </button>
           </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr className="text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">
                <th className="px-6 py-3">Date</th>
                <th className="px-6 py-3">No.</th>
                <th className="px-6 py-3">Party Name</th>
                <th className="px-6 py-3 text-right">Amount</th>
                <th className="px-6 py-3 text-center">Status</th>
                <th className="px-6 py-3 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-500">
                    No transactions found. Click "New" to create one.
                  </td>
                </tr>
              ) : (
                filtered.map((t) => (
                  <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                      {new Date(t.date).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">
                      {t.invoiceNumber}
                      {t.isEstimate && (
                        <span className="ml-2 inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-purple-100 text-purple-800">
                          EST
                        </span>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900">
                      {t.partyName}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900 text-right font-medium">
                      {t.grandTotal.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-center">
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
                        ${t.status === 'PAID' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}
                      `}>
                        {t.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <div className="flex justify-end items-center gap-2">
                        {/* Download button enabled for all types */}
                        <button
                          type="button"
                          onClick={(e) => handleDownload(e, t)}
                          className="group flex items-center justify-center w-8 h-8 rounded-full text-slate-400 hover:text-blue-600 hover:bg-blue-50 transition-all border border-transparent hover:border-blue-100"
                          title="Download PDF"
                        >
                          <Download size={16} className="pointer-events-none" />
                        </button>

                        <button 
                          type="button"
                          onClick={(e) => handleEdit(e, t)}
                          className="group flex items-center justify-center w-8 h-8 rounded-full text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all border border-transparent hover:border-indigo-100"
