import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, TransactionType } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const doc = new jsPDF();

    // Determine Document Title
    let docTitle = "INVOICE";
    if (transaction.type === TransactionType.SALE) {
        docTitle = transaction.isEstimate ? "ESTIMATE" : "INVOICE";
    } else {
        docTitle = "PURCHASE ORDER";
    }

    // Determine Label for Number (Invoice No vs Estimate No)
    const noLabel = transaction.isEstimate ? "Estimate No:" : "Invoice No:";

    // Company Header
    doc.setFontSize(22);
    doc.setTextColor(37, 99, 235); // Blue-600
