    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    doc.text("Professional Printing Solutions", 14, 25);
    doc.text("Vadodara, Gujarat", 14, 30);
    // Add more company details if needed

    // Invoice Details Right Side
    const rightX = 140;
    doc.setFontSize(16);
    doc.setTextColor(0, 0, 0);
    doc.text(docTitle, rightX, 20);

    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    doc.text(`${noLabel} ${transaction.invoiceNumber}`, rightX, 30);
    doc.text(`Date: ${transaction.date}`, rightX, 35);
    doc.text(`Status: ${transaction.status}`, rightX, 40);

    // Divider
    doc.setDrawColor(200, 200, 200);
    doc.line(14, 45, 196, 45);

    // Bill To
    doc.setFontSize(12);
    doc.setTextColor(0, 0, 0);
    doc.text("Bill To:", 14, 55);
    doc.setFontSize(11);
    doc.setFont(undefined, 'bold');
    doc.text(transaction.partyName, 14, 61);
    doc.setFont(undefined, 'normal');
    doc.setFontSize(10);
    doc.setTextColor(80, 80, 80);

    if (transaction.partyAddress) {
      const splitAddress = doc.splitTextToSize(transaction.partyAddress, 80);
      doc.text(splitAddress, 14, 66);
    }

    // Table
    const tableColumn = ["#", "Description", "Material", "Size (AxB)", "SqFt", "Qty", "Rate", "Amount"];
    const tableRows = transaction.items.map((item, index) => {
      const sizeStr = item.sizeA > 0 && item.sizeB > 0 ? `${item.sizeA} x ${item.sizeB}` : "-";
      const sqFtStr = item.sqFt > 0 ? item.sqFt.toString() : "-";
      return [
        index + 1,
        item.description,
        item.material || "-",
        sizeStr,
        sqFtStr,
        item.quantity,
        item.rate,
        item.amount.toFixed(2)
      ];
    });

    if (typeof autoTable === 'function') {
        autoTable(doc, {
          head: [tableColumn],
          body: tableRows,
          startY: 85,
          theme: 'grid',
          headStyles: { fillColor: [37, 99, 235], textColor: 255 }, // Blue header
          styles: { fontSize: 9, cellPadding: 3 },
          columnStyles: {
            0: { cellWidth: 10 }, // #
            1: { cellWidth: 50 }, // Description
            2: { cellWidth: 30 }, // Material
            3: { cellWidth: 20 }, // Size
            4: { cellWidth: 15 }, // SqFt
            5: { cellWidth: 15 }, // Qty
            6: { cellWidth: 20 }, // Rate
            7: { cellWidth: 25, halign: 'right' }, // Amount
          },
          foot: [
              [
                  "", 
                  "", 
                  "",
                  "", 
                  "", 
                  "Total", 
                  "", 
                  transaction.subTotal.toFixed(2)
              ]
          ]
        });
    } else {
        console.error("autoTable is not a function");
        doc.text("Table could not be generated.", 14, 85);
    }

    // Totals Section
    // Safe access to finalY
    const lastTableY = (doc as any).lastAutoTable ? (doc as any).lastAutoTable.finalY : 150;
    const finalY = lastTableY + 10;

    // Box for totals
    doc.setFillColor(248, 250, 252);
    doc.rect(130, finalY - 5, 70, 30, 'F');

    doc.setFontSize(10);
    doc.setTextColor(70, 70, 70);

    doc.text(`Sub Total:`, 140, finalY);
    doc.text(`${transaction.subTotal.toFixed(2)}`, 190, finalY, { align: "right" });

    doc.setFontSize(12);
    doc.setTextColor(0, 0, 0);
    doc.setFont(undefined, 'bold');
    doc.text(transaction.isEstimate ? 'Estimated Total:' : 'Grand Total:', 140, finalY + 10); // Adjusted Y position
    doc.text(`${transaction.grandTotal.toFixed(2)}`, 190, finalY + 10, { align: "right" });

    // Footer
    doc.setFontSize(9);
    doc.setFont(undefined, 'normal');
    doc.setTextColor(150, 150, 150);
    doc.text("Thank you for your business!", 105, 280, { align: "center" });
    doc.text("Generated via EasyIn", 105, 285, { align: "center" });

    doc.save(`${transaction.invoiceNumber}.pdf`);
  } catch (error) {
    console.error("Error generating PDF:", error);
    throw error; // Re-throw to be caught in the UI
  }
};

