import React, { useRef } from 'react';
import { Download, Upload } from 'lucide-react';
import { Transaction } from '../types';

interface DataManagementProps {
  transactions: Transaction[];
  onImport: (data: Transaction[]) => void;
}

export const DataManagement: React.FC<DataManagementProps> = ({ transactions, onImport }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleBackup = () => {
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `easyin_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
            if (window.confirm('WARNING: This will replace ALL current data with the backup file. Are you sure?')) {
                onImport(json);
                alert('Data restored successfully!');
            }
        } else {
            alert('Invalid backup file format.');
        }
      } catch (err) {
        alert('Failed to parse backup file.');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6">
       <div className="flex flex-col">
          <h1 className="text-2xl font-bold text-slate-900">Data Backup & Restore</h1>
          <p className="text-slate-500">Offline mode relies on your browser storage. Regular backups are recommended.</p>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Backup Section */}
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-4">
             <div className="p-4 bg-blue-50 text-blue-600 rounded-full">
                <Download size={32} />
             </div>
             <div>
                <h3 className="text-lg font-semibold text-slate-900">Export Backup</h3>
                <p className="text-sm text-slate-500 mt-1">Download all your Invoices, Bills, and Data as a generic JSON file.</p>
             </div>
             <button onClick={handleBackup} className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium w-full shadow-sm shadow-blue-200">
                Download JSON File
             </button>
          </div>

          {/* Restore Section */}
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-4">
             <div className="p-4 bg-orange-50 text-orange-600 rounded-full">
                <Upload size={32} />
             </div>
             <div>
                <h3 className="text-lg font-semibold text-slate-900">Import Data</h3>
                <p className="text-sm text-slate-500 mt-1">Restore from a previously saved JSON file. This will overwrite current data.</p>
             </div>
             <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleRestore}
                className="hidden"
             />
             <button onClick={() => fileInputRef.current?.click()} className="px-6 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 font-medium w-full">
                Select Backup File
             </button>
          </div>
       </div>

       <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 mt-6">
          <h4 className="text-sm font-bold text-yellow-800">Important Note:</h4>
          <p className="text-sm text-yellow-800 mt-1">
             Since this app runs offline in your browser, clearing your browser cache/cookies will delete your data. 
             Please use the "Export Backup" feature regularly to save your work to your computer.
          </p>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Transaction, TransactionType } from './types';

// Mock Data for initial load
const MOCK_DATA: Transaction[] = [
  {
    id: '1',
    type: TransactionType.SALE,
    invoiceNumber: 'INV-1001',
    date: new Date().toISOString().split('T')[0],
    partyName: 'Rahul Traders',
    partyAddress: '123 Market Road, Mumbai',
    items: [
      { 
        id: '101', 
        description: 'Flex Banner Printing', 
        material: 'Star Flex',
        sizeA: 10, 
        sizeB: 5, 
        sqFt: 50, 
        quantity: 2, 
        rate: 15, 
        unit: 'sqft', 
        amount: 1500
      }
    ],
    subTotal: 1500,
    grandTotal: 1500,
    status: 'PAID',
    isEstimate: false
  }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formType, setFormType] = useState<TransactionType>(TransactionType.SALE);

  // Load data from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('easyin_transactions_v1');
    if (saved) {
      try {
        setTransactions(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse transactions", e);
        setTransactions(MOCK_DATA);
      }
    } else {
      setTransactions(MOCK_DATA);
    }
  }, []);

  // Save data on change
  useEffect(() => {
    localStorage.setItem('easyin_transactions_v1', JSON.stringify(transactions));
  }, [transactions]);

  const handleNavigate = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleAddTransaction = (type: TransactionType) => {
    setFormType(type);
    setEditingTransaction(null);
    setViewState('form');
  };

  const handleEditTransaction = (transaction: Transaction) => {
    setFormType(transaction.type);
    setEditingTransaction(transaction);
    setViewState('form');
  };

  const handleDeleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
  };

  const handleImportData = (data: Transaction[]) => {
      setTransactions(data);
  };

  const renderContent = () => {
    if (activeTab === 'dashboard') {
      return <Dashboard transactions={transactions} />;
    }

    if (activeTab === 'reports') {
      return <Reports transactions={transactions} />;
    }

    if (activeTab === 'data') {
      return <DataManagement transactions={transactions} onImport={handleImportData} />;
    }

    // Sales (Invoices) Tab
    if (activeTab === 'sales') {
      const type = TransactionType.SALE;

      if (viewState === 'form' && formType === type) {
        return (
          <TransactionForm 
            type={type} 
            initialData={editingTransaction}
            onSave={handleSaveTransaction}
            onCancel={() => setViewState('list')}
          />
        );
      }

      return (
        <TransactionList 
          type={type}
          transactions={transactions}
          onAdd={() => handleAddTransaction(type)}
          onEdit={handleEditTransaction}
          onDelete={handleDeleteTransaction}
        />
      );
    }

    // Purchases Tab
    if (activeTab === 'purchases') {
      const type = TransactionType.PURCHASE;

      if (viewState === 'form' && formType === type) {
        return (
          <TransactionForm 
            type={type} 
            initialData={editingTransaction}
            onSave={handleSaveTransaction}
            onCancel={() => setViewState('list')}
          />
        );
      }

      return (
        <TransactionList 
          type={type}
          transactions={transactions}
          onAdd={() => handleAddTransaction(type)}
          onEdit={handleEditTransaction}
          onDelete={handleDeleteTransaction}
        />
      );
    }

    return <div>Page not found</div>;
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

