import { Transaction } from "../types";

export const exportTransactionsToCSV = (transactions: Transaction[], filename: string) => {
  const headers = [
    "Date",
    "No.",
    "Document Type",
    "Party Name",
    "Address",
    "Items Summary",
    "Sub Total",
    "Grand Total",
    "Status"
  ];

  const rows = transactions.map(t => {
    const itemsSummary = t.items.map(item => `${item.description} (x${item.quantity})`).join("; ");
    const docType = t.isEstimate ? "Estimate" : "Invoice";

    return [
      t.date,
      `"${t.invoiceNumber}"`,
      docType,
      `"${t.partyName.replace(/"/g, '""')}"`,
      `"${(t.partyAddress || "").replace(/"/g, '""')}"`,
      `"${itemsSummary.replace(/"/g, '""')}"`,
      t.subTotal.toFixed(2),
      t.grandTotal.toFixed(2),
      t.status
    ];
  });

  const csvContent = [
    headers.join(","),
    ...rows.map(row => row.join(","))
  ].join("\n");

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

/**
 * Copies data to clipboard in TSV format.
 * This allows users to simply PASTE (Ctrl+V) into Google Sheets or Excel.
 */
export const copyTransactionsToClipboard = (transactions: Transaction[]) => {
  const headers = ["Date", "No.", "Type", "Party", "Items", "Amount", "Status"];
  const rows = transactions.map(t => [
    t.date,
    t.invoiceNumber,
    t.isEstimate ? "Estimate" : "Invoice",
    t.partyName,
    t.items.map(i => i.description).join("; "),
    t.grandTotal.toFixed(2),
    t.status
  ]);

  const tsvContent = [
    headers.join("\t"),
    ...rows.map(row => row.join("\t"))
  ].join("\n");

  navigator.clipboard.writeText(tsvContent).then(() => {
    alert("Data copied to clipboard! You can now paste (Ctrl+V) directly into Google Sheets or Excel.");
  }).catch(err => {
    console.error('Could not copy text: ', err);
    alert("Failed to copy to clipboard.");
  });
};

