import React from 'react';
import { Transaction, TransactionType } from '../types';
import { TrendingUp, CheckCircle, IndianRupee, FileText, Download } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const sales = transactions.filter(t => t.type === TransactionType.SALE && !t.isEstimate);

  const totalSales = sales.reduce((acc, t) => acc + t.grandTotal, 0);
  const paidSales = sales.filter(t => t.status === 'PAID').reduce((acc, t) => acc + t.grandTotal, 0);
  const unpaidSales = sales.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + t.grandTotal, 0);

  const handleExportFullReport = () => {
    if (transactions.length === 0) {
      alert("No data available to export.");
      return;
    }
    exportTransactionsToCSV(transactions, "Complete_Business_Report");
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Sales Reports</h1>
          <p className="text-slate-500">Overview of your Invoices and Revenue.</p>
        </div>
        <button 
          onClick={handleExportFullReport}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium shadow-sm"
        >
          <Download size={18} />
          <span>Export Detailed Report</span>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <ReportCard 
            title="Total Sales" 
            value={totalSales} 
            color="blue" 
            icon={<TrendingUp size={20} />} 
        />
        <ReportCard 
            title="Total Collected (Paid)" 
            value={paidSales} 
            color="green" 
            icon={<CheckCircle size={20} />} 
        />
        <ReportCard 
            title="Unpaid / Pending" 
            value={unpaidSales} 
            color="orange" 
            icon={<IndianRupee size={20} />} 
        />
      </div>

      <div className="grid grid-cols-1 gap-6">
          {/* Sales Summary */}
          <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
               <h3 className="font-semibold text-slate-900">Sales Summary</h3>
               <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">Historical Data</span>
            </div>
            <div className="p-4">
                <div className="space-y-3">
                    <div className="flex justify-between text-sm">
                        <span className="text-slate-600">Total Invoices</span>
                        <span className="font-medium">{sales.length}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                        <span className="text-slate-600">Average Invoice Value</span>
                        <span className="font-medium">
                            {sales.length > 0 
                                ? new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(totalSales / sales.length)
                                : '₹ 0.00'
                            }
                        </span>
                    </div>
                     <div className="flex justify-between text-sm">
                        <span className="text-slate-600">Pending Amount</span>
                        <span className="font-medium text-orange-600">
                             {new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(unpaidSales)}
                        </span>
                    </div>
                </div>
            </div>
          </div>
      </div>
    </div>
  );
};

