import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Transaction, TransactionType } from './types';

// Mock Data for initial load
const MOCK_DATA: Transaction[] = [
  {
    id: '1',
    type: TransactionType.SALE,
    invoiceNumber: 'INV-1001',
    date: new Date().toISOString().split('T')[0],
    partyName: 'Rahul Traders',
    partyAddress: '123 Market Road, Mumbai',
    items: [
      { 
        id: '101', 
        description: 'Flex Banner Printing', 
        material: 'Star Flex',
        sizeA: 10, 
        sizeB: 5, 
        sqFt: 50, 
        quantity: 2, 
        rate: 15, 
        unit: 'sqft', 
        amount: 1500
      }
    ],
    subTotal: 1500,
    grandTotal: 1500,
    status: 'PAID',
    isEstimate: false
  }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formType, setFormType] = useState<TransactionType>(TransactionType.SALE);

  // Load data from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('easyin_transactions_v1');
    if (saved) {
      try {
        setTransactions(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse transactions", e);
        setTransactions(MOCK_DATA);
      }
    } else {
      setTransactions(MOCK_DATA);
    }
  }, []);

  // Save data on change
  useEffect(() => {
    localStorage.setItem('easyin_transactions_v1', JSON.stringify(transactions));
  }, [transactions]);

  const handleNavigate = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleAddTransaction = (type: TransactionType) => {
    setFormType(type);
    setEditingTransaction(null);
    setViewState('form');
  };

  const handleEditTransaction = (transaction: Transaction) => {
    setFormType(transaction.type);
    setEditingTransaction(transaction);
    setViewState('form');
  };

  const handleDeleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
  };

  const handleImportData = (data: Transaction[]) => {
      setTransactions(data);
  };

  const renderContent = () => {
    if (activeTab === 'dashboard') {
      return (
        <Dashboard 
          transactions={transactions} 
          onAddInvoice={() => {
            setActiveTab('sales');
            handleAddTransaction(TransactionType.SALE);
          }} 
        />
      );
    }

    if (activeTab === 'reports') {
      return <Reports transactions={transactions} />;
    }

    if (activeTab === 'data') {
      return <DataManagement transactions={transactions} onImport={handleImportData} />;
    }

    // Sales (Invoices) Tab
    if (activeTab === 'sales') {
      const type = TransactionType.SALE;

      if (viewState === 'form' && formType === type) {
        return (
          <TransactionForm 
            type={type} 
            initialData={editingTransaction}
            onSave={handleSaveTransaction}
            onCancel={() => setViewState('list')}
          />
        );
      }

      return (
        <TransactionList 
          type={type}
          transactions={transactions}
          onAdd={() => handleAddTransaction(type)}
          onEdit={handleEditTransaction}
          onDelete={handleDeleteTransaction}
        />
      );
    }

    return <div>Page not found</div>;
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  Plus, 
  Search, 
  Filter, 
  FileText, 
  Download, 
  Edit, 
  Trash2, 
  ClipboardCheck, 
  X, 
  Calendar,
  XCircle,
  CheckCircle2,
  Clock
} from 'lucide-react';
import { Transaction, TransactionType } from '../types';
import { generateInvoicePDF } from '../utils/pdfGenerator';
import { exportTransactionsToCSV, copyTransactionsToClipboard } from '../utils/csvExporter';

interface TransactionListProps {
  type: TransactionType;
  transactions: Transaction[];
  onAdd: () => void;
  onEdit: (t: Transaction) => void;
  onDelete: (id: string) => void;
}

export const TransactionList: React.FC<TransactionListProps> = ({ type, transactions, onAdd, onEdit, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  // Advanced Filter States
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [statusFilter, setStatusFilter] = useState<'ALL' | 'PAID' | 'UNPAID'>('ALL');
  const [docTypeFilter, setDocTypeFilter] = useState<'ALL' | 'INVOICE' | 'ESTIMATE'>('ALL');

  const filtered = transactions.filter(t => {
    // Basic type match (Sale vs Purchase)
    if (t.type !== type) return false;

    // Search term match
    const searchLower = searchTerm.toLowerCase();
    const matchSearch = t.partyName.toLowerCase().includes(searchLower) || 
                       t.invoiceNumber.toLowerCase().includes(searchLower);
    if (!matchSearch) return false;

    // Document Type Filter (Invoice/Estimate)
    if (docTypeFilter === 'INVOICE' && t.isEstimate) return false;
    if (docTypeFilter === 'ESTIMATE' && !t.isEstimate) return false;

    // Status Filter
    if (statusFilter !== 'ALL' && t.status !== statusFilter) return false;

    // Date Range Filter
    if (dateFrom && t.date < dateFrom) return false;
    if (dateTo && t.date > dateTo) return false;

    return true;
  });

  const hasActiveFilters = dateFrom || dateTo || statusFilter !== 'ALL' || docTypeFilter !== 'ALL';

  const clearFilters = () => {
    setDateFrom('');
    setDateTo('');
    setStatusFilter('ALL');
    setDocTypeFilter('ALL');
    setSearchTerm('');
  };

  const handleDownload = async (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    try {
      await generateInvoicePDF(t);
    } catch (error) {
      console.error("PDF Generation Error:", error);
      alert("Failed to generate PDF.");
    }
  };

  const handleExportCSV = () => {
    if (filtered.length === 0) {
      alert("No matching data to export.");
      return;
    }
    const filename = type === TransactionType.SALE ? "Sales_Export" : "Purchase_Export";
    exportTransactionsToCSV(filtered, filename);
  };

  const handleCopyForSheets = () => {
    if (filtered.length === 0) {
      alert("No matching data to copy.");
      return;
    }
    copyTransactionsToClipboard(filtered);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation(); 
    if (window.confirm("Delete this transaction? This cannot be undone.")) {
        onDelete(id);
    }
  };

  const handleEditClick = (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    onEdit(t);
  };

  return (
    <div className="space-y-6">
      {/* Header section remains similar */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">
            {type === TransactionType.SALE ? 'Sales Invoices & Estimates' : 'Purchase Bills'}
          </h1>
          <p className="text-slate-500">
            Manage your {type === TransactionType.SALE ? 'sales' : 'purchases'} and billing.
          </p>
        </div>
        <button 
          onClick={onAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium shadow-sm shadow-blue-200"
        >
          <Plus size={20} />
          <span>New {type === TransactionType.SALE ? 'Invoice / Estimate' : 'Bill'}</span>
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        {/* Main Search Bar and Action Buttons */}
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
           <div className="relative flex-1 max-w-md">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
             <input 
                type="text" 
                placeholder="Search by party or invoice no..." 
                className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>

           <div className="flex flex-wrap gap-2">
             <button 
                onClick={handleCopyForSheets}
                className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium"
                title="Copy current list for Google Sheets"
             >
                <ClipboardCheck size={16} className="text-emerald-600" />
                <span className="hidden sm:inline">Copy for Sheets</span>
             </button>
             <button 
                onClick={handleExportCSV}
                className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium"
                title="Export current list as CSV"
             >
                <FileText size={16} className="text-blue-600" />
                <span className="hidden sm:inline">Export CSV</span>
             </button>
             <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center gap-2 px-3 py-2 border rounded-lg transition-colors text-sm font-medium ${
                  showFilters || hasActiveFilters 
                  ? 'bg-blue-50 border-blue-200 text-blue-700' 
                  : 'bg-white border-slate-300 text-slate-700 hover:bg-slate-50'
                }`}
             >
                <Filter size={16} />
                <span className="hidden sm:inline">Filter</span>
                {hasActiveFilters && (
                  <span className="ml-1 flex h-2 w-2 rounded-full bg-blue-600"></span>
                )}
             </button>
           </div>
        </div>

        {/* Expandable Filter Panel */}
        {showFilters && (
          <div className="p-4 bg-slate-50/50 border-b border-slate-200 animate-in slide-in-from-top duration-200">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              {/* Date Filter */}
              <div className="space-y-2 md:col-span-2">
                <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1">
                  <Calendar size={12} /> Date Range
                </label>
                <div className="flex items-center gap-2">
                  <input 
                    type="date" 
                    value={dateFrom}
                    onChange={(e) => setDateFrom(e.target.value)}
                    className="flex-1 px-3 py-1.5 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                  <span className="text-slate-400">to</span>
                  <input 
                    type="date" 
                    value={dateTo}
                    onChange={(e) => setDateTo(e.target.value)}
                    className="flex-1 px-3 py-1.5 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                </div>
              </div>

              {/* Status Filter */}
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Payment Status</label>
                <div className="flex bg-white border border-slate-300 rounded-lg p-0.5">
                  {(['ALL', 'PAID', 'UNPAID'] as const).map((s) => (
                    <button
                      key={s}
                      onClick={() => setStatusFilter(s)}
                      className={`flex-1 py-1 px-2 rounded-md text-xs font-medium transition-all ${
                        statusFilter === s 
                        ? 'bg-blue-600 text-white shadow-sm' 
                        : 'text-slate-600 hover:bg-slate-100'
                      }`}
                    >
                      {s.charAt(0) + s.slice(1).toLowerCase()}
                    </button>
                  ))}
                </div>
              </div>

              {/* Document Type Filter */}
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Document Type</label>
                <div className="flex bg-white border border-slate-300 rounded-lg p-0.5">
                  {(['ALL', 'INVOICE', 'ESTIMATE'] as const).map((d) => (
                    <button
                      key={d}
                      onClick={() => setDocTypeFilter(d)}
                      className={`flex-1 py-1 px-2 rounded-md text-xs font-medium transition-all ${
                        docTypeFilter === d 
                        ? 'bg-blue-600 text-white shadow-sm' 
                        : 'text-slate-600 hover:bg-slate-100'
                      }`}
                    >
                      {d.charAt(0) + d.slice(1).toLowerCase()}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Clear All Button */}
            <div className="mt-4 flex justify-end">
              <button 
                onClick={clearFilters}
                className="text-xs font-semibold text-red-600 hover:text-red-700 flex items-center gap-1 px-2 py-1 hover:bg-red-50 rounded"
              >
                <XCircle size={14} /> Clear All Filters
              </button>
            </div>
          </div>
        )}

        {/* Table Results */}
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr className="text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">
                <th className="px-6 py-3">Date</th>
                <th className="px-6 py-3">No.</th>
                <th className="px-6 py-3">Party Name</th>
                <th className="px-6 py-3 text-right">Amount</th>
                <th className="px-6 py-3 text-center">Status</th>
                <th className="px-6 py-3 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-500">
                    <div className="flex flex-col items-center gap-2">
                        <Search size={40} className="text-slate-200" />
                        <p>No transactions match your search/filters.</p>
                        {hasActiveFilters && (
                          <button onClick={clearFilters} className="text-blue-600 text-sm font-bold">Clear filters</button>
                        )}
                    </div>
                  </td>
                </tr>
              ) : (
                filtered.map((t) => (
                  <tr key={t.id} className="group hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                      {new Date(t.date).toLocaleDateString()}
