import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, TransactionType, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    // Attempt to load profile from storage
    const savedProfile = localStorage.getItem('easyin_profile_v1');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      name: "My Business",
      address: "Shop Address",
      phone: "000-000-0000",
      email: "",
      currencySymbol: "₹",
      defaultStatus: "UNPAID"
    };

    const doc = new jsPDF();

    // Determine Document Title
    let docTitle = "INVOICE";
    if (transaction.type === TransactionType.SALE) {
        docTitle = transaction.isEstimate ? "ESTIMATE" : "INVOICE";
    } else {
        docTitle = "PURCHASE ORDER";
    }

    // Header - Business Details (Left Side)
    doc.setFontSize(20);
    doc.setTextColor(37, 99, 235); // Blue
    doc.setFont(undefined, 'bold');
    doc.text(profile.name, 14, 20);

    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.setFont(undefined, 'normal');

    const headerDetails = [
        profile.address,
        `Phone: ${profile.phone}`,
        profile.email ? `Email: ${profile.email}` : "",
        profile.taxId ? `GSTIN: ${profile.taxId}` : ""
    ].filter(Boolean);

    headerDetails.forEach((text, i) => {
        doc.text(text, 14, 26 + (i * 4.5));
    });

    // Invoice Details (Right Side)
    const rightX = 140;
    doc.setFontSize(16);
    doc.setTextColor(0, 0, 0);
    doc.setFont(undefined, 'bold');
    doc.text(docTitle, rightX, 20);

    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.setFont(undefined, 'normal');

    const noLabel = transaction.isEstimate ? "Estimate No:" : "Invoice No:";
    doc.text(`${noLabel} ${transaction.invoiceNumber}`, rightX, 28);
    doc.text(`Date: ${transaction.date}`, rightX, 33);
    doc.text(`Status: ${transaction.status}`, rightX, 38);

    // Divider
    doc.setDrawColor(230, 230, 230);
    doc.line(14, 45, 196, 45);

    // Bill To
    doc.setFontSize(10);
    doc.setTextColor(0, 0, 0);
    doc.text("BILL TO:", 14, 55);
    doc.setFontSize(11);
    doc.setFont(undefined, 'bold');
    doc.text(transaction.partyName, 14, 61);

    doc.setFont(undefined, 'normal');
    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    if (transaction.partyAddress) {
      const splitAddress = doc.splitTextToSize(transaction.partyAddress, 80);
      doc.text(splitAddress, 14, 66);
    }

    // Table
    const tableColumn = ["#", "Description", "Material", "Size (AxB)", "SqFt", "Qty", "Rate", "Amount"];
    const tableRows = transaction.items.map((item, index) => {
      const sizeStr = item.sizeA > 0 && item.sizeB > 0 ? `${item.sizeA} x ${item.sizeB}` : "-";
      const sqFtStr = item.sqFt > 0 ? item.sqFt.toString() : "-";
      return [
        index + 1,
        item.description,
        item.material || "-",
        sizeStr,
        sqFtStr,
        item.quantity,
        item.rate,
        item.amount.toFixed(2)
      ];
    });

    if (typeof autoTable === 'function') {
        autoTable(doc, {
          head: [tableColumn],
          body: tableRows,
          startY: 85,
          theme: 'grid',
          headStyles: { fillColor: [37, 99, 235], textColor: 255 },
          styles: { fontSize: 8, cellPadding: 3 },
          columnStyles: {
            7: { halign: 'right' },
          }
        });
    }

    const lastTableY = (doc as any).lastAutoTable ? (doc as any).lastAutoTable.finalY : 150;
    const finalY = lastTableY + 10;

    // Totals Box
    doc.setFillColor(248, 250, 252);
    doc.rect(130, finalY - 5, 66, 25, 'F');

    doc.setFontSize(9);
    doc.setTextColor(100, 100, 100);
    doc.text(`Sub Total:`, 135, finalY);
    doc.text(`${profile.currencySymbol} ${transaction.subTotal.toFixed(2)}`, 190, finalY, { align: "right" });

    doc.setFontSize(11);
    doc.setTextColor(0, 0, 0);
    doc.setFont(undefined, 'bold');
    doc.text(`GRAND TOTAL:`, 135, finalY + 10);
    doc.text(`${profile.currencySymbol} ${transaction.grandTotal.toFixed(2)}`, 190, finalY + 10, { align: "right" });

    // Footer
    doc.setFontSize(8);
    doc.setTextColor(150, 150, 150);
    doc.setFont(undefined, 'normal');
    doc.text("Authorized Signatory", 196, 275, { align: "right" });
    doc.line(146, 270, 196, 270);
    doc.text("Generated via EasyIn Invoicing", 105, 290, { align: "center" });

    const filenamePrefix = transaction.isEstimate ? "Estimate" : "Invoice";
    doc.save(`${filenamePrefix}_${transaction.invoiceNumber}.pdf`);

  } catch (error) {
    console.error("Error generating PDF:", error);
    alert("Failed to generate PDF. See console for details.");
  }
};

