import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, TransactionType, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const savedProfile = localStorage.getItem('easyin_profile_v1');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      name: "My Business",
      address: "Shop Address",
      phone: "000-000-0000",
      email: "",
      currencySymbol: "₹",
      defaultStatus: "UNPAID",
      materials: [],
      pdfFooterNote: "Thank you!",
      showSqFtInPdf: true,
      showMaterialInPdf: true
    };

    const doc = new jsPDF();
    const docTitle = transaction.isEstimate ? "ESTIMATE" : (transaction.type === TransactionType.SALE ? "INVOICE" : "PURCHASE ORDER");

    // Header
    doc.setFontSize(20).setTextColor(37, 99, 235).setFont(undefined, 'bold').text(profile.name, 14, 20);
    doc.setFontSize(9).setTextColor(100, 100, 100).setFont(undefined, 'normal');
    [profile.address, `Phone: ${profile.phone}`, profile.email, profile.taxId].filter(Boolean).forEach((text, i) => {
        doc.text(text as string, 14, 26 + (i * 4.5));
    });

    // Document Info
    const rightX = 140;
    doc.setFontSize(16).setTextColor(0).setFont(undefined, 'bold').text(docTitle, rightX, 20);
    doc.setFontSize(9).setTextColor(100).setFont(undefined, 'normal');
    doc.text(`${transaction.isEstimate ? "Estimate" : "Invoice"} #: ${transaction.invoiceNumber}`, rightX, 28);
    doc.text(`Date: ${transaction.date}`, rightX, 33);
    doc.text(`Status: ${transaction.status}`, rightX, 38);

    doc.setDrawColor(230).line(14, 45, 196, 45);

    // Bill To
    doc.setFontSize(10).setTextColor(0).text("BILL TO:", 14, 55);
    doc.setFontSize(11).setFont(undefined, 'bold').text(transaction.partyName, 14, 61);
    doc.setFont(undefined, 'normal').setFontSize(9).setTextColor(100);
    if (transaction.partyAddress) doc.text(doc.splitTextToSize(transaction.partyAddress, 80), 14, 66);

    // Dynamic Columns based on settings
    const tableHeaders = ["#", "Description"];
    if (profile.showMaterialInPdf) tableHeaders.push("Material");
    tableHeaders.push("Size");
    if (profile.showSqFtInPdf) tableHeaders.push("SqFt");
    tableHeaders.push("Qty", "Rate", "Amount");

    const tableRows = transaction.items.map((item, index) => {
      const row = [index + 1, item.description];
      if (profile.showMaterialInPdf) row.push(item.material || "-");
      row.push(item.sizeA > 0 && item.sizeB > 0 ? `${item.sizeA}x${item.sizeB}` : "-");
      if (profile.showSqFtInPdf) row.push(item.sqFt > 0 ? item.sqFt.toString() : "-");
      row.push(item.quantity, item.rate, item.amount.toFixed(2));
      return row;
    });

    if (typeof autoTable === 'function') {
        autoTable(doc, {
          head: [tableHeaders],
          body: tableRows,
          startY: 85,
          theme: 'grid',
          headStyles: { fillColor: [37, 99, 235] },
          styles: { fontSize: 8 },
        });
    }

    const finalY = (doc as any).lastAutoTable ? (doc as any).lastAutoTable.finalY + 10 : 150;

    // Totals
    doc.setFontSize(11).setFont(undefined, 'bold').setTextColor(0);
    doc.text(`GRAND TOTAL: ${profile.currencySymbol} ${transaction.grandTotal.toFixed(2)}`, 196, finalY, { align: "right" });

    // Footer Settings Implementation
    if (profile.pdfFooterNote) {
      doc.setFontSize(8).setTextColor(120).setFont(undefined, 'normal');
      doc.text("NOTES:", 14, finalY + 15);
      doc.text(doc.splitTextToSize(profile.pdfFooterNote, 180), 14, finalY + 20);
    }

    doc.setFontSize(8).setTextColor(180).text("Generated via EasyIn Invoicing", 105, 290, { align: "center" });
    doc.save(`${docTitle}_${transaction.invoiceNumber}.pdf`);

  } catch (error) {
    console.error(error);
    alert("PDF Error: " + error);
  }
};

