import { GoogleGenAI } from "@google/genai";
import { Transaction, TransactionType } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY not found in environment variables.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateBusinessInsight = async (transactions: Transaction[], query: string): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "Please configure your API Key to use AI insights.";

  const sales = transactions.filter(t => t.type === TransactionType.SALE);
  const purchases = transactions.filter(t => t.type === TransactionType.PURCHASE);

  // Summarize data to avoid token limits if data is huge (simplified strategy)
  const summary = {
    totalSalesCount: sales.length,
    totalPurchaseCount: purchases.length,
    totalSalesValue: sales.reduce((acc, curr) => acc + curr.grandTotal, 0),
    totalPurchaseValue: purchases.reduce((acc, curr) => acc + curr.grandTotal, 0),
    recentTransactions: transactions.slice(0, 10).map(t => ({
      date: t.date,
      type: t.type,
      party: t.partyName,
      amount: t.grandTotal,
      items: t.items.map(i => `${i.description} (${i.quantity})`).join(", ")
    }))
  };

  const prompt = `
    You are a smart business assistant for a small business owner.
    Here is a summary of the business data:
    ${JSON.stringify(summary, null, 2)}

    The user asks: "${query}"

    Provide a concise, helpful, and data-driven answer. Use markdown for formatting.
    If the user asks for analysis, look for trends in the recent transactions.
  `;

  try {
    // Fix: Updated model name to gemini-3-flash-preview for general text tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    // Fix: Access text property directly (not as a method) from GenerateContentResponse
    return response.text || "No insight generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I encountered an error while analyzing your data.";
  }
};

import React, { useState } from 'react';
