import { Transaction } from "../types";

/**
 * Detailed Export: One row per item for granular reporting in Excel.
 * Headers: Date, Name, Description, Material, Size A, Size B, QTY, Rate (₹), Total Sq. Feet, Total Amount (₹)
 */
export const exportTransactionsToCSV = (transactions: Transaction[], filename: string) => {
  const headers = [
    "Date",
    "Name",
    "Description",
    "Material",
    "Size A",
    "Size B",
    "QTY",
    "Rate (₹)",
    "Total Sq. Feet",
    "Total Amount (₹)"
  ];

  const rows: string[][] = [];

  // Sort by date descending
  const sortedTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedTransactions.forEach(t => {
    t.items.forEach(item => {
      rows.push([
        t.date,
        `"${t.partyName.replace(/"/g, '""')}"`,
        `"${item.description.replace(/"/g, '""')}"`,
        `"${(item.material || "").replace(/"/g, '""')}"`,
        item.sizeA.toString(),
        item.sizeB.toString(),
        item.quantity.toString(),
        item.rate.toString(),
        item.sqFt.toString(),
        item.amount.toString()
      ]);
    });
  });

  const csvContent = [
    headers.join(","),
    ...rows.map(row => row.join(","))
  ].join("\n");

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `${filename}_Detailed_${new Date().toISOString().split('T')[0]}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

/**
 * Copies detailed data to clipboard in TSV format for direct Excel/Google Sheets paste.
 * This satisfies the "arrangement in excel sheet" request.
 */
export const copyTransactionsToClipboard = (transactions: Transaction[]) => {
  const headers = [
    "Date",
    "Name",
    "Description",
    "Material",
    "Size A",
    "Size B",
    "QTY",
    "Rate (₹)",
    "Total Sq. Feet",
    "Total Amount (₹)"
  ];

  const rows: string[][] = [];

  // Sort by date descending
  const sortedTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedTransactions.forEach(t => {
    t.items.forEach(item => {
      rows.push([
        t.date,
        t.partyName,
        item.description,
        item.material || "",
        item.sizeA.toString(),
        item.sizeB.toString(),
        item.quantity.toString(),
        item.rate.toString(),
        item.sqFt.toString(),
        item.amount.toString()
      ]);
    });
  });

  const tsvContent = [
    headers.join("\t"),
    ...rows.map(row => row.join("\t"))
  ].join("\n");

  navigator.clipboard.writeText(tsvContent).then(() => {
    alert("Detailed data copied! (One row per item). Ready to paste (Ctrl+V) into Excel or Google Sheets.");
  }).catch(err => {
    console.error('Could not copy text: ', err);
    alert("Failed to copy to clipboard.");
  });
};

