          {children}
        </main>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer
} from 'recharts';
import { 
  ArrowUpRight, 
  TrendingUp, 
  FileText
} from 'lucide-react';
import { Transaction, TransactionType } from '../types';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface DashboardProps {
  transactions: Transaction[];
  onAddInvoice: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ transactions, onAddInvoice }) => {
  const stats = useMemo(() => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);

    const totalSales = sales.reduce((acc, t) => acc + t.grandTotal, 0);
    const unpaidAmount = sales.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + t.grandTotal, 0);

    return { totalSales, unpaidAmount };
  }, [transactions]);

  const chartData = useMemo(() => {
    const last7Days = [...Array(7)].map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      return d.toISOString().split('T')[0];
    });

    return last7Days.map(date => {
      const daysTxns = transactions.filter(t => t.date === date && t.type === TransactionType.SALE);
      return {
        date: new Date(date).toLocaleDateString('en-US', { weekday: 'short' }),
        Sales: daysTxns.reduce((acc, t) => acc + t.grandTotal, 0),
      };
    });
  }, [transactions]);

  const handleDownloadReport = () => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);
    if (sales.length === 0) {
      alert("No sales data available to export.");
      return;
    }
    exportTransactionsToCSV(sales, "Business_Summary_Report");
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Dashboard Overview</h1>
          <p className="text-slate-500">Welcome back, here's what's happening today.</p>
        </div>
        <div className="flex gap-2">
            <span className="bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-sm font-medium">
                {new Date().toLocaleDateString()}
            </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <StatCard 
          title="Total Sales" 
          amount={stats.totalSales} 
          icon={<TrendingUp className="text-green-600" size={24} />} 
          trend="Revenue" 
          trendUp={true}
          bgColor="bg-green-50"
        />
        <StatCard 
          title="Unpaid Estimates" 
          amount={stats.unpaidAmount} 
          icon={<ArrowUpRight className="text-orange-600" size={24} />} 
          trend="Outstanding" 
          trendUp={false} 
          bgColor="bg-orange-50"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold text-slate-800 mb-6">Sales Trend (Last 7 Days)</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: '#64748b' }} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{ fill: '#64748b' }} />
                <Tooltip 
                  cursor={{ fill: '#f1f5f9' }}
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="Sales" fill="#2563eb" radius={[4, 4, 0, 0]} barSize={32} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
           <h3 className="text-lg font-semibold text-slate-800 mb-6">Quick Actions</h3>
           <div className="space-y-3">
              <button 
                onClick={onAddInvoice}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 rounded-lg border border-slate-200 transition-colors"
              >
                 <span className="font-medium text-slate-700">Add New Estimate</span>
                 <ArrowUpRight size={18} className="text-slate-400" />
              </button>
              <button 
                onClick={handleDownloadReport}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 rounded-lg border border-slate-200 transition-colors"
              >
                 <span className="font-medium text-slate-700">Download Report (CSV)</span>
                 <FileText size={18} className="text-slate-400" />
              </button>
           </div>

           <div className="mt-8">
             <h4 className="text-sm font-medium text-slate-500 mb-3">System Status</h4>
             <div className="flex items-center gap-2 text-sm text-green-600 bg-green-50 p-3 rounded-lg">
                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                Gemini AI Connected
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

