  const [docTypeFilter, setDocTypeFilter] = useState<'ALL' | 'INVOICE' | 'ESTIMATE'>('ALL');

  const filtered = transactions.filter(t => {
    // Basic type match (Sale vs Purchase)
    if (t.type !== type) return false;

    // Search term match
    const searchLower = searchTerm.toLowerCase();
    const matchSearch = t.partyName.toLowerCase().includes(searchLower) || 
                       t.invoiceNumber.toLowerCase().includes(searchLower);
    if (!matchSearch) return false;

    // Document Type Filter (Invoice/Estimate)
    if (docTypeFilter === 'INVOICE' && t.isEstimate) return false;
    if (docTypeFilter === 'ESTIMATE' && !t.isEstimate) return false;

    // Status Filter
    if (statusFilter !== 'ALL' && t.status !== statusFilter) return false;

    // Date Range Filter
    if (dateFrom && t.date < dateFrom) return false;
    if (dateTo && t.date > dateTo) return false;

    return true;
  });

  const hasActiveFilters = dateFrom || dateTo || statusFilter !== 'ALL' || docTypeFilter !== 'ALL';

  const clearFilters = () => {
    setDateFrom('');
    setDateTo('');
    setStatusFilter('ALL');
    setDocTypeFilter('ALL');
    setSearchTerm('');
  };

  const handleDownload = async (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    try {
      await generateInvoicePDF(t);
    } catch (error) {
      console.error("PDF Generation Error:", error);
      alert("Failed to generate PDF.");
    }
  };

  const handleExportCSV = () => {
    if (filtered.length === 0) {
      alert("No matching data to export.");
      return;
    }
    const filename = type === TransactionType.SALE ? "Estimates_Export" : "Purchase_Export";
    exportTransactionsToCSV(filtered, filename);
  };

  const handleCopyForSheets = () => {
    if (filtered.length === 0) {
      alert("No matching data to copy.");
      return;
    }
    copyTransactionsToClipboard(filtered);
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation(); 
    if (window.confirm("Delete this transaction? This cannot be undone.")) {
        onDelete(id);
    }
  };

  const handleEditClick = (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    onEdit(t);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">
            {type === TransactionType.SALE ? 'Sales Estimates' : 'Purchase Bills'}
          </h1>
          <p className="text-slate-500">
            Manage your {type === TransactionType.SALE ? 'sales' : 'purchases'} and billing.
          </p>
        </div>
        <button 
          onClick={onAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors font-medium shadow-sm shadow-blue-200"
        >
          <Plus size={20} />
          <span>New {type === TransactionType.SALE ? 'Estimate' : 'Bill'}</span>
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        {/* Main Search Bar and Action Buttons */}
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
           <div className="relative flex-1 max-w-md">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
             <input 
                type="text" 
                placeholder={`Search by party or ${type === TransactionType.SALE ? 'estimate' : 'bill'} no...`} 
                className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>

           <div className="flex flex-wrap gap-2">
             <button 
                onClick={handleCopyForSheets}
                className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium"
                title="Copy current list for Google Sheets"
             >
                <ClipboardCheck size={16} className="text-emerald-600" />
                <span className="hidden sm:inline">Copy for Sheets</span>
             </button>
             <button 
                onClick={handleExportCSV}
                className="flex items-center gap-2 px-3 py-2 bg-white border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium"
                title="Export current list as CSV"
             >
                <FileText size={16} className="text-blue-600" />
                <span className="hidden sm:inline">Export CSV</span>
             </button>
             <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center gap-2 px-3 py-2 border rounded-lg transition-colors text-sm font-medium ${
                  showFilters || hasActiveFilters 
                  ? 'bg-blue-50 border-blue-200 text-blue-700' 
