/**
 * Detailed Export: One row per item for granular reporting in Excel.
 * Headers: Date, Name, Description, Material, Size A, Size B, QTY, Rate, Total Sq. Feet, Total Amount
 * This version includes a UTF-8 BOM to prevent character corruption (â,¹) in Excel.
 */
export const exportTransactionsToCSV = (transactions: Transaction[], filename: string) => {
  const headers = [
    "Date",
    "Name",
    "Description",
    "Material",
    "Size A",
    "Size B",
    "QTY",
    "Rate",
    "Total Sq. Feet",
    "Total Amount"
  ];

  const rows: string[][] = [];

  // Sort by date descending
  const sortedTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedTransactions.forEach(t => {
    // Format date as DD-MM-YYYY to match the user's image
    const [year, month, day] = t.date.split('-');
    const formattedDate = `${day}-${month}-${year}`;

    t.items.forEach(item => {
      rows.push([
        formattedDate,
        `"${(t.partyName || "-").replace(/"/g, '""')}"`,
        `"${(item.description || "-").replace(/"/g, '""')}"`,
        `"${(item.material || "-").replace(/"/g, '""')}"`,
        (item.sizeA || 0).toString(),
        (item.sizeB || 0).toString(),
        (item.quantity || 0).toString(),
        (item.rate || 0).toString(),
        (item.sqFt || 0).toString(),
        (item.amount || 0).toString()
      ]);
    });
  });

  // Adding \uFEFF (UTF-8 BOM) at the start for Excel compatibility
  const csvContent = "\uFEFF" + [
    headers.join(","),
    ...rows.map(row => row.join(","))
  ].join("\n");

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

/**
 * Copies detailed data to clipboard in TSV format for direct Excel/Google Sheets paste.
 */
export const copyTransactionsToClipboard = (transactions: Transaction[]) => {
  const headers = [
    "Date",
    "Name",
    "Description",
    "Material",
    "Size A",
    "Size B",
    "QTY",
    "Rate",
    "Total Sq. Feet",
    "Total Amount"
  ];

  const rows: string[][] = [];

  const sortedTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedTransactions.forEach(t => {
    const [year, month, day] = t.date.split('-');
    const formattedDate = `${day}-${month}-${year}`;

    t.items.forEach(item => {
      rows.push([
        formattedDate,
        t.partyName || "-",
        item.description || "-",
        item.material || "-",
        (item.sizeA || 0).toString(),
        (item.sizeB || 0).toString(),
        (item.quantity || 0).toString(),
        (item.rate || 0).toString(),
        (item.sqFt || 0).toString(),
        (item.amount || 0).toString()
      ]);
    });
  });

  const tsvContent = [
    headers.join("\t"),
    ...rows.map(row => row.join("\t"))
  ].join("\n");

  navigator.clipboard.writeText(tsvContent).then(() => {
    alert("Data copied! Ready to paste into Excel.");
  }).catch(err => {
    console.error('Copy error: ', err);
    alert("Clipboard copy failed.");
  });
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>(profile.defaultStatus || 'UNPAID');
  const [isEstimate, setIsEstimate] = useState(true);
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
      setIsEstimate(initialData.isEstimate !== undefined ? initialData.isEstimate : true);
    } else {
      const prefix = type === TransactionType.SALE ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Ensure size changes update SqFt
        if (field === 'sizeA' || field === 'sizeB') {
           updated.sqFt = Number((updated.sizeA * updated.sizeB).toFixed(2));
        }

        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;
        let baseAmount = 0;
        if (isDimensional) {
           // Standard flex calculation: (Width * Height) * Rate * Quantity
           baseAmount = updated.sqFt * updated.rate * updated.quantity;
        } else {
           // Simple quantity calculation
           baseAmount = updated.quantity * updated.rate;
        }

        updated.amount = Number(baseAmount.toFixed(2));
        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { 
      id: Date.now().toString(), 
      description: '', 
      material: '',
      sizeA: 0, 
      sizeB: 0, 
      sqFt: 0, 
      quantity: 1, 
      rate: 0, 
      unit: 'sqft', 
      amount: 0 
    }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(i => i.id !== id));
    } else {
      setItems([{ 
        id: Date.now().toString(), 
        description: '', 
        material: '',
        sizeA: 0, 
        sizeB: 0, 
        sqFt: 0, 
        quantity: 1, 
        rate: 0, 
        unit: 'sqft', 
        amount: 0 
      }]);
    }
  };

  const currentTransaction: Transaction = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    return {
      id: initialData?.id || 'temp',
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      subTotal,
      grandTotal: subTotal,
      status,
      isEstimate: type === TransactionType.SALE ? isEstimate : false
    };
  }, [type, invoiceNumber, date, partyName, partyAddress, items, status, isEstimate, initialData]);

  const handleSave = () => {
    if (!partyName) {
      alert("Please enter a client name");
      return;
    }
    onSave({ ...currentTransaction, id: initialData ? initialData.id : Date.now().toString() });
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-100 flex flex-col overflow-hidden">
      {/* Top Bar */}
      <div className="h-16 bg-white border-b border-slate-200 px-4 flex items-center justify-between shadow-sm flex-shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-lg font-bold text-slate-900 leading-tight">
              {initialData ? 'Update' : 'Create'} {type === TransactionType.SALE ? 'Estimate' : 'Purchase Bill'}
            </h2>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Real-time Editing Mode</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={() => setShowPreview(!showPreview)} 
            className={`hidden lg:flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold border transition-all ${
              showPreview ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-600'
            }`}
          >
            {showPreview ? <Edit3 size={18}/> : <Eye size={18}/>}
            {showPreview ? 'Hide Preview' : 'Show Preview'}
          </button>
          <button 
            onClick={handleSave} 
            className="flex items-center gap-2 bg-blue-600 text-white px-8 py-2 rounded-lg hover:bg-blue-700 transition-all font-bold shadow-lg shadow-blue-200"
          >
            <Save size={18} /> Save
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-8 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-xl xl:max-w-2xl' : 'max-w-4xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Client / Party Name</label>
                <input 
                  type="text" 
                  value={partyName} 
                  onChange={(e) => setPartyName(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-medium" 
                  placeholder="Who is this for?" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">{type === TransactionType.SALE ? 'Estimate' : 'Bill'} No.</label>
                <input 
                  type="text" 
                  value={invoiceNumber} 
                  onChange={(e) => setInvoiceNumber(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-mono" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Document Date</label>
                <input 
                  type="date" 
                  value={date} 
                  onChange={(e) => setDate(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Status & Type</label>
                <div className="grid grid-cols-2 gap-2">
                  <select 
                    value={isEstimate || type === TransactionType.PURCHASE ? 'ESTIMATE' : 'INVOICE'} 
                    onChange={(e) => setIsEstimate(e.target.value === 'ESTIMATE')}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold"
                    disabled={type === TransactionType.PURCHASE}
                  >
                    <option value="ESTIMATE">Estimate</option>
                    <option value="INVOICE">Invoice</option>
                  </select>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as 'PAID' | 'UNPAID')}
                    className={`w-full px-4 py-2.5 border rounded-lg outline-none text-sm font-bold ${status === 'PAID' ? 'bg-green-50 border-green-200 text-green-700' : 'bg-red-50 border-red-200 text-red-700'}`}
                  >
                    <option value="PAID">PAID</option>
                    <option value="UNPAID">UNPAID</option>
                  </select>
                </div>
              </div>
              <div className="md:col-span-2 space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Billing Address</label>
                <textarea 
                  value={partyAddress} 
                  onChange={(e) => setPartyAddress(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white h-20 transition-all text-sm" 
                  placeholder="Optional address details..." 
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-tighter">Line Items</h3>
                <button onClick={addItem} className="text-blue-600 text-xs font-black flex items-center gap-1 hover:underline">
                  <Plus size={16}/> ADD ROW
                </button>
              </div>

              <div className="space-y-3">
                {items.map((item, index) => (
                  <div key={item.id} className="p-4 bg-slate-50 rounded-xl border border-slate-200 space-y-4 relative group">
                    <button 
                      onClick={() => removeItem(item.id)} 
                      className="absolute top-4 right-4 text-slate-300 hover:text-red-500 transition-colors"
                    >
                      <Trash2 size={16}/>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                      <div className="md:col-span-2">
                        <input 
                          type="text" 
                          value={item.description} 
                          onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} 
                          className="w-full bg-transparent border-b border-slate-300 py-1 outline-none text-sm font-bold focus:border-blue-500 transition-all" 
                          placeholder="Description" 
                        />
                      </div>
                      <div className="md:col-span-2">
                         <input 
                          type="text" 
                          list="materials-list" 
                          value={item.material} 
                          onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} 
                          className="w-full bg-transparent border-b border-slate-300 py-1 outline-none text-sm focus:border-blue-500 transition-all" 
                          placeholder="Material" 
                        />
                        <datalist id="materials-list">
                          {profile.materials.map(m => <option key={m} value={m} />)}
                        </datalist>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Size (W x H)</label>
                        <div className="flex items-center gap-1">
                          <input type="number" value={item.sizeA || ''} onChange={(e) => handleItemChange(item.id, 'sizeA', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-center" placeholder="W"/>
                          <span className="text-slate-300">x</span>
                          <input type="number" value={item.sizeB || ''} onChange={(e) => handleItemChange(item.id, 'sizeB', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-center" placeholder="H"/>
                        </div>
                      </div>
                      <div className="space-y-1 text-center">
                        <label className="text-[9px] font-black text-slate-400 uppercase">SqFt (Area)</label>
                        <div className="text-sm font-black text-blue-600 h-8 flex items-center justify-center bg-blue-50 rounded border border-blue-100">{item.sqFt || '0'}</div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Rate</label>
                        <input type="number" value={item.rate || ''} onChange={(e) => handleItemChange(item.id, 'rate', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-right font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">QTY</label>
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 1)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-center" />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-200">
               <div className="flex flex-col items-end gap-2">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Total Estimate Value</p>
                  <div className="text-3xl font-black text-slate-900">
                    {profile.currencySymbol} {currentTransaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                  </div>
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="hidden lg:block flex-1 bg-slate-100 overflow-y-auto border-l border-slate-200 shadow-inner">
             <div className="p-12 min-w-min">
                <InvoicePreview transaction={currentTransaction} profile={profile} />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export enum TransactionType {
  SALE = 'SALE',
  PURCHASE = 'PURCHASE',
}

export interface LineItem {
  id: string;
  description: string;
  details: string;
  material: string;
  sizeA: number;
  sizeB: number;
  sqFt: number;
  quantity: number;
  rate: number;
  unit: string;
  amount: number;
}

export interface BusinessProfile {
  currencySymbol: string;
  defaultStatus: 'PAID' | 'UNPAID';
  materials: string[];
  pdfFooterNote: string;
  showSqFtInPdf: boolean;
  showMaterialInPdf: boolean;
  pdfThemeColor: string;
  pdfAccentColor: string;
  companyLogo?: string; // base64
}

export interface Transaction {
  id: string;
  type: TransactionType;
  invoiceNumber: string;
  date: string;
  partyName: string; 
  partyPhone?: string;
  partyAddress?: string; 
  items: LineItem[];
  subTotal: number;
  grandTotal: number;
  notes?: string;
  status: 'PAID' | 'UNPAID';
  isEstimate?: boolean;
}

export interface BusinessStats {
  totalSales: number;
  totalPurchases: number;
  totalProfit: number;
  unpaidInvoices: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', details: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>(profile.defaultStatus || 'UNPAID');
  const [isEstimate, setIsEstimate] = useState(true);
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
      setIsEstimate(initialData.isEstimate !== undefined ? initialData.isEstimate : true);
    } else {
      const prefix = type === TransactionType.SALE ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Ensure size changes update SqFt
        if (field === 'sizeA' || field === 'sizeB') {
           updated.sqFt = Number((updated.sizeA * updated.sizeB).toFixed(2));
        }

        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;
        let baseAmount = 0;
        if (isDimensional) {
           // Standard flex calculation: (Width * Height) * Rate * Quantity
           baseAmount = updated.sqFt * updated.rate * updated.quantity;
        } else {
           // Simple quantity calculation
           baseAmount = updated.quantity * updated.rate;
        }

        updated.amount = Number(baseAmount.toFixed(2));
        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { 
      id: Date.now().toString(), 
      description: '', 
      details: '',
      material: '',
      sizeA: 0, 
      sizeB: 0, 
      sqFt: 0, 
      quantity: 1, 
      rate: 0, 
      unit: 'sqft', 
      amount: 0 
    }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(i => i.id !== id));
    } else {
      setItems([{ 
        id: Date.now().toString(), 
        description: '', 
        details: '',
        material: '',
        sizeA: 0, 
        sizeB: 0, 
        sqFt: 0, 
        quantity: 1, 
        rate: 0, 
        unit: 'sqft', 
        amount: 0 
      }]);
    }
  };

  const currentTransaction: Transaction = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    return {
      id: initialData?.id || 'temp',
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      subTotal,
      grandTotal: subTotal,
      status,
      isEstimate: type === TransactionType.SALE ? isEstimate : false
    };
  }, [type, invoiceNumber, date, partyName, partyAddress, items, status, isEstimate, initialData]);

  const handleSave = () => {
    if (!partyName) {
      alert("Please enter a client name");
      return;
    }
    onSave({ ...currentTransaction, id: initialData ? initialData.id : Date.now().toString() });
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-100 flex flex-col overflow-hidden">
      {/* Top Bar */}
      <div className="h-16 bg-white border-b border-slate-200 px-4 flex items-center justify-between shadow-sm flex-shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-lg font-bold text-slate-900 leading-tight">
              {initialData ? 'Update' : 'Create'} {type === TransactionType.SALE ? 'Estimate' : 'Purchase Bill'}
            </h2>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Real-time Editing Mode</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={() => setShowPreview(!showPreview)} 
            className={`hidden lg:flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold border transition-all ${
              showPreview ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-600'
            }`}
          >
            {showPreview ? <Edit3 size={18}/> : <Eye size={18}/>}
            {showPreview ? 'Hide Preview' : 'Show Preview'}
          </button>
          <button 
            onClick={handleSave} 
            className="flex items-center gap-2 bg-blue-600 text-white px-8 py-2 rounded-lg hover:bg-blue-700 transition-all font-bold shadow-lg shadow-blue-200"
          >
            <Save size={18} /> Save
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-8 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-xl xl:max-w-2xl' : 'max-w-4xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Client / Party Name</label>
                <input 
                  type="text" 
                  value={partyName} 
                  onChange={(e) => setPartyName(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-medium" 
                  placeholder="Who is this for?" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">{type === TransactionType.SALE ? 'Estimate' : 'Bill'} No.</label>
                <input 
                  type="text" 
                  value={invoiceNumber} 
                  onChange={(e) => setInvoiceNumber(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-mono" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Document Date</label>
                <input 
                  type="date" 
                  value={date} 
                  onChange={(e) => setDate(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Status & Type</label>
                <div className="grid grid-cols-2 gap-2">
                  <select 
                    value={isEstimate || type === TransactionType.PURCHASE ? 'ESTIMATE' : 'INVOICE'} 
                    onChange={(e) => setIsEstimate(e.target.value === 'ESTIMATE')}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold"
                    disabled={type === TransactionType.PURCHASE}
                  >
                    <option value="ESTIMATE">Estimate</option>
                    <option value="INVOICE">Invoice</option>
                  </select>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as 'PAID' | 'UNPAID')}
                    className={`w-full px-4 py-2.5 border rounded-lg outline-none text-sm font-bold ${status === 'PAID' ? 'bg-green-50 border-green-200 text-green-700' : 'bg-red-50 border-red-200 text-red-700'}`}
                  >
                    <option value="PAID">PAID</option>
                    <option value="UNPAID">UNPAID</option>
                  </select>
                </div>
              </div>
              <div className="md:col-span-2 space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Billing Address</label>
                <textarea 
                  value={partyAddress} 
                  onChange={(e) => setPartyAddress(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white h-20 transition-all text-sm" 
                  placeholder="Optional address details..." 
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-tighter">Line Items</h3>
                <button onClick={addItem} className="text-blue-600 text-xs font-black flex items-center gap-1 hover:underline">
                  <Plus size={16}/> ADD ROW
                </button>
              </div>

              <div className="space-y-3">
                {items.map((item, index) => (
                  <div key={item.id} className="p-4 bg-slate-50 rounded-xl border border-slate-200 space-y-4 relative group">
                    <button 
                      onClick={() => removeItem(item.id)} 
                      className="absolute top-4 right-4 text-slate-300 hover:text-red-500 transition-colors"
                    >
                      <Trash2 size={16}/>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                      <div className="md:col-span-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Item Description</label>
                        <input 
                          type="text" 
                          value={item.description} 
                          onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} 
                          className="w-full bg-transparent border-b border-slate-300 py-1 outline-none text-sm font-bold focus:border-blue-500 transition-all" 
                          placeholder="Description" 
                        />
                      </div>
                      <div className="md:col-span-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Extra Details / Remarks</label>
                        <input 
                          type="text" 
                          value={item.details} 
                          onChange={(e) => handleItemChange(item.id, 'details', e.target.value)} 
                          className="w-full bg-transparent border-b border-slate-300 py-1 outline-none text-sm focus:border-blue-500 transition-all" 
                          placeholder="Details (optional)" 
                        />
                      </div>
                      <div className="md:col-span-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Material</label>
                         <input 
                          type="text" 
                          list="materials-list" 
                          value={item.material} 
                          onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} 
                          className="w-full bg-transparent border-b border-slate-300 py-1 outline-none text-sm focus:border-blue-500 transition-all" 
                          placeholder="Material" 
                        />
                        <datalist id="materials-list">
                          {profile.materials.map(m => <option key={m} value={m} />)}
                        </datalist>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Size (W x H)</label>
                        <div className="flex items-center gap-1">
                          <input type="number" value={item.sizeA || ''} onChange={(e) => handleItemChange(item.id, 'sizeA', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-center" placeholder="W"/>
                          <span className="text-slate-300">x</span>
                          <input type="number" value={item.sizeB || ''} onChange={(e) => handleItemChange(item.id, 'sizeB', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-center" placeholder="H"/>
                        </div>
                      </div>
                      <div className="space-y-1 text-center">
                        <label className="text-[9px] font-black text-slate-400 uppercase">SqFt (Area)</label>
                        <div className="text-sm font-black text-blue-600 h-8 flex items-center justify-center bg-blue-50 rounded border border-blue-100">{item.sqFt || '0'}</div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Rate</label>
                        <input type="number" value={item.rate || ''} onChange={(e) => handleItemChange(item.id, 'rate', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-right font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">QTY</label>
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 1)} className="w-full bg-white border border-slate-200 rounded px-2 py-1 text-sm text-center" />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-200">
               <div className="flex flex-col items-end gap-2">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Total Estimate Value</p>
                  <div className="text-3xl font-black text-slate-900">
                    {profile.currencySymbol} {currentTransaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
                  </div>
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="hidden lg:block flex-1 bg-slate-100 overflow-y-auto border-l border-slate-200 shadow-inner">
             <div className="p-12 min-w-min">
                <InvoicePreview transaction={currentTransaction} profile={profile} />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, TransactionType, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const savedProfile = localStorage.getItem('easyin_profile_v1');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      currencySymbol: "Rs.",
      defaultStatus: "UNPAID",
      materials: [],
      pdfFooterNote: "Thank you!",
      showSqFtInPdf: true,
      showMaterialInPdf: true,
      pdfThemeColor: "#2563eb"
    };

    const doc = new jsPDF();
    const docTitle = transaction.isEstimate || transaction.type === TransactionType.SALE ? "ESTIMATE" : "PURCHASE ORDER";

    // Explicitly type themeRGB as a tuple [number, number, number] to satisfy jspdf-autotable's Color expectations
    const themeRGB: [number, number, number] = profile.pdfThemeColor ? hexToRgb(profile.pdfThemeColor) : [37, 99, 235];

    // Header - Simplified (Removed Business Info)
    doc.setFontSize(22).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold').text("ESTIMATE DOCUMENT", 14, 20);
    doc.setFontSize(9).setTextColor(120, 120, 120).setFont(undefined, 'normal').text("OFFICIAL RECORD", 14, 28);

    // Document Info
    const rightX = 140;
    doc.setFontSize(24).setTextColor(230, 230, 230).setFont(undefined, 'bold').text(docTitle, rightX, 22);
    doc.setFontSize(9).setTextColor(60, 60, 60).setFont(undefined, 'normal');
    doc.text(`${transaction.isEstimate || transaction.type === TransactionType.SALE ? "Estimate" : "Bill"} #: ${transaction.invoiceNumber}`, rightX, 32);
    doc.text(`Date: ${transaction.date}`, rightX, 37);

    // Status Badge
    doc.setDrawColor(transaction.status === 'PAID' ? 22 : 220, transaction.status === 'PAID' ? 163 : 38, transaction.status === 'PAID' ? 74 : 38);
    doc.setFillColor(transaction.status === 'PAID' ? 240 : 254, transaction.status === 'PAID' ? 253 : 242, transaction.status === 'PAID' ? 244 : 242);
    doc.roundedRect(rightX, 42, 25, 6, 1, 1, 'FD');
    doc.setFontSize(7).setFont(undefined, 'bold').setTextColor(transaction.status === 'PAID' ? 22 : 220, transaction.status === 'PAID' ? 163 : 38, transaction.status === 'PAID' ? 74 : 38);
    doc.text(transaction.status, rightX + 12.5, 46.2, { align: 'center' });

    doc.setDrawColor(240).line(14, 55, 196, 55);

    // Bill To
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("BILLED TO", 14, 65);
    doc.setFontSize(12).setTextColor(0).setFont(undefined, 'bold').text(transaction.partyName, 14, 71);
    doc.setFont(undefined, 'normal').setFontSize(9).setTextColor(100);
    if (transaction.partyAddress) {
        const splitText = doc.splitTextToSize(transaction.partyAddress, 80);
        doc.text(splitText, 14, 77);
    }

    // Dynamic Columns based on settings
    const tableHeaders = ["#", "Description", "Details"];
    if (profile.showMaterialInPdf) tableHeaders.push("Material");
    tableHeaders.push("Size");
    if (profile.showSqFtInPdf) tableHeaders.push("SqFt");
    tableHeaders.push("Qty", "Rate", "Amount");

    const tableRows = transaction.items.map((item, index) => {
      const row = [index + 1, item.description, item.details || "-"];
      if (profile.showMaterialInPdf) row.push(item.material || "-");
      row.push(item.sizeA > 0 && item.sizeB > 0 ? `${item.sizeA}x${item.sizeB}` : "-");
      if (profile.showSqFtInPdf) row.push(item.sqFt > 0 ? item.sqFt.toString() : "-");
      row.push(item.quantity, item.rate.toFixed(2), item.amount.toFixed(2));
      return row;
    });

    autoTable(doc, {
      head: [tableHeaders],
      body: tableRows,
      startY: 95,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255, fontStyle: 'bold' },
      styles: { fontSize: 8, cellPadding: 3 },
      columnStyles: {
        0: { cellWidth: 10 },
        2: { cellWidth: 40 }, // Width for details column
        [tableHeaders.length - 1]: { halign: 'right', fontStyle: 'bold' }
      }
    });

    const finalY = (doc as any).lastAutoTable ? (doc as any).lastAutoTable.finalY + 15 : 150;

    // Summary
    const boxWidth = 70;
    const boxHeight = 12;
    const boxX = 196 - boxWidth;
    const boxY = finalY - 5;

    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(boxX, boxY, boxWidth, boxHeight, 1, 1, 'F');

    doc.setFontSize(9).setFont(undefined, 'bold').setTextColor(255);
    doc.text(`TOTAL AMOUNT`, boxX + 4, boxY + 7.5);

    const displayCurrency = profile.currencySymbol === '₹' ? 'Rs.' : profile.currencySymbol;
    doc.setFontSize(13).setFont(undefined, 'bold');
    doc.text(`${displayCurrency} ${transaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, 192, boxY + 7.5, { align: "right" });

    // Terms
    if (profile.pdfFooterNote) {
      doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("TERMS & CONDITIONS", 14, finalY + 15);
      doc.setFontSize(8).setTextColor(120).setFont(undefined, 'normal');
      doc.text(doc.splitTextToSize(profile.pdfFooterNote, 110), 14, finalY + 20);
    }

    // Signatory
    const footerY = Math.max(finalY + 50, 265);
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'normal').text("Authorized Signatory", 196, footerY + 5, { align: "right" });
    doc.setDrawColor(200).line(150, footerY, 196, footerY);

    doc.setFontSize(7).setTextColor(180).text(`Generated using EasyIn Invoicing • Date: ${new Date().toLocaleString()}`, 105, 290, { align: "center" });
    doc.save(`${docTitle}_${transaction.invoiceNumber}.pdf`);

  } catch (error) {
    console.error(error);
    alert("PDF Error: " + error);
  }
};

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? [
    parseInt(result[1], 16),
    parseInt(result[2], 16),
    parseInt(result[3], 16)
  ] : [37, 99, 235];
}

import { Transaction } from "../types";

/**
 * Detailed Export: One row per item for granular reporting in Excel.
 * Headers: Date, Name, Description, Details, Material, Size A, Size B, QTY, Rate, Total Sq. Feet, Total Amount
 * This version includes a UTF-8 BOM to prevent character corruption (â,¹) in Excel.
 */
export const exportTransactionsToCSV = (transactions: Transaction[], filename: string) => {
  const headers = [
    "Date",
    "Name",
    "Description",
    "Details",
    "Material",
    "Size A",
    "Size B",
    "QTY",
    "Rate",
    "Total Sq. Feet",
    "Total Amount"
  ];

  const rows: string[][] = [];

  // Sort by date descending
  const sortedTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedTransactions.forEach(t => {
    // Format date as DD-MM-YYYY to match the user's image
    const [year, month, day] = t.date.split('-');
    const formattedDate = `${day}-${month}-${year}`;

    t.items.forEach(item => {
      rows.push([
        formattedDate,
        `"${(t.partyName || "-").replace(/"/g, '""')}"`,
        `"${(item.description || "-").replace(/"/g, '""')}"`,
        `"${(item.details || "-").replace(/"/g, '""')}"`,
        `"${(item.material || "-").replace(/"/g, '""')}"`,
        (item.sizeA || 0).toString(),
        (item.sizeB || 0).toString(),
        (item.quantity || 0).toString(),
        (item.rate || 0).toString(),
        (item.sqFt || 0).toString(),
        (item.amount || 0).toString()
      ]);
    });
  });

  // Adding \uFEFF (UTF-8 BOM) at the start for Excel compatibility
  const csvContent = "\uFEFF" + [
    headers.join(","),
    ...rows.map(row => row.join(","))
  ].join("\n");

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

/**
 * Copies detailed data to clipboard in TSV format for direct Excel/Google Sheets paste.
 */
export const copyTransactionsToClipboard = (transactions: Transaction[]) => {
  const headers = [
    "Date",
    "Name",
    "Description",
    "Details",
    "Material",
    "Size A",
    "Size B",
    "QTY",
    "Rate",
    "Total Sq. Feet",
    "Total Amount"
  ];

  const rows: string[][] = [];

  const sortedTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  sortedTransactions.forEach(t => {
    const [year, month, day] = t.date.split('-');
    const formattedDate = `${day}-${month}-${year}`;

    t.items.forEach(item => {
      rows.push([
        formattedDate,
        t.partyName || "-",
        item.description || "-",
        item.details || "-",
        item.material || "-",
        (item.sizeA || 0).toString(),
        (item.sizeB || 0).toString(),
        (item.quantity || 0).toString(),
        (item.rate || 0).toString(),
        (item.sqFt || 0).toString(),
        (item.amount || 0).toString()
      ]);
    });
  });

  const tsvContent = [
    headers.join("\t"),
    ...rows.map(row => row.join("\t"))
  ].join("\n");

  navigator.clipboard.writeText(tsvContent).then(() => {
    alert("Data copied! Ready to paste into Excel.");
  }).catch(err => {
    console.error('Copy error: ', err);
    alert("Clipboard copy failed.");
  });
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', details: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>(profile.defaultStatus || 'UNPAID');
  const [isEstimate, setIsEstimate] = useState(true);
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
      setIsEstimate(initialData.isEstimate !== undefined ? initialData.isEstimate : true);
    } else {
      const prefix = type === TransactionType.SALE ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;

        // Formula: SizeA * SizeB * Quantity = Total SqFt
        if (isDimensional) {
           updated.sqFt = Number((updated.sizeA * updated.sizeB * updated.quantity).toFixed(2));
           // Formula: Total SqFt * Rate = Amount
           updated.amount = Number((updated.sqFt * updated.rate).toFixed(2));
        } else {
           updated.sqFt = 0;
           // Fallback: Quantity * Rate = Amount (for non-dimensional items)
           updated.amount = Number((updated.quantity * updated.rate).toFixed(2));
        }

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { 
      id: Date.now().toString(), 
      description: '', 
      details: '',
      material: '',
      sizeA: 0, 
      sizeB: 0, 
      sqFt: 0, 
      quantity: 1, 
      rate: 0, 
      unit: 'sqft', 
      amount: 0 
    }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(i => i.id !== id));
    } else {
      setItems([{ 
        id: Date.now().toString(), 
        description: '', 
        details: '',
        material: '',
        sizeA: 0, 
        sizeB: 0, 
        sqFt: 0, 
        quantity: 1, 
        rate: 0, 
        unit: 'sqft', 
        amount: 0 
      }]);
    }
  };

  const currentTransaction: Transaction = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    return {
      id: initialData?.id || 'temp',
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      subTotal,
      grandTotal: subTotal,
      status,
      isEstimate: type === TransactionType.SALE ? isEstimate : false
    };
  }, [type, invoiceNumber, date, partyName, partyAddress, items, status, isEstimate, initialData]);

  const handleSave = () => {
    if (!partyName) {
      alert("Please enter a client name");
      return;
    }
    onSave({ ...currentTransaction, id: initialData ? initialData.id : Date.now().toString() });
  };

  return (
    <div className="fixed inset-0 z-50 bg-slate-100 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-4 flex items-center justify-between shadow-sm flex-shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-lg font-bold text-slate-900 leading-tight">
              {initialData ? 'Update' : 'Create'} {type === TransactionType.SALE ? 'Estimate' : 'Purchase Bill'}
            </h2>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Real-time Editing Mode</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={() => setShowPreview(!showPreview)} 
            className={`hidden lg:flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold border transition-all ${
              showPreview ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-600'
            }`}
          >
            {showPreview ? <Edit3 size={18}/> : <Eye size={18}/>}
            {showPreview ? 'Hide Preview' : 'Show Preview'}
          </button>
          <button 
            onClick={handleSave} 
            className="flex items-center gap-2 bg-blue-600 text-white px-8 py-2 rounded-lg hover:bg-blue-700 transition-all font-bold shadow-lg shadow-blue-200"
          >
            <Save size={18} /> Save
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-8 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-xl xl:max-w-2xl' : 'max-w-4xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Client / Party Name</label>
                <input 
                  type="text" 
                  value={partyName} 
                  onChange={(e) => setPartyName(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-medium" 
                  placeholder="Who is this for?" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">{type === TransactionType.SALE ? 'Estimate' : 'Bill'} No.</label>
                <input 
                  type="text" 
                  value={invoiceNumber} 
                  onChange={(e) => setInvoiceNumber(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-mono" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Document Date</label>
                <input 
                  type="date" 
                  value={date} 
                  onChange={(e) => setDate(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Status & Type</label>
                <div className="grid grid-cols-2 gap-2">
                  <select 
                    value={isEstimate || type === TransactionType.PURCHASE ? 'ESTIMATE' : 'INVOICE'} 
                    onChange={(e) => setIsEstimate(e.target.value === 'ESTIMATE')}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none text-sm font-bold"
                    disabled={type === TransactionType.PURCHASE}
                  >
                    <option value="ESTIMATE">Estimate</option>
                    <option value="INVOICE">Invoice</option>
                  </select>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as 'PAID' | 'UNPAID')}
                    className={`w-full px-4 py-2.5 border rounded-lg outline-none text-sm font-bold ${status === 'PAID' ? 'bg-green-50 border-green-200 text-green-700' : 'bg-red-50 border-red-200 text-red-700'}`}
                  >
                    <option value="PAID">PAID</option>
                    <option value="UNPAID">UNPAID</option>
                  </select>
                </div>
              </div>
              <div className="md:col-span-2 space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Billing Address</label>
                <textarea 
                  value={partyAddress} 
                  onChange={(e) => setPartyAddress(e.target.value)} 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white h-20 transition-all text-sm" 
                  placeholder="Optional address details..." 
