import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, TransactionType, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const savedProfile = localStorage.getItem('easyin_profile_v1');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      currencySymbol: "Rs.",
      defaultStatus: "UNPAID",
      materials: [],
      pdfFooterNote: "Thank you!",
      showSqFtInPdf: true,
      showMaterialInPdf: true,
      pdfThemeColor: "#2563eb"
    };

    const doc = new jsPDF();
    const docTitle = transaction.isEstimate || transaction.type === TransactionType.SALE ? "ESTIMATE" : "PURCHASE ORDER";

    // Explicitly type themeRGB as a tuple [number, number, number] to satisfy jspdf-autotable's Color expectations
    const themeRGB: [number, number, number] = profile.pdfThemeColor ? hexToRgb(profile.pdfThemeColor) : [37, 99, 235];

    // Header - Simplified (Removed Business Info)
    doc.setFontSize(22).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold').text("ESTIMATE DOCUMENT", 14, 20);
    doc.setFontSize(9).setTextColor(120, 120, 120).setFont(undefined, 'normal').text("OFFICIAL RECORD", 14, 28);

    // Document Info
    const rightX = 140;
    doc.setFontSize(24).setTextColor(230, 230, 230).setFont(undefined, 'bold').text(docTitle, rightX, 22);
    doc.setFontSize(9).setTextColor(60, 60, 60).setFont(undefined, 'normal');
    doc.text(`${transaction.isEstimate || transaction.type === TransactionType.SALE ? "Estimate" : "Bill"} #: ${transaction.invoiceNumber}`, rightX, 32);
    doc.text(`Date: ${transaction.date}`, rightX, 37);

    // Status Badge
    doc.setDrawColor(transaction.status === 'PAID' ? 22 : 220, transaction.status === 'PAID' ? 163 : 38, transaction.status === 'PAID' ? 74 : 38);
    doc.setFillColor(transaction.status === 'PAID' ? 240 : 254, transaction.status === 'PAID' ? 253 : 242, transaction.status === 'PAID' ? 244 : 242);
    doc.roundedRect(rightX, 42, 25, 6, 1, 1, 'FD');
    doc.setFontSize(7).setFont(undefined, 'bold').setTextColor(transaction.status === 'PAID' ? 22 : 220, transaction.status === 'PAID' ? 163 : 38, transaction.status === 'PAID' ? 74 : 38);
    doc.text(transaction.status, rightX + 12.5, 46.2, { align: 'center' });

    doc.setDrawColor(240).line(14, 55, 196, 55);

    // Bill To
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("BILLED TO", 14, 65);
    doc.setFontSize(12).setTextColor(0).setFont(undefined, 'bold').text(transaction.partyName, 14, 71);
    doc.setFont(undefined, 'normal').setFontSize(9).setTextColor(100);
    if (transaction.partyAddress) {
        const splitText = doc.splitTextToSize(transaction.partyAddress, 80);
        doc.text(splitText, 14, 77);
    }

    // Dynamic Columns based on settings
    const tableHeaders = ["#", "Description", "Details"];
    if (profile.showMaterialInPdf) tableHeaders.push("Material");
    tableHeaders.push("Size", "Qty");
    if (profile.showSqFtInPdf) tableHeaders.push("Total SqFt");
    tableHeaders.push("Rate", "Amount");

    const tableRows = transaction.items.map((item, index) => {
      const row = [index + 1, item.description, item.details || "-"];
      if (profile.showMaterialInPdf) row.push(item.material || "-");
      row.push(item.sizeA > 0 && item.sizeB > 0 ? `${item.sizeA}x${item.sizeB}` : "-", item.quantity.toString());
      if (profile.showSqFtInPdf) row.push(item.sqFt > 0 ? item.sqFt.toString() : "-");
      row.push(item.rate.toFixed(2), item.amount.toFixed(2));
      return row;
    });

    autoTable(doc, {
      head: [tableHeaders],
      body: tableRows,
      startY: 95,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255, fontStyle: 'bold' },
      styles: { fontSize: 8, cellPadding: 3 },
      columnStyles: {
        0: { cellWidth: 10 },
        2: { cellWidth: 35 },
        [tableHeaders.length - 1]: { halign: 'right', fontStyle: 'bold' }
      }
    });

    const finalY = (doc as any).lastAutoTable ? (doc as any).lastAutoTable.finalY + 15 : 150;

    // Summary
    const boxWidth = 70;
    const boxHeight = 12;
    const boxX = 196 - boxWidth;
    const boxY = finalY - 5;

    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(boxX, boxY, boxWidth, boxHeight, 1, 1, 'F');

    doc.setFontSize(9).setFont(undefined, 'bold').setTextColor(255);
    doc.text(`TOTAL AMOUNT`, boxX + 4, boxY + 7.5);

    const displayCurrency = profile.currencySymbol === '₹' ? 'Rs.' : profile.currencySymbol;
    doc.setFontSize(13).setFont(undefined, 'bold');
    doc.text(`${displayCurrency} ${transaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, 192, boxY + 7.5, { align: "right" });

    // Terms
    if (profile.pdfFooterNote) {
      doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("TERMS & CONDITIONS", 14, finalY + 15);
      doc.setFontSize(8).setTextColor(120).setFont(undefined, 'normal');
      doc.text(doc.splitTextToSize(profile.pdfFooterNote, 110), 14, finalY + 20);
    }

    // Signatory
    const footerY = Math.max(finalY + 50, 265);
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'normal').text("Authorized Signatory", 196, footerY + 5, { align: "right" });
    doc.setDrawColor(200).line(150, footerY, 196, footerY);

    doc.setFontSize(7).setTextColor(180).text(`Generated using EasyIn Invoicing • Date: ${new Date().toLocaleString()}`, 105, 290, { align: "center" });
    doc.save(`${docTitle}_${transaction.invoiceNumber}.pdf`);

  } catch (error) {
    console.error(error);
    alert("PDF Error: " + error);
  }
};

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? [
    parseInt(result[1], 16),
    parseInt(result[2], 16),
    parseInt(result[3], 16)
  ] : [37, 99, 235];
}

