              `}
            >
              <div className="flex items-center gap-3">
                <span className={`${activeTab === item.id ? 'text-blue-600' : 'text-slate-400'}`}>
                  {item.icon}
                </span>
                {item.label}
              </div>
              {activeTab === item.id && <ChevronRight size={14} className="opacity-50" />}
            </button>
          ))}
        </nav>

        <div className="absolute bottom-0 w-full p-4 border-t border-slate-100 bg-white">
          <div className="px-4 py-3 bg-slate-50 rounded-xl border border-slate-200/50">
             <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Desktop App Ready</p>
             </div>
             <p className="text-xs font-bold text-slate-700 mt-1">Version 1.0.0 Stable</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 lg:px-8 shrink-0">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg"
          >
            <Menu size={20} />
          </button>

          <div className="flex items-center gap-6 ml-auto">
            <div className="hidden sm:flex flex-col items-end">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Current Environment</p>
              <p className="text-sm font-bold text-slate-800">Local Machine / EXE Mode</p>
            </div>
            <div className="h-10 w-px bg-slate-100"></div>
            <button 
              onClick={() => onNavigate('settings')}
              className="h-10 w-10 rounded-xl bg-slate-50 text-slate-500 flex items-center justify-center border border-slate-200 hover:bg-white hover:text-blue-600 hover:border-blue-200 transition-all shadow-sm"
            >
              <SettingsIcon size={18} />
            </button>
          </div>
        </header>

        {/* Content Body */}
        <main className="flex-1 overflow-auto bg-slate-50/50">
          <div className="max-w-[1600px] mx-auto p-4 lg:p-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData, profile }) => {
  const isSale = type === TransactionType.SALE;

  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', details: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>(profile.defaultStatus || 'UNPAID');
  const [isEstimate, setIsEstimate] = useState(isSale);
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
      setIsEstimate(initialData.isEstimate !== undefined ? initialData.isEstimate : isSale);
    } else {
      const prefix = isSale ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;

        if (isDimensional) {
           const rawAreaPerPiece = updated.sizeA * updated.sizeB;
           const minSqFt = isSale ? (profile.minSqFtPerPiece || 0) : 0; // Only apply min area for sales
           const effectiveAreaPerPiece = Math.max(rawAreaPerPiece, minSqFt);

           updated.sqFt = Number((effectiveAreaPerPiece * updated.quantity).toFixed(2));
           const calculatedAmount = updated.sqFt * updated.rate;

           const minAmt = isSale ? (profile.minItemAmount || 0) : 0; // Only apply min amount for sales
           updated.amount = Number(Math.max(calculatedAmount, minAmt).toFixed(2));
        } else {
           updated.sqFt = 0;
           const calculatedAmount = updated.quantity * updated.rate;
           const minAmt = isSale ? (profile.minItemAmount || 0) : 0;
           updated.amount = Number(Math.max(calculatedAmount, minAmt).toFixed(2));
        }

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { 
      id: Date.now().toString(), 
      description: '', 
      details: '',
      material: '',
      sizeA: 0, 
      sizeB: 0, 
      sqFt: 0, 
      quantity: 1, 
      rate: 0, 
      unit: 'sqft', 
      amount: 0 
    }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(i => i.id !== id));
    } else {
      setItems([{ 
        id: Date.now().toString(), 
        description: '', 
        details: '',
        material: '',
        sizeA: 0, 
        sizeB: 0, 
        sqFt: 0, 
        quantity: 1, 
        rate: 0, 
        unit: 'sqft', 
        amount: 0 
      }]);
    }
  };

  const currentTransaction: Transaction = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    return {
      id: initialData?.id || 'temp',
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      subTotal,
      grandTotal: subTotal,
      status,
      isEstimate: isSale ? isEstimate : false
    };
  }, [type, invoiceNumber, date, partyName, partyAddress, items, status, isEstimate, initialData]);

  const handleSave = () => {
    if (!partyName) {
      alert(`Please enter a ${isSale ? 'client' : 'supplier'} name`);
      return;
    }
    onSave({ ...currentTransaction, id: initialData ? initialData.id : Date.now().toString() });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-50 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-4 flex items-center justify-between shadow-sm flex-shrink-0 z-10">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-lg font-bold text-slate-900 leading-tight">
              {initialData ? 'Update' : 'Create'} {isSale ? 'Estimate' : 'Purchase Bill'}
            </h2>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Transaction Editor</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setShowPreview(!showPreview)} 
            className={`hidden lg:flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold border transition-all ${
              showPreview ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-600'
            }`}
          >
            {showPreview ? <Edit3 size={18}/> : <Eye size={18}/>}
            {showPreview ? 'Hide Preview' : 'Live Preview'}
          </button>
          <button onClick={handleSave} className="flex items-center gap-2 bg-blue-600 text-white px-8 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-wider text-xs">
            <Save size={18} /> Save Entry
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-10 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-2xl xl:max-w-3xl' : 'max-w-5xl mx-auto'}`}>
          <div className="space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isSale ? 'Customer / Client Name' : 'Supplier / Vendor Name'}</label>
                <input type="text" value={partyName} onChange={(e) => setPartyName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-bold text-slate-800" placeholder={isSale ? "Who are you billing?" : "Who did you buy from?"} />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{isSale ? 'Doc Number' : 'Bill Reference'}</label>
                <input type="text" value={invoiceNumber} onChange={(e) => setInvoiceNumber(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-mono font-bold" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Entry Date</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-bold" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Type & Status</label>
                <div className="grid grid-cols-2 gap-3">
                  <select 
                    value={isEstimate || !isSale ? 'ESTIMATE' : 'INVOICE'} 
                    onChange={(e) => setIsEstimate(e.target.value === 'ESTIMATE')} 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm font-bold appearance-none cursor-pointer"
                    disabled={!isSale}
                  >
                    <option value="ESTIMATE">Estimate</option>
                    <option value="INVOICE">Final Bill</option>
                  </select>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as 'PAID' | 'UNPAID')} 
                    className={`w-full px-4 py-3 border rounded-xl outline-none text-sm font-black appearance-none cursor-pointer transition-colors ${status === 'PAID' ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-rose-50 border-rose-200 text-rose-700'}`}
                  >
                    <option value="PAID">PAID</option>
                    <option value="UNPAID">UNPAID</option>
                  </select>
                </div>
              </div>
              <div className="md:col-span-2 space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Billing/Vendor Address</label>
                <textarea value={partyAddress} onChange={(e) => setPartyAddress(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white h-24 transition-all text-sm font-medium" placeholder="Additional details..." />
              </div>
            </div>

            <div className="space-y-6 pt-4 border-t border-slate-100">
              <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Line Items (Materials & Services)</h3>
                <button onClick={addItem} className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-slate-800 transition-all uppercase tracking-widest">
                  <Plus size={14}/> Add Row
                </button>
              </div>

              <div className="space-y-4">
                {items.map((item, index) => (
                  <div key={item.id} className="p-5 bg-white rounded-2xl border border-slate-200 shadow-sm space-y-5 relative group hover:border-blue-300 transition-all">
                    <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500 transition-colors">
                      <Trash2 size={16}/>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-4 gap-5">
                      <div className="md:col-span-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Description</label>
                        <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-slate-50 border-b-2 border-slate-200 rounded-t-lg px-3 py-2 outline-none text-sm font-bold focus:border-blue-500 transition-all" placeholder="Item Name" />
                      </div>
                      <div className="md:col-span-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Remarks</label>
                        <input type="text" value={item.details} onChange={(e) => handleItemChange(item.id, 'details', e.target.value)} className="w-full bg-slate-50 border-b-2 border-slate-200 rounded-t-lg px-3 py-2 outline-none text-sm font-medium focus:border-blue-500 transition-all" placeholder="Size variations, color, etc." />
                      </div>
                      <div className="md:col-span-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Material</label>
                         <input type="text" list="materials-list" value={item.material} onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} className="w-full bg-slate-50 border-b-2 border-slate-200 rounded-t-lg px-3 py-2 outline-none text-sm font-bold focus:border-blue-500 transition-all" placeholder="Select..." />
                        <datalist id="materials-list">
                          {profile.materials.map(m => <option key={m} value={m} />)}
                        </datalist>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-5">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Dimensions (W x H)</label>
                        <div className="flex items-center gap-2">
                          <input type="number" value={item.sizeA || ''} onChange={(e) => handleItemChange(item.id, 'sizeA', parseFloat(e.target.value) || 0)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-2 py-2 text-sm text-center font-bold" placeholder="W"/>
                          <span className="text-slate-300 font-bold">×</span>
                          <input type="number" value={item.sizeB || ''} onChange={(e) => handleItemChange(item.id, 'sizeB', parseFloat(e.target.value) || 0)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-2 py-2 text-sm text-center font-bold" placeholder="H"/>
                        </div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Quantity</label>
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 1)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1 text-center">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total SqFt</label>
                        <div className="text-sm font-black text-blue-700 h-10 flex items-center justify-center bg-blue-50/50 rounded-lg border-2 border-blue-100">{item.sqFt || '0'}</div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Rate (₹)</label>
                        <input type="number" value={item.rate || ''} onChange={(e) => handleItemChange(item.id, 'rate', parseFloat(e.target.value) || 0)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-right font-black" />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-200 flex flex-col items-end gap-2">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Grand Total Balance</p>
               <div className="text-4xl font-black text-slate-900 flex items-center gap-3">
                 <span className="text-blue-600 font-medium text-2xl">{profile.currencySymbol}</span>
                 {currentTransaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="hidden lg:block flex-1 bg-slate-100 overflow-y-auto border-l border-slate-200">
             <div className="p-12 scale-[0.85] origin-top">
                <InvoicePreview transaction={currentTransaction} profile={profile} />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Settings } from './components/Settings';
import { UnitConverter } from './components/UnitConverter';
import { Transaction, TransactionType, BusinessProfile } from './types';

const DEFAULT_MATERIALS = [
  "Regular Flex", "B.B. Reg. Flex", "Star Flex", "Vinyl", 
  "Vinyl + Lam", "Vinyl + Foamsheet", "One Way", "Retro Vinyl", 
  "Transperant Vinyl", "Backlit", "Vinyl + Lam + Foamsheet", "Foamsheet"
];

const DEFAULT_PROFILE: BusinessProfile = {
  currencySymbol: '₹',
  defaultStatus: 'UNPAID',
  materials: DEFAULT_MATERIALS,
  pdfFooterNote: 'Thank you for your business! Goods once sold will not be taken back.',
  showSqFtInPdf: true,
  showMaterialInPdf: true,
  pdfThemeColor: '#2563eb',
  pdfAccentColor: '#1e40af',
  minSqFtPerPiece: 0,
  minItemAmount: 0
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [formType, setFormType] = useState<TransactionType>(TransactionType.SALE);

  useEffect(() => {
    const savedTxns = localStorage.getItem('easyin_transactions_v1');
    if (savedTxns) {
      try {
        setTransactions(JSON.parse(savedTxns));
      } catch (e) {
        console.error("Failed to parse transactions");
      }
    }

    const savedProfile = localStorage.getItem('easyin_profile_v1');
    if (savedProfile) {
      try {
        const parsed = JSON.parse(savedProfile);
        setBusinessProfile({ ...DEFAULT_PROFILE, ...parsed });
      } catch (e) {
        setBusinessProfile(DEFAULT_PROFILE);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('easyin_transactions_v1', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('easyin_profile_v1', JSON.stringify(businessProfile));
  }, [businessProfile]);

  const handleNavigate = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleAddTransaction = (type: TransactionType) => {
    setFormType(type);
    setEditingTransaction(null);
    setViewState('form');
  };

  const handleEditTransaction = (transaction: Transaction) => {
    setFormType(transaction.type);
    setEditingTransaction(transaction);
    setViewState('form');
  };

  const handleDeleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <Dashboard 
            transactions={transactions} 
            onAddInvoice={() => {
              setActiveTab('sales');
              handleAddTransaction(TransactionType.SALE);
            }} 
          />
        );
      case 'reports':
        return <Reports transactions={transactions} />;
      case 'settings':
        return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      case 'data':
        return <DataManagement transactions={transactions} onImport={setTransactions} />;
      case 'converter':
        return <UnitConverter />;
      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              type={formType} 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => setViewState('list')}
            />
          );
        }
        return (
          <TransactionList 
            type={TransactionType.SALE}
            transactions={transactions}
            onAdd={() => handleAddTransaction(TransactionType.SALE)}
            onEdit={handleEditTransaction}
            onDelete={handleDeleteTransaction}
          />
        );
      case 'purchases':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              type={formType} 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => setViewState('list')}
            />
          );
        }
        return (
          <TransactionList 
            type={TransactionType.PURCHASE}
            transactions={transactions}
            onAdd={() => handleAddTransaction(TransactionType.PURCHASE)}
            onEdit={handleEditTransaction}
            onDelete={handleDeleteTransaction}
          />
        );
      default:
        return <div className="p-8 text-center text-slate-500 font-bold">Page coming soon...</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { TrendingUp, CheckCircle, IndianRupee, FileText, Download, Wallet, ArrowDownCircle, ArrowUpCircle } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const [reportType, setReportType] = useState<'SALES' | 'PURCHASE' | 'CASHFLOW'>('SALES');

  const sales = transactions.filter(t => t.type === TransactionType.SALE);
  const purchases = transactions.filter(t => t.type === TransactionType.PURCHASE);

  const totalSales = sales.reduce((acc, t) => acc + t.grandTotal, 0);
  const totalPurchases = purchases.reduce((acc, t) => acc + t.grandTotal, 0);

  const paidSales = sales.filter(t => t.status === 'PAID').reduce((acc, t) => acc + t.grandTotal, 0);
  const unpaidSales = sales.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + t.grandTotal, 0);

  const paidPurchases = purchases.filter(t => t.status === 'PAID').reduce((acc, t) => acc + t.grandTotal, 0);
  const unpaidPurchases = purchases.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + t.grandTotal, 0);

  const handleExportFullReport = () => {
    if (transactions.length === 0) {
      alert("No data available to export.");
      return;
    }
    exportTransactionsToCSV(transactions, "Complete_Business_Report");
  };

  const cashFlow = useMemo(() => {
    const balance = totalSales - totalPurchases;
    const actualCash = paidSales - paidPurchases;
    return { balance, actualCash };
  }, [totalSales, totalPurchases, paidSales, paidPurchases]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Business Reports</h1>
          <p className="text-slate-500 font-medium">Detailed insights into your financial data.</p>
        </div>
        <button 
          onClick={handleExportFullReport}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 text-xs uppercase tracking-wider"
        >
          <Download size={18} />
          Export All Data (CSV)
        </button>
      </div>

      <div className="flex bg-white border border-slate-200 p-1 rounded-xl w-full md:w-fit">
        <button 
          onClick={() => setReportType('SALES')}
          className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${reportType === 'SALES' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
        >
          Sales
        </button>
        <button 
          onClick={() => setReportType('PURCHASE')}
          className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${reportType === 'PURCHASE' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
        >
          Purchases
        </button>
        <button 
          onClick={() => setReportType('CASHFLOW')}
          className={`flex-1 md:flex-none px-6 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${reportType === 'CASHFLOW' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'}`}
        >
          Cash Flow
        </button>
      </div>

      {reportType === 'SALES' && (
        <div className="animate-in fade-in slide-in-from-top-2 duration-300 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <ReportCard title="Gross Sales" value={totalSales} color="blue" icon={<TrendingUp size={20} />} />
            <ReportCard title="Sales Collected" value={paidSales} color="green" icon={<CheckCircle size={20} />} />
            <ReportCard title="Sales Outstanding" value={unpaidSales} color="orange" icon={<IndianRupee size={20} />} />
          </div>
          <SummaryTable title="Sales Summary" data={[
            { label: 'Total Sales Count', value: sales.length.toString() },
            { label: 'Average Sale Value', value: sales.length > 0 ? `₹${(totalSales / sales.length).toFixed(2)}` : '₹0.00' },
            { label: 'Highest Sale', value: `₹${Math.max(0, ...sales.map(s => s.grandTotal)).toFixed(2)}` }
          ]} />
        </div>
      )}

      {reportType === 'PURCHASE' && (
        <div className="animate-in fade-in slide-in-from-top-2 duration-300 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <ReportCard title="Total Purchases" value={totalPurchases} color="rose" icon={<ArrowDownCircle size={20} />} />
            <ReportCard title="Purchases Paid" value={paidPurchases} color="emerald" icon={<CheckCircle size={20} />} />
            <ReportCard title="Purchases Due" value={unpaidPurchases} color="amber" icon={<IndianRupee size={20} />} />
          </div>
          <SummaryTable title="Purchase Summary" data={[
            { label: 'Total Purchase Orders', value: purchases.length.toString() },
            { label: 'Average Purchase Value', value: purchases.length > 0 ? `₹${(totalPurchases / purchases.length).toFixed(2)}` : '₹0.00' },
            { label: 'Pending Payments', value: `₹${unpaidPurchases.toFixed(2)}` }
          ]} />
        </div>
      )}

      {reportType === 'CASHFLOW' && (
        <div className="animate-in fade-in slide-in-from-top-2 duration-300 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
                <div>
                   <div className="flex items-center gap-3 mb-4">
                      <div className="p-3 bg-blue-50 text-blue-600 rounded-xl"><Wallet size={24} /></div>
                      <h4 className="font-black text-slate-800 uppercase tracking-widest text-sm">Net Business Balance</h4>
                   </div>
                   <p className="text-4xl font-black text-slate-900">₹{cashFlow.balance.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</p>
                   <p className="text-xs text-slate-500 mt-2 font-medium">Formula: (Total Sales - Total Purchases)</p>
                </div>
            </div>
            <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
                <div>
                   <div className="flex items-center gap-3 mb-4">
                      <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl"><ArrowUpCircle size={24} /></div>
                      <h4 className="font-black text-slate-800 uppercase tracking-widest text-sm">Actual Cash In Hand</h4>
                   </div>
                   <p className="text-4xl font-black text-slate-900">₹{cashFlow.actualCash.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</p>
                   <p className="text-xs text-slate-500 mt-2 font-medium">Formula: (Sales Paid - Purchases Paid)</p>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const ReportCard: React.FC<{title: string, value: number, color: string, icon: React.ReactNode}> = ({ title, value, color, icon }) => {
    const colorClasses: Record<string, string> = {
        blue: 'bg-blue-50 text-blue-700 border-blue-100',
        green: 'bg-emerald-50 text-emerald-700 border-emerald-100',
        orange: 'bg-orange-50 text-orange-700 border-orange-100',
        rose: 'bg-rose-50 text-rose-700 border-rose-100',
        emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
        amber: 'bg-amber-50 text-amber-700 border-amber-100',
    };

    return (
        <div className={`p-6 rounded-2xl border ${colorClasses[color] || 'bg-slate-50'} flex flex-col justify-between h-36 transition-transform hover:scale-[1.02]`}>
            <div className="flex justify-between items-start">
                 <h4 className="text-xs font-black uppercase tracking-widest opacity-80">{title}</h4>
                 <div className="opacity-80 p-2 bg-white/50 rounded-lg">{icon}</div>
            </div>
            <p className="text-2xl font-black mt-2">
                {new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' }).format(value)}
            </p>
        </div>
    );
}

const SummaryTable: React.FC<{title: string, data: {label: string, value: string}[]}> = ({ title, data }) => (
  <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
    <div className="p-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
       <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">{title}</h3>
    </div>
    <div className="p-6">
        <div className="space-y-4">
            {data.map((item, idx) => (
                <div key={idx} className="flex justify-between items-center py-2 border-b border-slate-50 last:border-0">
                    <span className="text-sm font-bold text-slate-500">{item.label}</span>
                    <span className="text-sm font-black text-slate-900">{item.value}</span>
                </div>
            ))}
        </div>
    </div>
  </div>
);

