import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3, Percent, Tag as DiscountIcon } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  type: TransactionType;
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ type, onSave, onCancel, initialData, profile }) => {
  const isSale = type === TransactionType.SALE;

  const [partyName, setPartyName] = useState('');
  const [partyAddress, setPartyAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', details: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0, taxPercent: 0, discount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>(profile.defaultStatus || 'UNPAID');
  const [isEstimate, setIsEstimate] = useState(isSale);
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setPartyAddress(initialData.partyAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
      setIsEstimate(initialData.isEstimate !== undefined ? initialData.isEstimate : isSale);
    } else {
      const prefix = isSale ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        const isDimensional = updated.sizeA > 0 && updated.sizeB > 0;

        if (isDimensional) {
           const rawAreaPerPiece = updated.sizeA * updated.sizeB;
           const minSqFt = isSale ? (profile.minSqFtPerPiece || 0) : 0;
           const effectiveAreaPerPiece = Math.max(rawAreaPerPiece, minSqFt);
           updated.sqFt = Number((effectiveAreaPerPiece * updated.quantity).toFixed(2));
           const calculatedAmount = updated.sqFt * updated.rate;
           updated.amount = Number(Math.max(calculatedAmount, (isSale ? profile.minItemAmount : 0)).toFixed(2));
        } else {
           updated.sqFt = 0;
           const calculatedAmount = updated.quantity * updated.rate;
           updated.amount = Number(Math.max(calculatedAmount, (isSale ? profile.minItemAmount : 0)).toFixed(2));
        }
        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', details: '', material: '', sizeA: 0, sizeB: 0, sqFt: 0, quantity: 1, rate: 0, unit: 'sqft', amount: 0, taxPercent: 0, discount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    const taxTotal = items.reduce((acc, item) => acc + (item.amount * ((item.taxPercent || 0) / 100)), 0);
    const discountTotal = items.reduce((acc, item) => acc + (item.discount || 0), 0);
    return { subTotal, taxTotal, discountTotal, grandTotal: (subTotal - discountTotal) + taxTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter a party name`); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type,
      invoiceNumber,
      date,
      partyName,
      partyAddress,
      items,
      ...totals,
      status,
      isEstimate: isSale ? isEstimate : false
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-50 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between shadow-sm z-10 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">
            {isSale ? 'Sales Entry' : 'Purchase Entry'}
          </h2>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowPreview(!showPreview)} className="hidden lg:flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black border bg-white border-slate-200 text-slate-600 hover:bg-slate-50">
            {showPreview ? <Edit3 size={16}/> : <Eye size={16}/>}
            {showPreview ? 'Hide Preview' : 'Preview PDF'}
          </button>
          <button onClick={handleSave} className="bg-blue-600 text-white px-8 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
            <Save size={18} className="mr-2" /> Save & Close
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-10 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-3xl xl:max-w-4xl' : 'max-w-6xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Party Name</label>
                <input type="text" value={partyName} onChange={(e) => setPartyName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-bold text-slate-800" placeholder="Customer or Supplier Name" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all font-bold" />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Item Table</h3>
                <button onClick={addItem} className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-slate-800 transition-all uppercase tracking-widest">
                  <Plus size={14}/> Add Item
                </button>
              </div>

              <div className="space-y-4">
                {items.map((item) => (
                  <div key={item.id} className="p-4 bg-white rounded-xl border border-slate-200 shadow-sm space-y-4 relative group">
                    <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500">
                      <Trash2 size={16}/>
                    </button>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold" placeholder="Description" />
                      <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 1)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-center" placeholder="Qty" />
                      <input type="number" value={item.rate} onChange={(e) => handleItemChange(item.id, 'rate', parseFloat(e.target.value) || 0)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-right font-black" placeholder="Rate" />
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      <div className="relative">
                        <Percent className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" size={12} />
                        <input type="number" value={item.taxPercent} onChange={(e) => handleItemChange(item.id, 'taxPercent', parseFloat(e.target.value) || 0)} className="w-full pl-8 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs" placeholder="Tax %" />
                      </div>
                      <div className="relative">
                        <DiscountIcon className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" size={12} />
                        <input type="number" value={item.discount} onChange={(e) => handleItemChange(item.id, 'discount', parseFloat(e.target.value) || 0)} className="w-full pl-8 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-lg text-xs" placeholder="Disc. Amt" />
                      </div>
                      <div className="md:col-span-2 text-right">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mr-2">Total</span>
                        <span className="text-sm font-black text-slate-900">₹{item.amount.toFixed(2)}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-200 flex flex-col items-end gap-3">
               <div className="flex justify-between w-full max-w-xs text-sm text-slate-500">
                  <span>Subtotal</span>
                  <span className="font-bold">₹{totals.subTotal.toFixed(2)}</span>
               </div>
               <div className="flex justify-between w-full max-w-xs text-sm text-rose-500">
                  <span>Total Discount</span>
                  <span className="font-bold">- ₹{totals.discountTotal.toFixed(2)}</span>
               </div>
               <div className="flex justify-between w-full max-w-xs text-sm text-blue-600">
                  <span>Total Tax</span>
                  <span className="font-bold">+ ₹{totals.taxTotal.toFixed(2)}</span>
               </div>
