import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { TrendingUp, CheckCircle, IndianRupee, Download } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const totalSales = transactions.reduce((acc, t) => acc + t.grandTotal, 0);
    const collected = transactions.filter(t => t.status === 'PAID').reduce((acc, t) => acc + t.grandTotal, 0);
    const outstanding = transactions.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + t.grandTotal, 0);
    const avgSale = transactions.length > 0 ? totalSales / transactions.length : 0;
    const maxSale = transactions.length > 0 ? Math.max(...transactions.map(t => t.grandTotal)) : 0;

    return { totalSales, collected, outstanding, avgSale, maxSale };
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Financial Reports</h1>
          <p className="text-slate-500 font-medium">Insights into your billing and collections.</p>
        </div>
        <button 
          onClick={() => exportTransactionsToCSV(transactions, "Full_Sales_Report")}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 text-xs uppercase tracking-widest"
        >
          <Download size={18} />
          Export All (CSV)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <ReportCard title="Total Revenue" value={stats.totalSales} color="blue" icon={<TrendingUp size={20} />} />
        <ReportCard title="Cash Collected" value={stats.collected} color="emerald" icon={<CheckCircle size={20} />} />
        <ReportCard title="Outstanding" value={stats.outstanding} color="rose" icon={<IndianRupee size={20} />} />
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50">
           <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">Performance Summary</h3>
        </div>
        <div className="p-6">
            <div className="space-y-4">
                <SummaryRow label="Total Invoices Count" value={transactions.length.toString()} />
                <SummaryRow label="Average Invoice Value" value={`₹${stats.avgSale.toFixed(2)}`} />
                <SummaryRow label="Highest Billing" value={`₹${stats.maxSale.toFixed(2)}`} />
                <SummaryRow label="Collection Efficiency" value={`${transactions.length > 0 ? ((stats.collected / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
            </div>
        </div>
      </div>
    </div>
  );
};

