import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`INV-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Logic: sizeA * sizeB * quantity = sqFt
        // Logic: sqFt * rate = amount
        const a = field === 'sizeA' ? Number(value) : updated.sizeA;
        const b = field === 'sizeB' ? Number(value) : updated.sizeB;
        const q = field === 'quantity' ? Number(value) : updated.quantity;
        const r = field === 'rate' ? Number(value) : updated.rate;

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter Customer Name`); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type: TransactionType.SALE,
      invoiceNumber,
      date,
      partyName,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-50 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between shadow-sm z-10 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">New Sale</h2>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowPreview(!showPreview)} className="hidden lg:flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black border bg-white border-slate-200 text-slate-600">
            {showPreview ? <Edit3 size={16}/> : <Eye size={16}/>}
            {showPreview ? 'Hide Preview' : 'Preview'}
          </button>
          <button onClick={handleSave} className="bg-blue-600 text-white px-8 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
            Save Invoice
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-10 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-3xl xl:max-w-4xl' : 'max-w-6xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer Name</label>
                <input type="text" value={partyName} onChange={(e) => setPartyName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" placeholder="Customer Name" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Billing Table</h3>
                <button onClick={addItem} className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-lg flex items-center gap-2">
                  <Plus size={14}/> Add Row
                </button>
              </div>

              <div className="space-y-3">
                {items.map((item) => (
                  <div key={item.id} className="p-4 bg-slate-50 rounded-xl border border-slate-200 flex flex-col md:flex-row gap-4 relative">
                    <button onClick={() => removeItem(item.id)} className="absolute top-2 right-2 text-slate-300 hover:text-rose-500 md:relative md:top-0 md:right-0 md:mt-8">
                      <Trash2 size={16}/>
                    </button>
                    <div className="flex-1 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase">Item Description</label>
                      <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold" />
                    </div>
                    <div className="w-24 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase">Size A</label>
                      <input type="number" value={item.sizeA} onChange={(e) => handleItemChange(item.id, 'sizeA', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-center" />
                    </div>
                    <div className="w-24 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase">Size B</label>
                      <input type="number" value={item.sizeB} onChange={(e) => handleItemChange(item.id, 'sizeB', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-center" />
                    </div>
                    <div className="w-24 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase">Qty</label>
                      <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-center" />
                    </div>
                    <div className="w-24 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase text-blue-600">SqFt</label>
                      <div className="w-full px-3 py-2 text-sm font-black text-blue-600 text-center">{item.sqFt}</div>
                    </div>
                    <div className="w-28 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase">Rate</label>
                      <input type="number" value={item.rate} onChange={(e) => handleItemChange(item.id, 'rate', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-right font-black" />
                    </div>
                    <div className="w-32 space-y-1">
                      <label className="text-[9px] font-black text-slate-400 uppercase">Amount</label>
                      <div className="w-full px-3 py-2 text-sm font-black text-right">₹{item.amount.toFixed(2)}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-200 flex flex-col items-end">
               <div className="text-4xl font-black text-slate-900">
                 <span className="text-blue-600 font-medium text-2xl mr-2">{profile.currencySymbol}</span>
                 {totals.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="hidden lg:block flex-1 bg-slate-100 overflow-y-auto border-l border-slate-200">
             <div className="p-12 scale-[0.8] origin-top">
                <InvoicePreview transaction={{...initialData, partyName, date, invoiceNumber, items, ...totals} as any} profile={profile} />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const savedProfile = localStorage.getItem('easyin_profile_v2');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      currencySymbol: "₹",
      pdfFooterNote: "Thank you!",
      pdfThemeColor: "#2563eb"
    };

    const doc = new jsPDF();
    const themeRGB: [number, number, number] = hexToRgb(profile.pdfThemeColor);

    // Header
    doc.setFontSize(22).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold').text("ESTIMATE", 14, 20);

    // Details
    doc.setFontSize(9).setTextColor(60, 60, 60).setFont(undefined, 'normal');
    doc.text(`Invoice #: ${transaction.invoiceNumber}`, 140, 20);
    doc.text(`Date: ${transaction.date}`, 140, 25);

    // Customer
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("CUSTOMER", 14, 40);
    doc.setFontSize(12).setTextColor(0).setFont(undefined, 'bold').text(transaction.partyName, 14, 46);

    // Columns: Desc, SizeA, SizeB, Qty, SqFt, Rate, Amount
    const tableHeaders = ["Description", "Size A", "Size B", "Qty", "SqFt", "Rate", "Amount"];
    const tableRows = transaction.items.map(item => [
      item.description,
      item.sizeA,
      item.sizeB,
      item.quantity,
      item.sqFt,
      item.rate.toFixed(2),
      item.amount.toFixed(2)
    ]);

    autoTable(doc, {
      head: [tableHeaders],
      body: tableRows,
      startY: 60,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255 },
      styles: { fontSize: 8 },
      columnStyles: {
        6: { halign: 'right', fontStyle: 'bold' }
      }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(130, finalY - 5, 66, 12, 1, 1, 'F');
    doc.setFontSize(10).setTextColor(255).setFont(undefined, 'bold');
    doc.text(`TOTAL: ₹ ${transaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, 192, finalY + 2.5, { align: "right" });

    doc.save(`Estimate_${transaction.invoiceNumber}.pdf`);
  } catch (error) {
    console.error(error);
  }
};

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? [
    parseInt(result[1], 16),
    parseInt(result[2], 16),
    parseInt(result[3], 16)
  ] : [37, 99, 235];
}

