import { Plus, Trash2, Save, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`INV-${Math.floor(1000 + Math.random() * 9000)}`);
    }
  }, [initialData]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Logic: sizeA * sizeB * quantity = sqFt
        // Logic: sqFt * rate = amount
        const a = field === 'sizeA' ? Number(value) : updated.sizeA;
        const b = field === 'sizeB' ? Number(value) : updated.sizeB;
        const q = field === 'quantity' ? Number(value) : updated.quantity;
        const r = field === 'rate' ? Number(value) : updated.rate;

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + item.amount, 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter Customer Name`); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type: TransactionType.SALE,
      invoiceNumber,
      date,
      partyName,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-50 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between shadow-sm z-10 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">Sales Entry</h2>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowPreview(!showPreview)} className="hidden lg:flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black border bg-white border-slate-200 text-slate-600">
            {showPreview ? <Edit3 size={16}/> : <Eye size={16}/>}
            {showPreview ? 'Hide Preview' : 'Preview'}
          </button>
          <button onClick={handleSave} className="bg-blue-600 text-white px-8 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
            Save Invoice
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-10 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-4xl xl:max-w-5xl' : 'max-w-6xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer Name</label>
                <input type="text" value={partyName} onChange={(e) => setPartyName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" placeholder="Customer Name" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Billing Date</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Billing Table</h3>
                <button onClick={addItem} className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-lg flex items-center gap-2">
                  <Plus size={14}/> Add Row
                </button>
              </div>

              <div className="space-y-4">
                {items.map((item) => (
                  <div key={item.id} className="p-5 bg-slate-50 rounded-2xl border border-slate-200 space-y-4 relative group">
                    <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500 transition-colors">
                      <Trash2 size={18}/>
                    </button>

                    {/* Primary Info: Desc, Material, Details */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Item Description</label>
                        <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold" placeholder="Banner, Sticker, etc." />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Material</label>
                        <select value={item.material} onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500">
                          <option value="">Select Material</option>
                          {profile.materials.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Optional Details / Notes</label>
                        <input type="text" value={item.details} onChange={(e) => handleItemChange(item.id, 'details', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm" placeholder="Additional info..." />
                      </div>
                    </div>

                    {/* Dimensional Logic: Size A, Size B, Qty, SqFt, Rate, Amount */}
                    <div className="grid grid-cols-2 md:grid-cols-6 gap-4 items-end bg-white/50 p-3 rounded-xl border border-slate-100">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Size A</label>
                        <input type="number" value={item.sizeA} onChange={(e) => handleItemChange(item.id, 'sizeA', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Size B</label>
                        <input type="number" value={item.sizeB} onChange={(e) => handleItemChange(item.id, 'sizeB', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Qty</label>
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-blue-600 uppercase">Total SqFt</label>
                        <div className="w-full px-3 py-2 text-sm font-black text-blue-600 text-center bg-blue-50 border border-blue-100 rounded-lg">{item.sqFt}</div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Rate</label>
                        <input type="number" value={item.rate} onChange={(e) => handleItemChange(item.id, 'rate', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm text-right font-black" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-900 uppercase">Amount</label>
                        <div className="w-full px-3 py-2 text-sm font-black text-right text-slate-900">₹{item.amount.toFixed(2)}</div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-200 flex flex-col items-end">
               <div className="text-4xl font-black text-slate-900">
                 <span className="text-blue-600 font-medium text-2xl mr-2">{profile.currencySymbol}</span>
                 {totals.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="hidden lg:block flex-1 bg-slate-100 overflow-y-auto border-l border-slate-200">
             <div className="p-12 scale-[0.7] origin-top">
                <InvoicePreview transaction={{...initialData, partyName, date, invoiceNumber, items, ...totals} as any} profile={profile} />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const savedProfile = localStorage.getItem('easyin_profile_v2');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      currencySymbol: "₹",
      pdfFooterNote: "Thank you!",
      pdfThemeColor: "#2563eb",
      defaultStatus: 'UNPAID',
      materials: ["Regular Flex", "Vinyl", "Star Flex", "Vinyl + Lam", "One Way"],
      showSqFtInPdf: true,
      showMaterialInPdf: true,
      pdfAccentColor: '#1e40af',
      minSqFtPerPiece: 0,
      minItemAmount: 0
    };

    const doc = new jsPDF();
    const themeRGB: [number, number, number] = hexToRgb(profile.pdfThemeColor);

    // Header
    doc.setFontSize(22).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold').text("ESTIMATE", 14, 20);

    // Details
    doc.setFontSize(9).setTextColor(60, 60, 60).setFont(undefined, 'normal');
    doc.text(`Invoice #: ${transaction.invoiceNumber}`, 140, 20);
    doc.text(`Date: ${transaction.date}`, 140, 25);

    // Customer
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("CUSTOMER", 14, 40);
    doc.setFontSize(12).setTextColor(0).setFont(undefined, 'bold').text(transaction.partyName, 14, 46);

    // Columns: Desc, SizeA, SizeB, Qty, SqFt, Rate, Amount
    const tableHeaders = ["Description", "Size A", "Size B", "Qty", "SqFt", "Rate", "Amount"];
    const tableRows = transaction.items.map(item => {
      // Create a combined description block for the PDF
      let combinedDesc = item.description || "";
      if (item.material) combinedDesc += `\nMaterial: ${item.material}`;
      if (item.details) combinedDesc += `\nNote: ${item.details}`;

      return [
        combinedDesc,
        item.sizeA,
        item.sizeB,
        item.quantity,
        item.sqFt,
        item.rate.toFixed(2),
        item.amount.toFixed(2)
      ];
    });

    autoTable(doc, {
      head: [tableHeaders],
      body: tableRows,
      startY: 60,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255 },
      styles: { fontSize: 8, cellPadding: 3 },
      columnStyles: {
        0: { cellWidth: 'auto' },
        6: { halign: 'right', fontStyle: 'bold' }
      }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(130, finalY - 5, 66, 12, 1, 1, 'F');
    doc.setFontSize(10).setTextColor(255).setFont(undefined, 'bold');
    doc.text(`TOTAL: ₹ ${transaction.grandTotal.toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, 192, finalY + 2.5, { align: "right" });

    doc.save(`Estimate_${transaction.invoiceNumber}.pdf`);
  } catch (error) {
    console.error(error);
  }
};

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? [
    parseInt(result[1], 16),
    parseInt(result[2], 16),
    parseInt(result[3], 16)
  ] : [37, 99, 235];
}

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Settings } from './components/Settings';
import { UnitConverter } from './components/UnitConverter';
import { AiAdvisor } from './components/AiAdvisor';
import { Transaction, BusinessProfile } from './types';

const DEFAULT_MATERIALS = [
  "Regular Flex",
  "B.B. Reg. Flex",
  "Star Flex",
  "Vinyl",
  "Vinyl + Lam",
  "Vinyl + Foamsheet",
  "One Way",
  "Retro Vinyl",
  "Transperant Vinyl",
  "Backlit",
  "Vinyl + Lam + Foamsheet",
  "Foamsheet"
];

const DEFAULT_PROFILE: BusinessProfile = {
  currencySymbol: '₹',
  defaultStatus: 'UNPAID',
  materials: DEFAULT_MATERIALS,
  pdfFooterNote: 'Thank you for your business!',
  showSqFtInPdf: true,
  showMaterialInPdf: true,
  pdfThemeColor: '#2563eb',
  pdfAccentColor: '#1e40af',
  minSqFtPerPiece: 0,
  minItemAmount: 0
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  useEffect(() => {
    const savedTxns = localStorage.getItem('easyin_transactions_v2');
    if (savedTxns) setTransactions(JSON.parse(savedTxns));

    const savedProfile = localStorage.getItem('easyin_profile_v2');
    if (savedProfile) {
      const parsed = JSON.parse(savedProfile);
      // Ensure we merge defaults so missing keys don't break the app
      setBusinessProfile({ ...DEFAULT_PROFILE, ...parsed });
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('easyin_transactions_v2', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('easyin_profile_v2', JSON.stringify(businessProfile));
  }, [businessProfile]);

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
    setEditingTransaction(null);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard transactions={transactions} onAddInvoice={() => setActiveTab('sales')} onNavigate={setActiveTab} />;
      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
          />
        );
      case 'reports': return <Reports transactions={transactions} />;
      case 'ai': return <AiAdvisor transactions={transactions} />;
      case 'converter': return <UnitConverter />;
      case 'data': return <DataManagement transactions={transactions} onImport={setTransactions} />;
      case 'settings': return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      default: return <div className="p-8">Section Coming Soon</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`INV-${Math.floor(1000 + Math.random() * 9000)}`);
      setStatus(profile.defaultStatus || 'UNPAID');
    }
