import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Settings } from './components/Settings';
import { UnitConverter } from './components/UnitConverter';
import { Transaction, BusinessProfile } from './types';

const DEFAULT_MATERIALS = [
  "Regular Flex",
  "B.B. Reg. Flex",
  "Star Flex",
  "Vinyl",
  "Vinyl + Lam",
  "Vinyl + Foamsheet",
  "One Way",
  "Retro Vinyl",
  "Transperant Vinyl",
  "Backlit",
  "Vinyl + Lam + Foamsheet",
  "Foamsheet"
];

const DEFAULT_PROFILE: BusinessProfile = {
  currencySymbol: '₹',
  defaultStatus: 'UNPAID',
  materials: DEFAULT_MATERIALS,
  pdfFooterNote: 'Thank you for your business!',
  showSqFtInPdf: true,
  showMaterialInPdf: true,
  pdfThemeColor: '#2563eb',
  pdfAccentColor: '#1e40af',
  minSqFtPerPiece: 0,
  minItemAmount: 0
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Initialize data from LocalStorage
  useEffect(() => {
    const savedTxns = localStorage.getItem('easyin_transactions_v2');
    if (savedTxns) setTransactions(JSON.parse(savedTxns));

    const savedProfile = localStorage.getItem('easyin_profile_v2');
    if (savedProfile) {
      const parsed = JSON.parse(savedProfile);
      setBusinessProfile({ ...DEFAULT_PROFILE, ...parsed });
    }
  }, []);

  // Persistent Save: Sync state to LocalStorage on every change
  useEffect(() => {
    localStorage.setItem('easyin_transactions_v2', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('easyin_profile_v2', JSON.stringify(businessProfile));
  }, [businessProfile]);

  // Automatic Backup Logic
  const triggerAutoBackupFile = useCallback(() => {
    if (transactions.length === 0) return;

    // Create backup payload
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `auto_backup_${new Date().toISOString().split('T')[0]}_${new Date().getHours()}${new Date().getMinutes()}.json`;

    // Note: Browsers usually block downloads on 'beforeunload' unless user-triggered.
    // However, in Electron environments (like the one provided in main.js), 
    // or if the user interacts with the page, this often works.
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    // Log backup in local storage for history
    localStorage.setItem('easyin_last_autobackup', new Date().toISOString());
  }, [transactions]);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      // We attempt a backup file download on close.
      // Most modern browsers will ignore this unless the app is running in a desktop wrapper (Electron)
      // or the user has granted permission for multiple downloads.
      triggerAutoBackupFile();

      // Traditional 'save current state' check
      localStorage.setItem('easyin_transactions_v2', JSON.stringify(transactions));
    };

    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        // Soft backup when user switches tabs or minimizes
        localStorage.setItem('easyin_safety_snap', JSON.stringify(transactions));
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      window.removeEventListener('beforeunload', handleBeforeUnload);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [transactions, triggerAutoBackupFile]);

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
    setEditingTransaction(null);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard transactions={transactions} onAddInvoice={() => setActiveTab('sales')} onNavigate={setActiveTab} />;
      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
          />
        );
      case 'reports': return <Reports transactions={transactions} />;
      case 'converter': return <UnitConverter />;
      case 'data': return <DataManagement transactions={transactions} onImport={setTransactions} />;
      case 'settings': return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      default: return <div className="p-8">Section Coming Soon</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { Download, Upload, ShieldCheck, History } from 'lucide-react';
import { Transaction } from '../types';

interface DataManagementProps {
  transactions: Transaction[];
  onImport: (data: Transaction[]) => void;
}

export const DataManagement: React.FC<DataManagementProps> = ({ transactions, onImport }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [lastAutoBackup, setLastAutoBackup] = useState<string | null>(null);

  useEffect(() => {
    const last = localStorage.getItem('easyin_last_autobackup');
    if (last) setLastAutoBackup(new Date(last).toLocaleString());
  }, []);

  const handleBackup = () => {
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `easyin_manual_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
            if (window.confirm('WARNING: This will replace ALL current data with the backup file. Are you sure?')) {
                onImport(json);
                alert('Data restored successfully!');
            }
        } else {
            alert('Invalid backup file format.');
        }
      } catch (err) {
        alert('Failed to parse backup file.');
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6">
       <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">Data Safety & Backups</h1>
            <p className="text-slate-500 font-medium">Your data stays on this device. We take automatic backups on exit.</p>
          </div>
          {lastAutoBackup && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-100 rounded-lg text-[10px] font-black uppercase tracking-widest">
               <ShieldCheck size={14} />
               Last Auto-Backup: {lastAutoBackup}
            </div>
          )}
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl">
                <Download size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-xl font-black text-slate-900">Manual Export</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Download your complete database as a JSON file. Use this for moving data between devices.</p>
             </div>
             <button onClick={handleBackup} className="px-8 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-black w-full shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
                Export Data Now
             </button>
          </div>

          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
                <Upload size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-xl font-black text-slate-900">Import / Restore</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Restore data from a backup file. This will overwrite your current transaction list.</p>
             </div>
             <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleRestore}
                className="hidden"
             />
             <button onClick={() => fileInputRef.current?.click()} className="px-8 py-3 bg-white border-2 border-slate-100 text-slate-700 rounded-xl hover:bg-slate-50 font-black w-full uppercase tracking-widest text-xs">
                Choose Backup File
             </button>
          </div>
       </div>

       <div className="bg-slate-900 rounded-2xl p-8 text-white relative overflow-hidden">
          <div className="relative z-10 flex flex-col md:flex-row gap-8 items-center">
             <div className="bg-white/10 p-4 rounded-2xl">
                <History size={48} className="text-blue-400" />
             </div>
             <div className="space-y-2 text-center md:text-left">
                <h4 className="text-lg font-black uppercase tracking-tight">How Auto-Backup Works</h4>
                <p className="text-slate-400 text-sm leading-relaxed">
                   When you close the tab or switch to another window, EasyIn automatically saves a snapshot to your browser's persistent storage. 
                   If you are using the desktop version, it will also attempt to save a physical file to your computer.
                </p>
             </div>
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-10">
             <ShieldCheck size={120} />
          </div>
       </div>
    </div>
  );
};

