                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold"
                    placeholder="••••••••"
                  />
                </div>
              </div>
            </div>

            <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
