  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Check for active session
  useEffect(() => {
    const savedSession = localStorage.getItem('easyin_current_session');
    if (savedSession) {
      setCurrentUser(JSON.parse(savedSession));
    }
  }, []);

  // Initialize data from LocalStorage based on User ID
  useEffect(() => {
    if (!currentUser) return;

    const userKey = `easyin_transactions_${currentUser.id}`;
    const profileKey = `easyin_profile_${currentUser.id}`;

    const savedTxns = localStorage.getItem(userKey);
    if (savedTxns) setTransactions(JSON.parse(savedTxns));
    else setTransactions([]);

    const savedProfile = localStorage.getItem(profileKey);
    if (savedProfile) {
      const parsed = JSON.parse(savedProfile);
      setBusinessProfile({ ...DEFAULT_PROFILE, ...parsed });
    } else {
      setBusinessProfile(DEFAULT_PROFILE);
    }
  }, [currentUser]);

  // Persistent Save: Sync state to LocalStorage on every change (User-specific)
  useEffect(() => {
    if (!currentUser) return;
    const userKey = `easyin_transactions_${currentUser.id}`;
    localStorage.setItem(userKey, JSON.stringify(transactions));
  }, [transactions, currentUser]);

  useEffect(() => {
    if (!currentUser) return;
    const profileKey = `easyin_profile_${currentUser.id}`;
    localStorage.setItem(profileKey, JSON.stringify(businessProfile));
  }, [businessProfile, currentUser]);

  // Automatic Backup Logic
  const triggerAutoBackupFile = useCallback(() => {
    if (!currentUser || transactions.length === 0) return;

    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `auto_backup_${currentUser.username}_${new Date().toISOString().split('T')[0]}.json`;

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    localStorage.setItem(`easyin_last_autobackup_${currentUser.id}`, new Date().toISOString());
  }, [transactions, currentUser]);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      triggerAutoBackupFile();
    };

    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden' && currentUser) {
        localStorage.setItem(`easyin_safety_snap_${currentUser.id}`, JSON.stringify(transactions));
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      window.removeEventListener('beforeunload', handleBeforeUnload);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [transactions, triggerAutoBackupFile, currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('easyin_current_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('easyin_current_session');
    setActiveTab('dashboard');
  };

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
    setEditingTransaction(null);
  };

  if (!currentUser) {
    return <Auth onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard transactions={transactions} onAddInvoice={() => setActiveTab('sales')} onNavigate={setActiveTab} />;
      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
          />
        );
      case 'reports': return <Reports transactions={transactions} />;
      case 'converter': return <UnitConverter />;
      case 'data': return <DataManagement transactions={transactions} onImport={setTransactions} currentUser={currentUser} />;
      case 'settings': return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      default: return <div className="p-8">Section Coming Soon</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={setActiveTab} onLogout={handleLogout} currentUser={currentUser}>
      {renderContent()}
    </Layout>
  );
};

