import React, { useRef, useState, useEffect } from 'react';
import { Download, Upload, ShieldCheck, History } from 'lucide-react';
import { Transaction, User } from '../types';

interface DataManagementProps {
  transactions: Transaction[];
  onImport: (data: Transaction[]) => void;
  currentUser: User;
}

export const DataManagement: React.FC<DataManagementProps> = ({ transactions, onImport, currentUser }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [lastAutoBackup, setLastAutoBackup] = useState<string | null>(null);

  useEffect(() => {
    const last = localStorage.getItem(`easyin_last_autobackup_${currentUser.id}`);
    if (last) setLastAutoBackup(new Date(last).toLocaleString());
  }, [currentUser]);

  const handleBackup = () => {
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `easyin_backup_${currentUser.username}_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
            if (window.confirm('WARNING: This will replace ALL current data for this user. Are you sure?')) {
                onImport(json);
                alert('Data restored successfully!');
            }
        } else {
            alert('Invalid backup file format.');
        }
      } catch (err) {
        alert('Failed to parse backup file.');
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6">
       <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">Data Safety & Backups</h1>
            <p className="text-slate-500 font-medium">Hello {currentUser.username}! Your data is isolated and safe on this device.</p>
          </div>
          {lastAutoBackup && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-100 rounded-lg text-[10px] font-black uppercase tracking-widest">
               <ShieldCheck size={14} />
               Last Auto-Backup: {lastAutoBackup}
            </div>
          )}
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl">
                <Download size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-xl font-black text-slate-900">Manual Export</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Download your complete database as a JSON file. Use this for moving data between devices.</p>
             </div>
             <button onClick={handleBackup} className="px-8 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-black w-full shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
                Export Data Now
             </button>
          </div>

          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
                <Upload size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-xl font-black text-slate-900">Import / Restore</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Restore data from a backup file. This will overwrite your current transaction list.</p>
             </div>
             <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleRestore}
                className="hidden"
             />
             <button onClick={() => fileInputRef.current?.click()} className="px-8 py-3 bg-white border-2 border-slate-100 text-slate-700 rounded-xl hover:bg-slate-50 font-black w-full uppercase tracking-widest text-xs">
                Choose Backup File
             </button>
          </div>
       </div>

       <div className="bg-slate-900 rounded-2xl p-8 text-white relative overflow-hidden">
          <div className="relative z-10 flex flex-col md:flex-row gap-8 items-center">
             <div className="bg-white/10 p-4 rounded-2xl">
                <History size={48} className="text-blue-400" />
             </div>
             <div className="space-y-2 text-center md:text-left">
                <h4 className="text-lg font-black uppercase tracking-tight">How User Data Works</h4>
                <p className="text-slate-400 text-sm leading-relaxed">
                   Your login credentials and invoices are stored locally using browser sandboxing. 
                   Switching browsers or clearing "Site Data" will remove these local accounts. 
                   Always keep a manual backup for long-term safety.
                </p>
             </div>
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-10">
             <ShieldCheck size={120} />
          </div>
       </div>
    </div>
  );
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction) => {
  try {
    const savedProfile = localStorage.getItem('easyin_profile_v2');
    const profile: BusinessProfile = savedProfile ? JSON.parse(savedProfile) : {
      currencySymbol: "₹",
      pdfFooterNote: "Thank you!",
      pdfThemeColor: "#2563eb",
      defaultStatus: 'UNPAID',
      materials: ["Regular Flex", "Vinyl", "Star Flex", "Vinyl + Lam", "One Way"],
      showSqFtInPdf: true,
      showMaterialInPdf: true,
      pdfAccentColor: '#1e40af',
      minSqFtPerPiece: 0,
      minItemAmount: 0
    };

    const doc = new jsPDF();
    const themeRGB: [number, number, number] = hexToRgb(profile.pdfThemeColor);

    // Header
    doc.setFontSize(22).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold').text("ESTIMATE", 14, 20);

    // Details
    doc.setFontSize(9).setTextColor(60, 60, 60).setFont(undefined, 'normal');
    doc.text(`Invoice #: ${transaction.invoiceNumber}`, 140, 20);
    doc.text(`Date: ${transaction.date}`, 140, 25);

    // Customer
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("CUSTOMER", 14, 40);
    doc.setFontSize(12).setTextColor(0).setFont(undefined, 'bold').text(transaction.partyName, 14, 46);

    // Columns: Desc, SizeA, SizeB, Qty, SqFt, Rate, Amount
    const tableHeaders = ["Description", "Size A", "Size B", "Qty", "SqFt", "Rate", "Amount"];
    const tableRows = transaction.items.map(item => {
      // Create a combined description block for the PDF
      let combinedDesc = item.description || "";
      if (item.material) combinedDesc += `\nMaterial: ${item.material}`;
      if (item.details) combinedDesc += `\nNote: ${item.details}`;

      return [
        combinedDesc,
        item.sizeA,
        item.sizeB,
        item.quantity,
        item.sqFt,
        Number(item.rate || 0).toFixed(2),
        Number(item.amount || 0).toFixed(2)
      ];
    });

    autoTable(doc, {
      head: [tableHeaders],
      body: tableRows,
      startY: 60,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255 },
      styles: { fontSize: 8, cellPadding: 3 },
      columnStyles: {
        0: { cellWidth: 'auto' },
        6: { halign: 'right', fontStyle: 'bold' }
      }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(130, finalY - 5, 66, 12, 1, 1, 'F');
    doc.setFontSize(10).setTextColor(255).setFont(undefined, 'bold');
    doc.text(`TOTAL: ₹ ${Number(transaction.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, 192, finalY + 2.5, { align: "right" });

    doc.save(`Estimate_${transaction.invoiceNumber}.pdf`);
  } catch (error) {
    console.error(error);
  }
};

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? [
    parseInt(result[1], 16),
    parseInt(result[2], 16),
    parseInt(result[3], 16)
  ] : [37, 99, 235];
}

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`INV-${Math.floor(1000 + Math.random() * 9000)}`);
      setStatus(profile.defaultStatus || 'UNPAID');
    }
  }, [initialData, profile.defaultStatus]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Pure Dimensional Logic: sizeA * sizeB * quantity = sqFt
        // Total Amount: sqFt * rate = amount
        const a = field === 'sizeA' ? Number(value) : Number(updated.sizeA);
        const b = field === 'sizeB' ? Number(value) : Number(updated.sizeB);
        const q = field === 'quantity' ? Number(value) : Number(updated.quantity);
        const r = field === 'rate' ? Number(value) : Number(updated.rate);

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + (Number(item.amount) || 0), 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter Customer Name`); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type: TransactionType.SALE,
      invoiceNumber,
      date,
      partyName,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-50 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between shadow-sm z-10 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-lg font-black text-slate-800 tracking-tight">SALE ENTRY</h2>
        </div>
        <div className="flex items-center gap-3">
