import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Settings } from './components/Settings';
import { UnitConverter } from './components/UnitConverter';
import { Transaction, BusinessProfile } from './types';

const DEFAULT_MATERIALS = [
  "Regular Flex",
  "B.B. Reg. Flex",
  "Star Flex",
  "Vinyl",
  "Vinyl + Lam",
  "Vinyl + Foamsheet",
  "One Way",
  "Retro Vinyl",
  "Transperant Vinyl",
  "Backlit",
  "Vinyl + Lam + Foamsheet",
  "Foamsheet"
];

const DEFAULT_PROFILE: BusinessProfile = {
  currencySymbol: '₹',
  defaultStatus: 'UNPAID',
  materials: DEFAULT_MATERIALS,
  pdfFooterNote: 'Thank you for your business!',
  showSqFtInPdf: true,
  showMaterialInPdf: true,
  pdfThemeColor: '#2563eb',
  pdfAccentColor: '#1e40af',
  minSqFtPerPiece: 0,
  minItemAmount: 0
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Initialize data from LocalStorage
  useEffect(() => {
    const savedTxns = localStorage.getItem('easyin_transactions_v2');
    if (savedTxns) setTransactions(JSON.parse(savedTxns));

    const savedProfile = localStorage.getItem('easyin_profile_v2');
    if (savedProfile) {
      const parsed = JSON.parse(savedProfile);
      setBusinessProfile({ ...DEFAULT_PROFILE, ...parsed });
    }
  }, []);

  // Persistent Save
  useEffect(() => {
    localStorage.setItem('easyin_transactions_v2', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('easyin_profile_v2', JSON.stringify(businessProfile));
  }, [businessProfile]);

  // Automatic Backup Logic
  const triggerAutoBackupFile = useCallback(() => {
    if (transactions.length === 0) return;

    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `auto_backup_${new Date().toISOString().split('T')[0]}.json`;

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    localStorage.setItem('easyin_last_autobackup', new Date().toISOString());
  }, [transactions]);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      triggerAutoBackupFile();
    };

    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        localStorage.setItem('easyin_safety_snap', JSON.stringify(transactions));
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      window.removeEventListener('beforeunload', handleBeforeUnload);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [transactions, triggerAutoBackupFile]);

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
    setEditingTransaction(null);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard transactions={transactions} onAddInvoice={() => setActiveTab('sales')} onNavigate={setActiveTab} />;
      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
          />
        );
      case 'reports': return <Reports transactions={transactions} />;
      case 'converter': return <UnitConverter />;
      case 'data': return <DataManagement transactions={transactions} onImport={setTransactions} />;
      case 'settings': return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      default: return <div className="p-8">Section Coming Soon</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  ShoppingCart, 
  FileText, 
  Menu, 
  X,
  Database,
  Ruler,
  Settings as SettingsIcon,
  ChevronRight,
  Wifi,
  WifiOff,
  HardDrive
} from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onNavigate: (tab: string) => void;
}

export const Layout: React.FC<LayoutProps> = ({ children, activeTab, onNavigate }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: <LayoutDashboard size={18} /> },
    { id: 'sales', label: 'Sales & Billing', icon: <ShoppingCart size={18} /> },
    { id: 'reports', label: 'Reports', icon: <FileText size={18} /> },
    { id: 'converter', label: 'Unit Converter', icon: <Ruler size={18} /> },
    { id: 'data', label: 'Data Management', icon: <Database size={18} /> },
    { id: 'settings', label: 'Settings', icon: <SettingsIcon size={18} /> },
  ];

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      <aside className={`fixed lg:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 transform transition-transform duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}`}>
        <div className="flex items-center justify-between h-16 px-6 border-b border-slate-100">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-black italic">E</div>
            <span className="text-xl font-black tracking-tighter text-slate-800">EasyIn</span>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        <nav className="p-3 space-y-1 overflow-y-auto h-[calc(100vh-120px)] mt-2">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => { onNavigate(item.id); setIsSidebarOpen(false); }}
              className={`w-full flex items-center justify-between px-4 py-2.5 rounded-xl text-sm font-semibold transition-all group ${activeTab === item.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-900'}`}
            >
              <div className="flex items-center gap-3">
                <span>{item.icon}</span>
                <div className="flex flex-col items-start leading-none">
                  <span>{item.label}</span>
                </div>
              </div>
              {activeTab === item.id && <ChevronRight size={14} className="opacity-50" />}
            </button>
          ))}
        </nav>

        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-100 bg-slate-50/50">
           <div className="flex items-center gap-3 text-slate-400">
              <HardDrive size={16} />
              <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-widest leading-none">Local Storage</span>
                <span className="text-[8px] font-medium leading-none mt-1">Data saved to this browser</span>
              </div>
           </div>
        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 lg:px-8 shrink-0">
          <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg">
            <Menu size={20} />
          </button>

          <div className="flex items-center gap-6 ml-auto">
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border ${isOnline ? 'bg-emerald-50 border-emerald-100 text-emerald-700' : 'bg-rose-50 border-rose-100 text-rose-700'} transition-all duration-500`}>
              {isOnline ? <Wifi size={14} /> : <WifiOff size={14} />}
              <span className="text-[10px] font-black uppercase tracking-widest">
                {isOnline ? 'Connected' : 'Offline Mode'}
              </span>
            </div>

            <div className="hidden sm:flex flex-col items-end">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Smart Invoicing</p>
              <p className="text-xs font-bold text-slate-800 mt-1 italic">Offline Ready</p>
            </div>
            <div className="h-10 w-px bg-slate-100"></div>
            <button onClick={() => onNavigate('settings')} className="h-10 w-10 rounded-xl bg-slate-50 text-slate-500 flex items-center justify-center border border-slate-200 hover:bg-white hover:text-blue-600 hover:border-blue-200 transition-all shadow-sm">
              <SettingsIcon size={18} />
            </button>
          </div>
        </header>

        <main className="flex-1 overflow-auto bg-slate-50/50 p-4 lg:p-8">
          <div className="max-w-[1600px] mx-auto animate-in fade-in slide-in-from-bottom-2 duration-500">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { Download, Upload, ShieldCheck, History } from 'lucide-react';
import { Transaction } from '../types';

interface DataManagementProps {
  transactions: Transaction[];
  onImport: (data: Transaction[]) => void;
}

export const DataManagement: React.FC<DataManagementProps> = ({ transactions, onImport }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [lastAutoBackup, setLastAutoBackup] = useState<string | null>(null);

  useEffect(() => {
    const last = localStorage.getItem('easyin_last_autobackup');
    if (last) setLastAutoBackup(new Date(last).toLocaleString());
  }, []);

  const handleBackup = () => {
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `easyin_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
            if (window.confirm('WARNING: This will replace ALL current data. Are you sure?')) {
                onImport(json);
                alert('Data restored successfully!');
            }
        } else {
            alert('Invalid backup file format.');
        }
      } catch (err) {
        alert('Failed to parse backup file.');
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6">
       <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">Data Safety & Backups</h1>
            <p className="text-slate-500 font-medium">Your data is isolated and safe on this device.</p>
          </div>
          {lastAutoBackup && (
            <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-100 rounded-lg text-[10px] font-black uppercase tracking-widest">
               <ShieldCheck size={14} />
               Last Auto-Backup: {lastAutoBackup}
            </div>
          )}
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl">
                <Download size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-xl font-black text-slate-900">Manual Export</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Download your complete database as a JSON file. Use this for moving data between devices.</p>
             </div>
             <button onClick={handleBackup} className="px-8 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-black w-full shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
                Export Data Now
             </button>
          </div>

          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
                <Upload size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-xl font-black text-slate-900">Import / Restore</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Restore data from a backup file. This will overwrite your current transaction list.</p>
             </div>
             <input 
                type="file" 
                accept=".json" 
                ref={fileInputRef}
                onChange={handleRestore}
                className="hidden"
             />
             <button onClick={() => fileInputRef.current?.click()} className="px-8 py-3 bg-white border-2 border-slate-100 text-slate-700 rounded-xl hover:bg-slate-50 font-black w-full uppercase tracking-widest text-xs">
                Choose Backup File
             </button>
          </div>
       </div>

       <div className="bg-slate-900 rounded-2xl p-8 text-white relative overflow-hidden">
          <div className="relative z-10 flex flex-col md:flex-row gap-8 items-center">
             <div className="bg-white/10 p-4 rounded-2xl">
                <History size={48} className="text-blue-400" />
             </div>
             <div className="space-y-2 text-center md:text-left">
                <h4 className="text-lg font-black uppercase tracking-tight">How Data Works</h4>
                <p className="text-slate-400 text-sm leading-relaxed">
                   Your invoices are stored locally using browser sandboxing. 
                   Clearing "Site Data" or "Cache" in your browser settings will remove your records. 
                   Always keep a manual backup for long-term safety.
                </p>
             </div>
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-10">
             <ShieldCheck size={120} />
          </div>
       </div>
    </div>
  );
};

