import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction, profile: BusinessProfile) => {
  try {
    const doc = new jsPDF();
    const themeRGB: [number, number, number] = hexToRgb(profile.pdfThemeColor || "#2563eb");

    // Header
    doc.setFontSize(22).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold').text("ESTIMATE", 14, 20);

    // Details
    doc.setFontSize(9).setTextColor(60, 60, 60).setFont(undefined, 'normal');
    doc.text(`Invoice #: ${transaction.invoiceNumber}`, 140, 20);
    doc.text(`Date: ${transaction.date}`, 140, 25);

    // Customer
    doc.setFontSize(8).setTextColor(150).setFont(undefined, 'bold').text("CUSTOMER", 14, 40);
    doc.setFontSize(12).setTextColor(0).setFont(undefined, 'bold').text(transaction.partyName, 14, 46);

    // Dynamic Columns based on Profile Settings
    const headers = ["Description"];
    if (profile.showMaterialInPdf) headers.push("Material");
    headers.push("Details");
    headers.push("Size A", "Size B", "Qty");
    if (profile.showSqFtInPdf) headers.push("SqFt");
    headers.push("Rate", "Amount");

    const tableRows = transaction.items.map(item => {
      const row: (string | number)[] = [item.description || "-"];
      if (profile.showMaterialInPdf) row.push(item.material || "-");
      row.push(item.details || "-");
      row.push(item.sizeA, item.sizeB, item.quantity);
      if (profile.showSqFtInPdf) row.push(item.sqFt);
      row.push(Number(item.rate || 0).toFixed(2), Number(item.amount || 0).toFixed(2));
      return row;
    });

    autoTable(doc, {
      head: [headers],
      body: tableRows,
      startY: 60,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255, fontSize: 7 },
      styles: { fontSize: 7, cellPadding: 2, overflow: 'linebreak' },
      columnStyles: {
        0: { cellWidth: 35 }, // Description
        1: { cellWidth: 25 }, // Material (if shown)
        2: { cellWidth: 25 }, // Details
        [headers.length - 1]: { halign: 'right', fontStyle: 'bold' }, // Amount
        [headers.length - 2]: { halign: 'right' } // Rate
      }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(130, finalY - 5, 66, 12, 1, 1, 'F');
    doc.setFontSize(10).setTextColor(255).setFont(undefined, 'bold');
    doc.text(`TOTAL: ₹ ${Number(transaction.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}`, 192, finalY + 2.5, { align: "right" });

    // Footer Note
    if (profile.pdfFooterNote) {
      doc.setFontSize(8).setTextColor(120).setFont(undefined, 'italic');
      doc.text(profile.pdfFooterNote, 14, doc.internal.pageSize.getHeight() - 20);
    }

    doc.save(`Estimate_${transaction.invoiceNumber}.pdf`);
  } catch (error) {
    console.error("PDF Generation Error:", error);
  }
};

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? [
    parseInt(result[1], 16),
    parseInt(result[2], 16),
    parseInt(result[3], 16)
  ] : [37, 99, 235];
}

