import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, ArrowLeft, Eye, Edit3 } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`EST-${Math.floor(1000 + Math.random() * 9000)}`);
      setStatus(profile.defaultStatus || 'UNPAID');
    }
  }, [initialData, profile.defaultStatus]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };

        // Pure Dimensional Logic: sizeA * sizeB * quantity = sqFt
        // Total Amount: sqFt * rate = amount
        const a = field === 'sizeA' ? Number(value) : Number(updated.sizeA);
        const b = field === 'sizeB' ? Number(value) : Number(updated.sizeB);
        const q = field === 'quantity' ? Number(value) : Number(updated.quantity);
        const r = field === 'rate' ? Number(value) : Number(updated.rate);

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));

        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + (Number(item.amount) || 0), 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter Customer Name`); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type: TransactionType.SALE,
      invoiceNumber,
      date,
      partyName,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-50 flex flex-col overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between shadow-sm z-10 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <ArrowLeft size={20} />
          </button>
          <h2 className="text-lg font-black text-slate-800 tracking-tight uppercase">Estimate Entry</h2>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={() => setShowPreview(!showPreview)} className="hidden lg:flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black border bg-white border-slate-200 text-slate-600">
            {showPreview ? <Edit3 size={16}/> : <Eye size={16}/>}
            {showPreview ? 'Hide Preview' : 'Show Preview'}
          </button>
          <button onClick={handleSave} className="bg-blue-600 text-white px-8 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
            Save Estimate
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`flex-1 overflow-y-auto p-4 lg:p-10 bg-white border-r border-slate-200 ${showPreview ? 'lg:max-w-4xl xl:max-w-5xl' : 'max-w-6xl mx-auto'}`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer Name</label>
                <input type="text" value={partyName} onChange={(e) => setPartyName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" placeholder="Customer Name" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" />
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Billing Table</h3>
                <button onClick={addItem} className="bg-slate-900 text-white text-[10px] font-black px-4 py-2 rounded-lg flex items-center gap-2">
                  <Plus size={14}/> Add Row
                </button>
              </div>

              <div className="space-y-6">
                {items.map((item) => (
                  <div key={item.id} className="p-6 bg-slate-50 rounded-2xl border border-slate-200 space-y-5 relative group shadow-sm transition-all hover:shadow-md">
                    <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500 transition-colors">
                      <Trash2 size={18}/>
                    </button>

                    {/* Material & Details Row */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Description / Item</label>
                        <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold focus:border-blue-500 outline-none" placeholder="Banner, Flex, etc." />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Material Selection</label>
                        <select value={item.material} onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500">
                          <option value="">Choose Material...</option>
                          {profile.materials.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Optional Notes / Details</label>
                        <input type="text" value={item.details} onChange={(e) => handleItemChange(item.id, 'details', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm" placeholder="Any extra instructions..." />
                      </div>
                    </div>

                    {/* Calculation Row */}
                    <div className="grid grid-cols-2 md:grid-cols-6 gap-4 items-end bg-white p-4 rounded-xl border border-slate-200">
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Size A</label>
                        <input type="number" value={item.sizeA} onChange={(e) => handleItemChange(item.id, 'sizeA', e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Size B</label>
                        <input type="number" value={item.sizeB} onChange={(e) => handleItemChange(item.id, 'sizeB', e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">QTY</label>
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-blue-600 uppercase">SQFT</label>
                        <div className="w-full px-3 py-2 text-sm font-black text-blue-600 text-center bg-blue-50 border border-blue-200 rounded-lg leading-tight">{item.sqFt}</div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase">Rate</label>
                        <input type="number" value={item.rate} onChange={(e) => handleItemChange(item.id, 'rate', e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-right font-black" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-900 uppercase">Total</label>
                        <div className="w-full px-3 py-2 text-sm font-black text-right text-slate-900">₹{Number(item.amount || 0).toFixed(2)}</div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-200 flex flex-col items-end">
               <div className="text-sm font-black text-slate-400 uppercase tracking-widest mb-1">Estimated Total</div>
               <div className="text-4xl font-black text-slate-900 flex items-baseline">
                 <span className="text-blue-600 font-medium text-2xl mr-2">{profile.currencySymbol}</span>
                 {Number(totals.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="hidden lg:block flex-1 bg-slate-100 overflow-y-auto border-l border-slate-200">
             <div className="p-12 scale-[0.65] origin-top">
                <InvoicePreview transaction={{...initialData, partyName, date, invoiceNumber, items, ...totals} as any} profile={profile} />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  Plus, 
  Search, 
  Filter, 
  FileText, 
  Download, 
  Edit, 
  Trash2, 
  ClipboardCheck, 
  Calendar,
  XCircle,
  CheckCircle2,
  Clock
} from 'lucide-react';
import { Transaction, TransactionType, BusinessProfile } from '../types';
import { generateInvoicePDF } from '../utils/pdfGenerator';
import { exportTransactionsToCSV, copyTransactionsToClipboard } from '../utils/csvExporter';

interface TransactionListProps {
  transactions: Transaction[];
  onAdd: () => void;
  onEdit: (t: Transaction) => void;
  onDelete: (id: string) => void;
  profile: BusinessProfile;
}

export const TransactionList: React.FC<TransactionListProps> = ({ transactions, onAdd, onEdit, onDelete, profile }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [statusFilter, setStatusFilter] = useState<'ALL' | 'PAID' | 'UNPAID'>('ALL');

  const filtered = transactions.filter(t => {
    const searchLower = searchTerm.toLowerCase();
    const matchSearch = t.partyName.toLowerCase().includes(searchLower) || 
                       t.invoiceNumber.toLowerCase().includes(searchLower);
    if (!matchSearch) return false;

    if (statusFilter !== 'ALL' && t.status !== statusFilter) return false;
    if (dateFrom && t.date < dateFrom) return false;
    if (dateTo && t.date > dateTo) return false;

    return true;
  });

  const hasActiveFilters = dateFrom || dateTo || statusFilter !== 'ALL';

  const clearFilters = () => {
    setDateFrom('');
    setDateTo('');
    setStatusFilter('ALL');
    setSearchTerm('');
  };

  const handleDownload = async (e: React.MouseEvent, t: Transaction) => {
    e.preventDefault();
    e.stopPropagation();
    try {
      await generateInvoicePDF(t, profile);
    } catch (error) {
      alert("Failed to generate PDF.");
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Recent Estimates</h1>
          <p className="text-slate-500 font-medium">Manage your historical estimates.</p>
        </div>
        <button 
          onClick={onAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs"
        >
          <Plus size={20} />
          <span>New Estimate</span>
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between">
           <div className="relative flex-1 max-w-md">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
             <input 
                type="text" 
                placeholder="Search customer or estimate no..." 
                className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 bg-white text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>

           <div className="flex gap-2">
             <button onClick={() => copyTransactionsToClipboard(filtered)} className="p-2 bg-white border border-slate-300 rounded-xl text-slate-700 hover:bg-slate-50" title="Copy to Sheets">
                <ClipboardCheck size={18} className="text-emerald-600" />
             </button>
             <button onClick={() => exportTransactionsToCSV(filtered, "Estimates_Export")} className="p-2 bg-white border border-slate-300 rounded-xl text-slate-700 hover:bg-slate-50" title="Export CSV">
                <FileText size={18} className="text-blue-600" />
             </button>
             <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center gap-2 px-4 py-2 border rounded-xl text-sm font-bold ${showFilters || hasActiveFilters ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-slate-300 text-slate-700 hover:bg-slate-50'}`}
             >
                <Filter size={16} /> Filter
             </button>
           </div>
        </div>

        {showFilters && (
          <div className="p-4 bg-slate-50/50 border-b border-slate-200">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2 md:col-span-2">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Date Range</label>
                <div className="flex items-center gap-2">
                  <input type="date" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} className="flex-1 px-3 py-2 border border-slate-300 rounded-xl text-sm" />
                  <span className="text-slate-400">to</span>
                  <input type="date" value={dateTo} onChange={(e) => setDateTo(e.target.value)} className="flex-1 px-3 py-2 border border-slate-300 rounded-xl text-sm" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Status</label>
                <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value as any)} className="w-full px-3 py-2 border border-slate-300 rounded-xl text-sm">
                  <option value="ALL">All Status</option>
                  <option value="PAID">Confirmed</option>
                  <option value="UNPAID">Pending</option>
                </select>
              </div>
            </div>
            {hasActiveFilters && (
              <div className="mt-4 flex justify-end">
                <button onClick={clearFilters} className="text-xs font-black text-rose-600 hover:text-rose-700 flex items-center gap-1">
                  <XCircle size={14} /> Clear All Filters
                </button>
              </div>
            )}
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr className="text-left text-xs font-black text-slate-500 uppercase tracking-widest">
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4">Est No.</th>
                <th className="px-6 py-4">Customer</th>
                <th className="px-6 py-4 text-right">Amount</th>
                <th className="px-6 py-4 text-center">Status</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filtered.length === 0 ? (
                <tr><td colSpan={6} className="px-6 py-12 text-center text-slate-500 font-bold">No estimates found.</td></tr>
              ) : (
                filtered.map((t) => (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{new Date(t.date).toLocaleDateString()}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-black text-slate-900">{t.invoiceNumber}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900 font-medium">{t.partyName}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-900 text-right font-black">₹{Number(t.grandTotal || 0).toFixed(2)}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-center">
                      <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${t.status === 'PAID' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                        {t.status === 'PAID' ? <CheckCircle2 size={12} /> : <Clock size={12} />}
                        {t.status === 'PAID' ? 'CONFIRMED' : 'PENDING'}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right">
                      <div className="flex justify-end gap-1">
                        <button onClick={(e) => handleDownload(e, t)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg" title="PDF"><Download size={16} /></button>
                        <button onClick={() => onEdit(t)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg" title="Edit"><Edit size={16} /></button>
                        <button onClick={() => window.confirm("Delete this estimate?") && onDelete(t.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg" title="Delete"><Trash2 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { TrendingUp, CheckCircle, IndianRupee, Download, ClipboardList } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const totalSales = transactions.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const collected = transactions
      .filter(t => t.status === 'PAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const outstanding = transactions
      .filter(t => t.status === 'UNPAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const avgSale = transactions.length > 0 ? totalSales / transactions.length : 0;
    const maxSale = transactions.length > 0 ? Math.max(...transactions.map(t => Number(t.grandTotal || 0))) : 0;

    return { totalSales, collected, outstanding, avgSale, maxSale };
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Estimate Insights</h1>
          <p className="text-slate-500 font-medium">Detailed breakdown of your generated estimates.</p>
        </div>
        <button 
          onClick={() => exportTransactionsToCSV(transactions, "Full_Estimates_Report")}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 text-xs uppercase tracking-widest"
        >
          <Download size={18} />
          Export All (CSV)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <ReportCard title="Gross Estimated" value={stats.totalSales} color="blue" icon={<ClipboardList size={20} />} />
        <ReportCard title="Confirmed Total" value={stats.collected} color="emerald" icon={<CheckCircle size={20} />} />
        <ReportCard title="Pending Total" value={stats.outstanding} color="rose" icon={<IndianRupee size={20} />} />
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50">
           <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">Summary Analytics</h3>
        </div>
        <div className="p-6">
            <div className="space-y-4">
                <SummaryRow label="Total Estimates Count" value={transactions.length.toString()} />
                <SummaryRow label="Average Estimate Value" value={`₹${stats.avgSale.toFixed(2)}`} />
                <SummaryRow label="Highest Single Estimate" value={`₹${stats.maxSale.toFixed(2)}`} />
                <SummaryRow label="Confirmation Rate" value={`${transactions.length > 0 ? ((stats.collected / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
            </div>
        </div>
      </div>
    </div>
  );
};

const ReportCard = ({title, value, color, icon}: any) => {
    const colors: any = {
        blue: 'bg-blue-50 text-blue-700 border-blue-100',
        emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
        rose: 'bg-rose-50 text-rose-700 border-rose-100',
    };
    return (
        <div className={`p-8 rounded-3xl border ${colors[color]} flex flex-col justify-between h-40`}>
            <div className="flex justify-between items-start">
                 <h4 className="text-xs font-black uppercase tracking-widest opacity-80">{title}</h4>
                 <div className="p-2 bg-white/50 rounded-xl">{icon}</div>
            </div>
            <p className="text-3xl font-black mt-2">₹{value.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</p>
        </div>
    );
}

const SummaryRow = ({label, value}: any) => (
    <div className="flex justify-between items-center py-3 border-b border-slate-50 last:border-0">
        <span className="text-sm font-bold text-slate-500">{label}</span>
        <span className="text-sm font-black text-slate-900">{value}</span>
    </div>
);

import { GoogleGenAI } from "@google/genai";
import { Transaction } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const generateBusinessInsight = async (transactions: Transaction[], query: string): Promise<string> => {
  if (!navigator.onLine) {
    return "Error: You are currently offline. AI insights require a network connection.";
  }

  const ai = getAiClient();
  if (!ai) return "Please configure your API Key to use AI insights.";

  const summary = {
    totalEstimatesCount: transactions.length,
    totalEstimatedRevenue: transactions.reduce((acc, curr) => acc + curr.grandTotal, 0),
    recentEstimates: transactions.slice(0, 10).map(t => ({
      date: t.date,
      customer: t.partyName,
      amount: t.grandTotal,
      status: t.status === 'PAID' ? 'Confirmed' : 'Pending'
    }))
  };

  const prompt = `
    You are a professional business advisor.
    Summary of Estimate Data: ${JSON.stringify(summary, null, 2)}
    User Query: "${query}"
    Provide a data-driven markdown response. Focus on estimate trends, customer behavior, and potential revenue. Use the word 'Estimates' instead of 'Sales' or 'Invoices'.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insight generated.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error analyzing data. Please check your internet connection.";
  }
};

