import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, ArrowLeft, Eye, EyeOff, Save, ChevronDown } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile }) => {
  const [partyName, setPartyName] = useState('');
  const [billingAddress, setBillingAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setBillingAddress(initialData.billingAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      setInvoiceNumber(`EST-${Math.floor(1000 + Math.random() * 9000)}`);
      setStatus(profile.defaultStatus || 'UNPAID');
    }
  }, [initialData, profile.defaultStatus]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        const a = field === 'sizeA' ? Number(value) : Number(updated.sizeA);
        const b = field === 'sizeB' ? Number(value) : Number(updated.sizeB);
        const q = field === 'quantity' ? Number(value) : Number(updated.quantity);
        const r = field === 'rate' ? Number(value) : Number(updated.rate);

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));
        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + (Number(item.amount) || 0), 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter Customer Name`); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type: TransactionType.SALE,
      invoiceNumber,
      date,
      partyName,
      billingAddress,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-white flex flex-col overflow-hidden">
      {/* Header Bar */}
      <div className="h-16 border-b border-slate-100 px-6 flex items-center justify-between shrink-0 bg-white">
        <div className="flex items-center gap-5">
          <button onClick={onCancel} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400 transition-colors">
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-base font-black text-slate-900 leading-none">Create Estimate</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Real-time Editing Mode</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setShowPreview(!showPreview)} 
            className="flex items-center gap-2 px-5 py-2 rounded-xl text-xs font-black border border-blue-100 text-blue-600 hover:bg-blue-50 transition-all"
          >
            {showPreview ? <EyeOff size={16}/> : <Eye size={16}/>}
            {showPreview ? 'Hide Preview' : 'Show Preview'}
          </button>
          <button 
            onClick={handleSave} 
            className="flex items-center gap-2 bg-blue-600 text-white px-8 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-100 text-xs"
          >
            <Save size={16} />
            Save
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Left Side: Form */}
        <div className="w-full lg:w-[45%] xl:w-[40%] overflow-y-auto bg-white p-6 border-r border-slate-100 custom-scrollbar">
          <div className="max-w-xl mx-auto space-y-8">
            {/* Header Inputs */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Client / Party Name</label>
                <input 
                  type="text" 
                  value={partyName} 
                  onChange={(e) => setPartyName(e.target.value)} 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white transition-all outline-none text-sm font-medium" 
                  placeholder="Who is this for?" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Estimate No.</label>
                <input 
                  type="text" 
                  value={invoiceNumber} 
                  readOnly 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-500 cursor-not-allowed" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Document Date</label>
                <input 
                  type="date" 
                  value={date} 
                  onChange={(e) => setDate(e.target.value)} 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white outline-none text-sm font-medium" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Status & Type</label>
                <div className="flex gap-2">
                  <div className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold flex items-center justify-between text-slate-900">
                    Estimate <ChevronDown size={14} className="text-slate-400" />
                  </div>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as any)} 
                    className={`flex-1 px-4 py-3 border rounded-xl text-sm font-black outline-none transition-all ${status === 'PAID' ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-rose-50 border-rose-100 text-rose-600'}`}
                  >
                    <option value="UNPAID">UNPAID</option>
                    <option value="PAID">PAID</option>
                  </select>
                </div>
              </div>
            </div>

            {/* Address Field */}
            <div className="space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Billing Address</label>
              <textarea 
                value={billingAddress}
                onChange={(e) => setBillingAddress(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white outline-none text-sm min-h-[80px] resize-none"
                placeholder="Optional address details..."
              />
            </div>

            {/* Line Items Section */}
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Line Items</h3>
                <button onClick={addItem} className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-1.5 hover:underline">
                  <Plus size={14}/> Add Row
                </button>
              </div>

              <div className="space-y-4">
                {items.map((item, index) => (
                  <div key={item.id} className="p-5 bg-white rounded-xl border border-slate-100 shadow-sm space-y-4 relative group hover:border-blue-200 transition-all">
                    {items.length > 1 && (
                      <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500">
                        <Trash2 size={16}/>
                      </button>
                    )}

                    {/* Item Top Row */}
                    <div className="grid grid-cols-1 md:grid-cols-12 gap-3">
                      <div className="md:col-span-4 space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Item Description</label>
                        <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full border-b border-slate-200 py-1 text-xs font-medium focus:border-blue-500 outline-none" placeholder="Description" />
                      </div>
                      <div className="md:col-span-5 space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Extra Details / Remarks</label>
                        <input type="text" value={item.details} onChange={(e) => handleItemChange(item.id, 'details', e.target.value)} className="w-full border-b border-slate-200 py-1 text-xs outline-none" placeholder="Details (optional)" />
                      </div>
                      <div className="md:col-span-3 space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Material</label>
                        <select value={item.material} onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} className="w-full border-b border-slate-200 py-1 text-xs outline-none focus:border-blue-500 bg-transparent">
                          <option value="">Material</option>
                          {profile.materials.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                      </div>
                    </div>

                    {/* Item Bottom Row (Calculations) */}
                    <div className="grid grid-cols-4 gap-3">
                      <div className="space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Size (W x H)</label>
                        <div className="flex items-center gap-2">
                          <input type="number" value={item.sizeA} onChange={(e) => handleItemChange(item.id, 'sizeA', e.target.value)} className="w-full border border-slate-200 rounded px-2 py-1 text-xs text-center" placeholder="W" />
                          <span className="text-slate-300 text-[10px]">x</span>
                          <input type="number" value={item.sizeB} onChange={(e) => handleItemChange(item.id, 'sizeB', e.target.value)} className="w-full border border-slate-200 rounded px-2 py-1 text-xs text-center" placeholder="H" />
                        </div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Qty</label>
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', e.target.value)} className="w-full border border-slate-200 rounded px-2 py-1 text-xs text-center font-bold" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-bold text-blue-400 uppercase">Total SqFt (W*H*Q)</label>
                        <div className="w-full px-2 py-1 text-xs font-black text-blue-600 text-center bg-blue-50 border border-blue-100 rounded leading-tight">{item.sqFt}</div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Rate</label>
                        <input type="number" value={item.rate} onChange={(e) => handleItemChange(item.id, 'rate', e.target.value)} className="w-full border border-slate-200 rounded px-2 py-1 text-xs text-right" placeholder="0.00" />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Total Display */}
            <div className="pt-8 flex flex-col items-end">
               <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Estimate Value</div>
               <div className="text-4xl font-black text-slate-900 flex items-center">
                 <span className="text-slate-900 font-bold text-2xl mr-3">{profile.currencySymbol}</span>
                 {Number(totals.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {/* Right Side: Document Preview */}
        {showPreview && (
          <div className="flex-1 bg-slate-50 flex items-start justify-center p-10 overflow-y-auto">
             <div className="scale-[0.85] origin-top shadow-2xl">
                <InvoicePreview 
                  transaction={{
                    ...initialData, 
                    partyName, 
                    billingAddress,
                    date, 
                    invoiceNumber, 
                    items, 
                    ...totals, 
                    status
                  } as any} 
                  profile={profile} 
                />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

