import React, { useRef, useState, useEffect } from 'react';
import { Download, Upload, ShieldCheck, History, Cloud, RefreshCw, CheckCircle2 } from 'lucide-react';
import { Transaction } from '../types';
import { syncToDrive, restoreFromDrive, initGapi } from '../services/googleDriveService';

interface DataManagementProps {
  transactions: Transaction[];
  onImport: (data: Transaction[]) => void;
  lastCloudSync?: string;
  onSyncComplete: () => void;
}

export const DataManagement: React.FC<DataManagementProps> = ({ transactions, onImport, lastCloudSync, onSyncComplete }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [lastAutoBackup, setLastAutoBackup] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'success' | 'error'>('idle');

  useEffect(() => {
    const last = localStorage.getItem('easyin_last_autobackup');
    if (last) setLastAutoBackup(new Date(last).toLocaleString());
    initGapi();
  }, []);

  const handleBackup = () => {
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `easyin_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleCloudSync = async () => {
    setIsSyncing(true);
    setSyncStatus('idle');
    try {
      await syncToDrive(transactions);
      setSyncStatus('success');
      onSyncComplete();
    } catch (err) {
      setSyncStatus('error');
      alert('Cloud Sync failed. Please ensure you are logged in to Google.');
    } finally {
      setIsSyncing(false);
    }
  };

  const handleCloudRestore = async () => {
    if (!window.confirm("This will replace all local data with the cloud backup. Proceed?")) return;
    setIsSyncing(true);
    try {
      const data = await restoreFromDrive();
      if (data) {
        onImport(data);
        alert('Data restored from Cloud successfully!');
      } else {
        alert('No backup file found in your Google Drive.');
      }
    } catch (err) {
      alert('Failed to restore from Cloud.');
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
            if (window.confirm('WARNING: This will replace ALL current data. Are you sure?')) {
                onImport(json);
                alert('Data restored successfully!');
            }
        } else {
            alert('Invalid backup file format.');
        }
      } catch (err) {
        alert('Failed to parse backup file.');
      }
    };
    reader.readAsText(file);
