        callback: handleGoogleCredentialResponse,
      });
    }
  }, []);

  const handleGoogleCredentialResponse = (response: any) => {
    setIsAuthenticating(true);
    const payload = decodeJwt(response.credential);

    if (payload) {
      const googleUser: UserType = {
        id: `google_${payload.sub}`,
        username: payload.name,
        businessName: `${payload.name}'s Business`,
        createdAt: new Date().toISOString(),
        email: payload.email,
        picture: payload.picture,
        googleId: payload.sub
      };

      // Store in local users list if not exists
      const storedUsers: UserType[] = JSON.parse(localStorage.getItem('easyin_users') || '[]');
      if (!storedUsers.some(u => u.id === googleUser.id)) {
        storedUsers.push(googleUser);
        localStorage.setItem('easyin_users', JSON.stringify(storedUsers));
      }

      onLogin(googleUser);
    } else {
      setError('Google Authentication failed. Please try again.');
    }
    setIsAuthenticating(false);
