import React, { useRef, useState, useEffect } from 'react';
import { Download, Upload, ShieldCheck, History } from 'lucide-react';
import { Transaction } from '../types';

interface DataManagementProps {
  transactions: Transaction[];
  onImport: (data: Transaction[]) => void;
  lastCloudSync?: string;
  onSyncComplete: () => void;
}

export const DataManagement: React.FC<DataManagementProps> = ({ transactions, onImport }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [lastAutoBackup, setLastAutoBackup] = useState<string | null>(null);

  useEffect(() => {
    const last = localStorage.getItem('easyin_last_autobackup');
    if (last) setLastAutoBackup(new Date(last).toLocaleString());
  }, []);

  const handleBackup = () => {
    const dataStr = JSON.stringify(transactions, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `easyin_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
            if (window.confirm('WARNING: This will replace ALL current data. Are you sure?')) {
                onImport(json);
                alert('Data restored successfully!');
            }
        } else {
            alert('Invalid backup file format.');
        }
      } catch (err) {
        alert('Failed to parse backup file.');
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6">
       <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">Data Management</h1>
            <p className="text-slate-500 font-medium">Manage your local database and portability.</p>
          </div>
          <div className="flex gap-2">
            {lastAutoBackup && (
              <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-100 rounded-lg text-[10px] font-black uppercase tracking-widest">
                 <ShieldCheck size={14} />
                 Auto-Save: {lastAutoBackup}
              </div>
            )}
          </div>
       </div>

       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-slate-50 text-slate-600 rounded-2xl">
                <Download size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-lg font-black text-slate-900">Manual JSON Export</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Download your complete database as a local JSON file for offline storage or moving to another device.</p>
             </div>
             <button onClick={handleBackup} className="px-8 py-3 bg-white border border-slate-200 text-slate-900 rounded-xl hover:bg-slate-50 font-black w-full shadow-sm uppercase tracking-widest text-xs">
                Download File
             </button>
          </div>

          <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-6">
             <div className="p-4 bg-slate-50 text-slate-600 rounded-2xl">
                <Upload size={40} />
             </div>
             <div className="space-y-2">
                <h3 className="text-lg font-black text-slate-900">Import Local Backup</h3>
                <p className="text-sm text-slate-500 leading-relaxed">Restore data from a previously downloaded .json file. This will overwrite existing local data.</p>
             </div>
             <input type="file" accept=".json" ref={fileInputRef} onChange={handleRestore} className="hidden" />
             <button onClick={() => fileInputRef.current?.click()} className="px-8 py-3 bg-white border border-slate-200 text-slate-900 rounded-xl hover:bg-slate-50 font-black w-full shadow-sm uppercase tracking-widest text-xs">
                Upload File
             </button>
          </div>
       </div>

       <div className="bg-slate-900 rounded-2xl p-8 text-white relative overflow-hidden">
          <div className="relative z-10 flex flex-col md:flex-row gap-8 items-center">
             <div className="bg-white/10 p-4 rounded-2xl">
                <History size={48} className="text-blue-400" />
             </div>
             <div className="space-y-2 text-center md:text-left">
                <h4 className="text-lg font-black uppercase tracking-tight">Local-First Security</h4>
                <p className="text-slate-400 text-sm leading-relaxed">
                   Your business records are stored strictly in your browser's private database. 
                   We do not store your data on any central servers. Please export your data regularly 
                   to prevent loss if you clear your browser cache or reset your device.
                </p>
             </div>
          </div>
          <div className="absolute top-0 right-0 p-8 opacity-10">
             <ShieldCheck size={120} />
          </div>
       </div>
    </div>
  );
};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { Transaction, BusinessProfile } from "../types";

export const generateInvoicePDF = (transaction: Transaction, profile: BusinessProfile) => {
  try {
    const doc = new jsPDF('p', 'mm', 'a4');
    const themeRGB: [number, number, number] = hexToRgb(profile.pdfThemeColor || "#2563eb");
    const currencyPrefix = profile.currencySymbol === '₹' ? 'Rs.' : profile.currencySymbol;

    // 1. Watermark Text
    doc.setFontSize(60).setTextColor(245, 245, 245).setFont(undefined, 'bold');
    doc.text("ESTIMATE", 196, 25, { align: 'right' });

    // 2. Main Title
    doc.setFontSize(28).setTextColor(themeRGB[0], themeRGB[1], themeRGB[2]).setFont(undefined, 'bold');
    doc.text("ESTIMATE DOCUMENT", 14, 25);

    doc.setFontSize(10).setTextColor(150, 150, 150).setFont(undefined, 'bold');
    doc.text("OFFICIAL RECORD", 14, 32);

    // 3. Document Details (Top Right)
    doc.setFontSize(10).setTextColor(80, 80, 80).setFont(undefined, 'normal');
    doc.text(`Estimate #: ${transaction.invoiceNumber}`, 196, 40, { align: 'right' });
    doc.text(`Date: ${transaction.date}`, 196, 46, { align: 'right' });

    // 4. Status Badge
    const statusText = transaction.status;
    const badgeColor = statusText === 'PAID' ? [16, 163, 74] : [225, 29, 72]; // emerald-600 : rose-600
    doc.setDrawColor(badgeColor[0], badgeColor[1], badgeColor[2]);
    doc.setLineWidth(0.5);
    doc.roundedRect(166, 52, 30, 8, 1, 1, 'D');
    doc.setFontSize(8).setTextColor(badgeColor[0], badgeColor[1], badgeColor[2]).setFont(undefined, 'bold');
    doc.text(statusText, 181, 57.5, { align: 'center' });

    // 5. Customer Details
    doc.setDrawColor(240, 240, 240);
    doc.line(14, 65, 196, 65);

    doc.setFontSize(9).setTextColor(160, 160, 160).setFont(undefined, 'bold');
    doc.text("BILLED TO", 14, 75);

    doc.setFontSize(16).setTextColor(30, 30, 30).setFont(undefined, 'bold');
    doc.text(transaction.partyName || "-", 14, 84);

    doc.setFontSize(10).setTextColor(100, 100, 100).setFont(undefined, 'normal');
    const splitAddress = doc.splitTextToSize(transaction.billingAddress || "-", 80);
    doc.text(splitAddress, 14, 91);

    // 6. Table Generation
    const headers = ["#", "Description", "Details", "Material", "Size", "Qty", "Total SqFt", "Rate", "Amount"];
    const tableRows = transaction.items.map((item, idx) => [
      idx + 1,
      item.description || "-",
      item.details || "-",
      item.material || "-",
      `${item.sizeA}x${item.sizeB}`,
      item.quantity,
      item.sqFt,
      Number(item.rate || 0).toFixed(2),
      Number(item.amount || 0).toFixed(2)
    ]);

    autoTable(doc, {
      head: [headers],
      body: tableRows,
      startY: 110,
      theme: 'grid',
      headStyles: { fillColor: themeRGB, textColor: 255, fontSize: 8, fontStyle: 'bold' },
      bodyStyles: { fontSize: 8, textColor: 60 },
      columnStyles: {
        0: { halign: 'center', cellWidth: 10 },
        4: { halign: 'center' },
        5: { halign: 'center' },
        6: { halign: 'center' },
        7: { halign: 'right' },
        8: { halign: 'right', fontStyle: 'bold', textColor: 20 }
      },
      styles: { cellPadding: 3 }
    });

    // 7. Total Amount Box
    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(themeRGB[0], themeRGB[1], themeRGB[2]);
    doc.roundedRect(126, finalY - 8, 70, 15, 1, 1, 'F');

    doc.setFontSize(10).setTextColor(255).setFont(undefined, 'bold');
    doc.text("TOTAL AMOUNT", 132, finalY + 1.5);

    const amountStr = `${currencyPrefix} ${Number(transaction.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}`;
    doc.setFontSize(14).text(amountStr, 192, finalY + 1.5, { align: 'right' });

    // 8. Terms & Conditions
    doc.setFontSize(9).setTextColor(160, 160, 160).setFont(undefined, 'bold');
    doc.text("TERMS & CONDITIONS", 14, finalY + 25);

    doc.setFontSize(9).setTextColor(100, 100, 100).setFont(undefined, 'italic');
    const footerText = profile.pdfFooterNote || "Thank you for your business! Goods once sold will not be taken back.";
    const splitFooter = doc.splitTextToSize(footerText, 100);
    doc.text(splitFooter, 14, finalY + 31);

    // 9. Signature
    const bottomY = doc.internal.pageSize.getHeight() - 40;
    doc.setDrawColor(220, 220, 220);
    doc.line(146, bottomY, 196, bottomY);
    doc.setFontSize(9).setTextColor(150).setFont(undefined, 'bold');
    doc.text("Authorized Signatory", 171, bottomY + 5, { align: 'center' });

    // 10. Footer Timestamp
    doc.setFontSize(7).setTextColor(200).setFont(undefined, 'bold');
    const timestamp = `Generated using EasyIn Invoicing • Date: ${new Date().toLocaleString()}`;
    doc.text(timestamp, 105, doc.internal.pageSize.getHeight() - 10, { align: 'center' });

    doc.save(`Estimate_${transaction.invoiceNumber}.pdf`);
  } catch (error) {
