    const currencyPrefix = profile.currencySymbol === '₹' ? 'Rs.' : profile.currencySymbol;

    // 1. Watermark Text
    doc.setFontSize(60).setTextColor(245, 245, 245).setFont(undefined, 'bold');
    doc.text("ESTIMATE", 196, 25, { align: 'right' });

