import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { 
  TrendingUp, 
  CheckCircle2,
  Clock,
  ShoppingCart,
  ArrowUpRight,
  ArrowDownRight
} from 'lucide-react';
import { Transaction, TransactionType } from '../types';

interface DashboardProps {
  transactions: Transaction[];
  onAddInvoice: () => void;
  onNavigate: (tab: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ transactions, onAddInvoice, onNavigate }) => {
  const stats = useMemo(() => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);
    const purchases = transactions.filter(t => t.type === TransactionType.PURCHASE);

    const totalSales = sales.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const collected = sales.filter(t => t.status === 'PAID').reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const pendingSales = sales.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const totalPurchases = purchases.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const cashOut = purchases.filter(t => t.status === 'PAID').reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    return { totalSales, collected, pendingSales, totalPurchases, cashOut };
  }, [transactions]);

  const chartData = [
    { name: 'Total Sales', amount: stats.totalSales, color: '#2563eb' },
    { name: 'Total Purchases', amount: stats.totalPurchases, color: '#9333ea' },
    { name: 'Outstanding', amount: stats.pendingSales, color: '#f43f5e' },
  ];

  const profit = stats.totalSales - stats.totalPurchases;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Business Overview</h1>
          <p className="text-slate-500 font-medium">Tracking your cash flow and operations.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={onAddInvoice} className="bg-blue-600 text-white px-8 py-3 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
            New Sale
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Sales" amount={stats.totalSales} icon={<TrendingUp size={20} />} color="blue" />
        <StatCard title="Total Purchases" amount={stats.totalPurchases} icon={<ShoppingCart size={20} />} color="purple" />
        <StatCard title="Sales Collected" amount={stats.collected} icon={<CheckCircle2 size={20} />} color="emerald" />
        <StatCard title="Net Profit/Loss" amount={profit} icon={profit >= 0 ? <ArrowUpRight size={20} /> : <ArrowDownRight size={20} />} color={profit >= 0 ? "emerald" : "rose"} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">Financial Performance</h3>
          </div>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ left: 0, right: 0, top: 10, bottom: 0 }}>
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontWeight: 'bold', fill: '#94a3b8', fontSize: 10 }} dy={10} />
                <Tooltip 
                  cursor={{ fill: '#f1f5f9' }} 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', padding: '12px' }}
                />
                <Bar dataKey="amount" radius={[8, 8, 0, 0]} barSize={60}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
           <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-8">Quick Insights</h3>
           <div className="space-y-6">
              <StatusProgress label="Paid vs Total Sales" value={stats.collected} total={stats.totalSales} color="bg-blue-500" />
              <StatusProgress label="Pending Receivables" value={stats.pendingSales} total={stats.totalSales} color="bg-rose-500" />
              <div className="pt-6 border-t border-slate-100">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Operating Summary</p>
                 <div className="flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs">
                       <span className="text-slate-500">Gross Margin:</span>
                       <span className="font-bold text-slate-900">{stats.totalSales > 0 ? (((stats.totalSales - stats.totalPurchases) / stats.totalSales) * 100).toFixed(1) : 0}%</span>
                    </div>
                    <div className="flex justify-between items-center text-xs">
                       <span className="text-slate-500">Collection Efficiency:</span>
                       <span className="font-bold text-emerald-600">{stats.totalSales > 0 ? ((stats.collected / stats.totalSales) * 100).toFixed(1) : 0}%</span>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, amount, icon, color }: { title: string, amount: number, icon: any, color: 'blue' | 'emerald' | 'rose' | 'purple' }) => {
  const styles = {
    blue: 'bg-blue-600 text-white',
    emerald: 'bg-emerald-600 text-white',
    rose: 'bg-rose-600 text-white',
    purple: 'bg-purple-600 text-white',
  };
  return (
    <div className={`p-6 rounded-3xl ${styles[color]} shadow-xl shadow-slate-200 transition-transform hover:scale-[1.02] relative overflow-hidden group`}>
      <div className="relative z-10">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-[9px] font-black uppercase tracking-[0.2em] opacity-70">{title}</h3>
          <div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md">{icon}</div>
        </div>
        <p className="text-2xl font-black tracking-tighter">
          ₹{Math.abs(amount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
        </p>
      </div>
      <div className="absolute top-0 right-0 p-4 opacity-5 transform group-hover:scale-110 transition-transform">
         {icon}
      </div>
    </div>
  );
};

const StatusProgress = ({ label, value, total, color }: any) => {
  const percentage = total > 0 ? (value / total) * 100 : 0;
  return (
    <div className="space-y-2">
       <div className="flex justify-between items-center">
          <span className="text-[10px] font-bold text-slate-500 uppercase">{label}</span>
          <span className="text-[10px] font-black text-slate-900">{percentage.toFixed(0)}%</span>
       </div>
       <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full ${color} rounded-full`} style={{ width: `${percentage}%` }}></div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, ArrowLeft, Eye, EyeOff, Save, Tag, ShoppingCart } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
  type?: TransactionType;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile, type = TransactionType.SALE }) => {
  const [partyName, setPartyName] = useState('');
  const [billingAddress, setBillingAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(type === TransactionType.SALE);

  const CURRENCY_SYMBOL = profile.currencySymbol === '₹' ? '₹' : profile.currencySymbol;

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setBillingAddress(initialData.billingAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      const prefix = type === TransactionType.SALE ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
      setStatus(profile.defaultStatus || 'UNPAID');
    }
  }, [initialData, profile.defaultStatus, type]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        const a = field === 'sizeA' ? Number(value) : Number(updated.sizeA);
        const b = field === 'sizeB' ? Number(value) : Number(updated.sizeB);
        const q = field === 'quantity' ? Number(value) : Number(updated.quantity);
        const r = field === 'rate' ? Number(value) : Number(updated.rate);

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));
        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + (Number(item.amount) || 0), 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    const partyLabel = type === TransactionType.SALE ? 'Customer' : 'Supplier';
    if (!partyName) { alert(`Please enter ${partyLabel} Name`); return; }
    if (!invoiceNumber) { alert("Please enter Reference Number"); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type,
      invoiceNumber,
      date,
      partyName,
      billingAddress,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-[#f8fafc] flex flex-col overflow-hidden text-slate-900">
      <div className="h-16 border-b border-slate-200 px-6 flex items-center justify-between shrink-0 bg-white">
        <div className="flex items-center gap-5">
          <button onClick={onCancel} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400 transition-colors">
            <ArrowLeft size={20} />
          </button>
          <div className="flex items-center gap-3">
             <div className={`p-2 rounded-lg text-white ${type === TransactionType.SALE ? 'bg-blue-600' : 'bg-purple-600'}`}>
                {type === TransactionType.SALE ? <Tag size={18} /> : <ShoppingCart size={18} />}
             </div>
             <div>
                <h2 className="text-sm font-black text-slate-900 leading-none">Record {type === TransactionType.SALE ? 'Sale Estimate' : 'Purchase Bill'}</h2>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Transaction Ref: {invoiceNumber}</p>
             </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {type === TransactionType.SALE && (
            <button 
              onClick={() => setShowPreview(!showPreview)} 
              className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black border border-slate-200 text-slate-600 hover:bg-slate-50 transition-all uppercase tracking-widest"
            >
              {showPreview ? <EyeOff size={14}/> : <Eye size={14}/>}
              {showPreview ? 'Hide Preview' : 'Show Preview'}
            </button>
          )}
          <button 
            onClick={handleSave} 
            className={`flex items-center gap-2 text-white px-8 py-2.5 rounded-xl transition-all font-black shadow-lg text-[10px] uppercase tracking-widest ${type === TransactionType.SALE ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-purple-600 hover:bg-purple-700 shadow-purple-100'}`}
          >
            <Save size={14} />
            Save {type === TransactionType.SALE ? 'Estimate' : 'Bill'}
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`w-full ${showPreview ? 'lg:w-[40%] xl:w-[30%]' : 'max-w-3xl mx-auto'} overflow-y-auto bg-white p-6 border-r border-slate-200 custom-scrollbar`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 gap-6">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{type === TransactionType.SALE ? 'Customer' : 'Supplier'} Name</label>
                <input 
                  type="text" 
                  value={partyName} 
                  onChange={(e) => setPartyName(e.target.value)} 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white transition-all outline-none text-sm font-bold" 
                  placeholder={type === TransactionType.SALE ? "Customer Name" : "Supplier Name"} 
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{type === TransactionType.SALE ? 'Estimate' : 'Bill'} No.</label>
                <input 
                  type="text" 
                  value={invoiceNumber} 
                  onChange={(e) => setInvoiceNumber(e.target.value)} 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white transition-all outline-none text-sm font-black" 
                  placeholder="REF-0000" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Document Date</label>
                  <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm font-bold" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Status</label>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as any)} 
                    className={`w-full px-4 py-3 border rounded-xl text-sm font-black outline-none transition-all ${status === 'PAID' ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-rose-50 border-rose-100 text-rose-600'}`}
                  >
                    <option value="UNPAID">{type === TransactionType.SALE ? 'PENDING' : 'UNPAID'}</option>
                    <option value="PAID">{type === TransactionType.SALE ? 'PAID' : 'PAID / OUT'}</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Billing Details / Address</label>
              <textarea 
                value={billingAddress}
                onChange={(e) => setBillingAddress(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white outline-none text-sm min-h-[60px] resize-none font-medium"
                placeholder="Optional notes or details..."
              />
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h3 className="text-[10px] font-black text-slate-900 uppercase tracking-[0.2em]">Items Entry</h3>
                <button onClick={addItem} className={`text-[9px] font-black uppercase tracking-widest flex items-center gap-1.5 hover:underline ${type === TransactionType.SALE ? 'text-blue-600' : 'text-purple-600'}`}>
                  <Plus size={14}/> Add New Line
                </button>
              </div>

              <div className="space-y-4">
                {items.map((item) => (
                  <div key={item.id} className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm space-y-4 relative group hover:border-blue-100 transition-all">
                    {items.length > 1 && (
                      <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500 transition-colors">
                        <Trash2 size={16}/>
                      </button>
                    )}

                    <div className="space-y-3">
                      <div className="space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Item Description</label>
                        <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-[#1e293b] text-white rounded-lg px-3 py-2 text-xs outline-none focus:ring-1 focus:ring-blue-500 font-bold" placeholder="Description..." />
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                         <div className="space-y-1">
                            <label className="text-[8px] font-bold text-slate-400 uppercase">Material / Category</label>
                            <select value={item.material} onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} className="w-full bg-[#1e293b] text-white rounded-lg px-3 py-2 text-xs outline-none font-bold">
                               <option value="">Select Type</option>
                               {profile.materials.map(m => <option key={m} value={m}>{m}</option>)}
                            </select>
                         </div>
                         <div className="space-y-1">
