                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-blue-400 uppercase">SqFt</label>
                          <div className="w-full px-2 py-1.5 text-[10px] font-black text-blue-600 text-center bg-blue-50 rounded border border-blue-100">{item.sqFt}</div>
