            <div className="pt-8 flex flex-col items-end border-t border-slate-100">
               <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Bill Amount</div>
               <div className="text-4xl font-black text-slate-900 flex items-center tracking-tighter">
                 <span className="text-slate-400 font-bold text-lg mr-2">{CURRENCY_SYMBOL}</span>
                 {Number(totals.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {showPreview && type === TransactionType.SALE && (
          <div className="flex-1 bg-slate-100 flex items-start justify-center p-8 overflow-y-auto">
             <div className="scale-[0.85] origin-top shadow-2xl">
                <InvoicePreview 
                  transaction={{
                    ...initialData, 
                    type: TransactionType.SALE,
                    partyName, 
                    billingAddress,
                    date, 
                    invoiceNumber, 
                    items, 
                    ...totals, 
                    status
                  } as any} 
                  profile={profile} 
                />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  Plus, Search, Filter, FileText, Download, Edit, Trash2, ClipboardCheck, XCircle, CheckCircle2, Clock, Tag, ShoppingCart
} from 'lucide-react';
import { Transaction, BusinessProfile, TransactionType } from '../types';
import { generateInvoicePDF } from '../utils/pdfGenerator';
import { exportTransactionsToCSV, copyTransactionsToClipboard } from '../utils/csvExporter';

interface TransactionListProps {
  transactions: Transaction[];
  onAdd: () => void;
  onEdit: (t: Transaction) => void;
  onDelete: (id: string) => void;
  profile: BusinessProfile;
  type?: TransactionType;
}

export const TransactionList: React.FC<TransactionListProps> = ({ transactions, onAdd, onEdit, onDelete, profile, type = TransactionType.SALE }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [statusFilter, setStatusFilter] = useState<'ALL' | 'PAID' | 'UNPAID'>('ALL');

  const filtered = transactions.filter(t => {
    const searchLower = searchTerm.toLowerCase();
    const matchSearch = t.partyName.toLowerCase().includes(searchLower) || t.invoiceNumber.toLowerCase().includes(searchLower);
    if (!matchSearch) return false;
    if (statusFilter !== 'ALL' && t.status !== statusFilter) return false;
    if (dateFrom && t.date < dateFrom) return false;
    if (dateTo && t.date > dateTo) return false;
    return true;
  });

  const clearFilters = () => {
    setDateFrom(''); setDateTo(''); setStatusFilter('ALL'); setSearchTerm('');
  };

  const handleDownload = async (e: React.MouseEvent, t: Transaction) => {
    e.stopPropagation();
    try { await generateInvoicePDF(t, profile); } catch (e) { alert("Failed to generate PDF."); }
  };

  const isSale = type === TransactionType.SALE;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            {isSale ? <Tag className="text-blue-600" /> : <ShoppingCart className="text-purple-600" />}
            {isSale ? 'Sales Estimates' : 'Purchase Bills'}
          </h1>
          <p className="text-slate-500 font-medium">{isSale ? 'History of all sales estimates.' : 'Records of materials and services purchased.'}</p>
        </div>
        <button 
          onClick={onAdd}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl transition-all font-black shadow-lg text-white uppercase tracking-widest text-[10px] ${isSale ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-purple-600 hover:bg-purple-700 shadow-purple-200'}`}
        >
          <Plus size={18} />
          <span>Record New {isSale ? 'Estimate' : 'Purchase'}</span>
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-5 border-b border-slate-100 bg-white flex flex-col md:flex-row gap-4 justify-between items-center">
           <div className="relative flex-1 w-full md:max-w-md">
             <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
             <input 
                type="text" 
                placeholder={isSale ? "Search customer or estimate no..." : "Search supplier or bill no..."} 
                className="w-full pl-12 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 text-sm font-medium outline-none transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>

           <div className="flex gap-2 w-full md:w-auto">
             <button onClick={() => copyTransactionsToClipboard(filtered)} className="flex-1 md:flex-none p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:bg-slate-50 hover:text-emerald-600 transition-colors" title="Copy for Sheets">
                <ClipboardCheck size={20} />
             </button>
             <button onClick={() => exportTransactionsToCSV(filtered, isSale ? "Estimates_Export" : "Purchases_Export")} className="flex-1 md:flex-none p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:bg-slate-50 hover:text-blue-600 transition-colors" title="Export CSV">
                <FileText size={20} />
             </button>
             <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center gap-2 px-6 py-2.5 border rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${showFilters || (dateFrom || dateTo || statusFilter !== 'ALL') ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}
             >
                <Filter size={14} /> Filter
             </button>
           </div>
        </div>

        {showFilters && (
          <div className="p-6 bg-slate-50 border-b border-slate-200 animate-in slide-in-from-top duration-300">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2 md:col-span-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Date Range Selection</label>
                <div className="flex items-center gap-3">
                  <input type="date" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} className="flex-1 px-4 py-2 bg-white border border-slate-200 rounded-xl text-sm font-bold outline-none" />
                  <span className="text-slate-300 font-black">TO</span>
                  <input type="date" value={dateTo} onChange={(e) => setDateTo(e.target.value)} className="flex-1 px-4 py-2 bg-white border border-slate-200 rounded-xl text-sm font-bold outline-none" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Status Filter</label>
                <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value as any)} className="w-full px-4 py-2 bg-white border border-slate-200 rounded-xl text-sm font-bold outline-none">
                  <option value="ALL">ALL RECORDS</option>
                  <option value="PAID">SETTLED / PAID</option>
                  <option value="UNPAID">PENDING / UNPAID</option>
                </select>
              </div>
            </div>
            {(dateFrom || dateTo || statusFilter !== 'ALL') && (
              <div className="mt-4 flex justify-end">
                <button onClick={clearFilters} className="text-[10px] font-black text-rose-500 hover:text-rose-700 flex items-center gap-1 uppercase tracking-widest">
                  <XCircle size={14} /> Clear All Filters
                </button>
              </div>
            )}
          </div>
        )}

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-[#f8fafc] border-b border-slate-200">
              <tr className="text-left text-[9px] font-black text-slate-400 uppercase tracking-widest">
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Ref No.</th>
                <th className="px-6 py-5">{isSale ? 'Customer' : 'Supplier'}</th>
                <th className="px-6 py-5 text-right">Amount</th>
                <th className="px-6 py-5 text-center">Status</th>
                <th className="px-6 py-5 text-right">Options</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filtered.length === 0 ? (
                <tr><td colSpan={6} className="px-6 py-16 text-center text-slate-400 font-bold uppercase tracking-widest text-xs">No records found.</td></tr>
              ) : (
                filtered.map((t) => (
                  <tr key={t.id} className="hover:bg-slate-50/80 transition-colors group">
                    <td className="px-6 py-4 whitespace-nowrap text-xs font-bold text-slate-500">{new Date(t.date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-xs font-black text-slate-900">{t.invoiceNumber}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-xs text-slate-900 font-bold">{t.partyName}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-xs text-slate-900 text-right font-black">₹{Number(t.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-center">
                      <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest border ${t.status === 'PAID' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-rose-50 text-rose-600 border-rose-100'}`}>
                        {t.status === 'PAID' ? <CheckCircle2 size={12} /> : <Clock size={12} />}
                        {t.status === 'PAID' ? 'SETTLED' : 'PENDING'}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right">
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        {isSale && <button onClick={(e) => handleDownload(e, t)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl" title="Download PDF"><Download size={16} /></button>}
                        <button onClick={() => onEdit(t)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl" title="Edit Entry"><Edit size={16} /></button>
                        <button onClick={() => window.confirm("Permanently delete this entry?") && onDelete(t.id)} className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl" title="Delete"><Trash2 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Settings } from './components/Settings';
import { UnitConverter } from './components/UnitConverter';
import { Auth } from './components/Auth';
import { Transaction, BusinessProfile, User, TransactionType } from './types';

const DEFAULT_MATERIALS = [
  "Regular Flex", "B.B. Reg. Flex", "Star Flex", "Vinyl", "Vinyl + Lam",
  "Vinyl + Foamsheet", "One Way", "Retro Vinyl", "Transperant Vinyl",
  "Backlit", "Vinyl + Lam + Foamsheet", "Foamsheet"
];

const DEFAULT_PROFILE: BusinessProfile = {
  currencySymbol: '₹',
  defaultStatus: 'UNPAID',
  materials: DEFAULT_MATERIALS,
  pdfFooterNote: 'Thank you for your business!',
  showSqFtInPdf: true,
  showMaterialInPdf: true,
  pdfThemeColor: '#2563eb',
  pdfAccentColor: '#1e40af',
  minSqFtPerPiece: 0,
  minItemAmount: 0
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  useEffect(() => {
    const savedTxns = localStorage.getItem('easyin_transactions_v2');
    if (savedTxns) setTransactions(JSON.parse(savedTxns));

    const savedProfile = localStorage.getItem('easyin_profile_v2');
    if (savedProfile) {
      setBusinessProfile({ ...DEFAULT_PROFILE, ...JSON.parse(savedProfile) });
    }

    const savedUser = localStorage.getItem('easyin_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('easyin_transactions_v2', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('easyin_profile_v2', JSON.stringify(businessProfile));
  }, [businessProfile]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('easyin_current_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('easyin_current_user');
    }
  }, [currentUser]);

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleLogout = () => {
    if (window.confirm("Are you sure you want to logout?")) {
      localStorage.removeItem('easyin_current_user');
      setCurrentUser(null);
      setActiveTab('dashboard');
      setViewState('list');
      setEditingTransaction(null);
    }
  };

  const handleNavigation = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  if (!currentUser) {
    return <Auth onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard transactions={transactions} onAddInvoice={() => { setActiveTab('sales'); setViewState('form'); }} onNavigate={handleNavigation} />;

      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
              type={TransactionType.SALE}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions.filter(t => t.type === TransactionType.SALE)}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
            profile={businessProfile}
            type={TransactionType.SALE}
          />
        );

      case 'purchases':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
              type={TransactionType.PURCHASE}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions.filter(t => t.type === TransactionType.PURCHASE)}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
            profile={businessProfile}
            type={TransactionType.PURCHASE}
          />
        );

      case 'reports': return <Reports transactions={transactions} />;
      case 'converter': return <UnitConverter />;
      case 'data': return <DataManagement transactions={transactions} onImport={setTransactions} lastCloudSync={businessProfile.lastCloudSync} onSyncComplete={() => setBusinessProfile(p => ({...p, lastCloudSync: new Date().toISOString()}))} />;
      case 'settings': return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      default: return <Dashboard transactions={transactions} onAddInvoice={() => { setActiveTab('sales'); setViewState('form'); }} onNavigate={handleNavigation} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigation} user={currentUser} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { TrendingUp, CheckCircle, IndianRupee, Download, ClipboardList, ShoppingBag } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);
    const purchases = transactions.filter(t => t.type === TransactionType.PURCHASE);

    const totalSales = sales.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const totalPurchases = purchases.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const collected = sales
      .filter(t => t.status === 'PAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const outstandingSales = sales
      .filter(t => t.status === 'UNPAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const profit = totalSales - totalPurchases;

    return { totalSales, totalPurchases, collected, outstandingSales, profit };
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Business Reports</h1>
          <p className="text-slate-500 font-medium">Full analysis of sales, purchases, and profits.</p>
        </div>
        <button 
          onClick={() => exportTransactionsToCSV(transactions, "Full_Business_Report")}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 text-xs uppercase tracking-widest"
        >
          <Download size={18} />
          Export All (CSV)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <ReportCard title="Total Sales" value={stats.totalSales} color="blue" icon={<ClipboardList size={20} />} />
        <ReportCard title="Total Purchases" value={stats.totalPurchases} color="purple" icon={<ShoppingBag size={20} />} />
        <ReportCard title="Net Profit/Loss" value={stats.profit} color={stats.profit >= 0 ? "emerald" : "rose"} icon={<IndianRupee size={20} />} />
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50">
           <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">Financial Summary</h3>
        </div>
        <div className="p-6">
            <div className="space-y-4">
                <SummaryRow label="Total Sales Count" value={transactions.filter(t => t.type === TransactionType.SALE).length.toString()} />
                <SummaryRow label="Total Purchases Count" value={transactions.filter(t => t.type === TransactionType.PURCHASE).length.toString()} />
                <SummaryRow label="Total Cash In (Sales PAID)" value={`₹${stats.collected.toFixed(2)}`} />
                <SummaryRow label="Outstanding Sales" value={`₹${stats.outstandingSales.toFixed(2)}`} />
                <SummaryRow label="Profit Margin" value={`${stats.totalSales > 0 ? ((stats.profit / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
            </div>
        </div>
      </div>
    </div>
  );
};

const ReportCard = ({title, value, color, icon}: any) => {
    const colors: any = {
        blue: 'bg-blue-50 text-blue-700 border-blue-100',
        emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
        rose: 'bg-rose-50 text-rose-700 border-rose-100',
        purple: 'bg-purple-50 text-purple-700 border-purple-100',
    };
    return (
        <div className={`p-8 rounded-3xl border ${colors[color]} flex flex-col justify-between h-40`}>
            <div className="flex justify-between items-start">
                 <h4 className="text-xs font-black uppercase tracking-widest opacity-80">{title}</h4>
                 <div className="p-2 bg-white/50 rounded-xl">{icon}</div>
            </div>
            <p className="text-3xl font-black mt-2">₹{value.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</p>
        </div>
    );
}

const SummaryRow = ({label, value}: any) => (
    <div className="flex justify-between items-center py-3 border-b border-slate-50 last:border-0">
        <span className="text-sm font-bold text-slate-500">{label}</span>
        <span className="text-sm font-black text-slate-900">{value}</span>
    </div>
);

