          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TransactionList } from './components/TransactionList';
import { TransactionForm } from './components/TransactionForm';
import { Reports } from './components/Reports';
import { DataManagement } from './components/DataManagement';
import { Settings } from './components/Settings';
import { UnitConverter } from './components/UnitConverter';
import { Auth } from './components/Auth';
import { Transaction, BusinessProfile, User, TransactionType } from './types';

const DEFAULT_MATERIALS = [
  "Regular Flex", "B.B. Reg. Flex", "Star Flex", "Vinyl", "Vinyl + Lam",
  "Vinyl + Foamsheet", "One Way", "Retro Vinyl", "Transperant Vinyl",
  "Backlit", "Vinyl + Lam + Foamsheet", "Foamsheet"
];

const DEFAULT_PROFILE: BusinessProfile = {
  currencySymbol: '₹',
  defaultStatus: 'UNPAID',
  materials: DEFAULT_MATERIALS,
  pdfFooterNote: 'Thank you for your business!',
  showSqFtInPdf: true,
  showMaterialInPdf: true,
  pdfThemeColor: '#2563eb',
  pdfAccentColor: '#1e40af',
  minSqFtPerPiece: 0,
  minItemAmount: 0
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [businessProfile, setBusinessProfile] = useState<BusinessProfile>(DEFAULT_PROFILE);
  const [viewState, setViewState] = useState<'list' | 'form'>('list');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  useEffect(() => {
    const savedTxns = localStorage.getItem('easyin_transactions_v2');
    if (savedTxns) setTransactions(JSON.parse(savedTxns));

    const savedProfile = localStorage.getItem('easyin_profile_v2');
    if (savedProfile) {
      setBusinessProfile({ ...DEFAULT_PROFILE, ...JSON.parse(savedProfile) });
    }

    const savedUser = localStorage.getItem('easyin_current_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('easyin_transactions_v2', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('easyin_profile_v2', JSON.stringify(businessProfile));
  }, [businessProfile]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('easyin_current_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('easyin_current_user');
    }
  }, [currentUser]);

  const handleSaveTransaction = (transaction: Transaction) => {
    if (editingTransaction) {
      setTransactions(prev => prev.map(t => t.id === transaction.id ? transaction : t));
    } else {
      setTransactions(prev => [transaction, ...prev]);
    }
    setViewState('list');
    setEditingTransaction(null);
  };

  const handleLogout = () => {
    if (window.confirm("Are you sure you want to logout?")) {
      localStorage.removeItem('easyin_current_user');
      setCurrentUser(null);
      setActiveTab('dashboard');
      setViewState('list');
      setEditingTransaction(null);
    }
  };

  const handleNavigation = (tab: string) => {
    setActiveTab(tab);
    setViewState('list');
    setEditingTransaction(null);
  };

  if (!currentUser) {
    return <Auth onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard transactions={transactions} onAddInvoice={() => { setActiveTab('sales'); setViewState('form'); }} onNavigate={handleNavigation} />;

      case 'sales':
        if (viewState === 'form') {
          return (
            <TransactionForm 
              initialData={editingTransaction}
              profile={businessProfile}
              onSave={handleSaveTransaction}
              onCancel={() => {setViewState('list'); setEditingTransaction(null);}}
            />
          );
        }
        return (
          <TransactionList 
            transactions={transactions.filter(t => t.type === TransactionType.SALE)}
            onAdd={() => {setEditingTransaction(null); setViewState('form');}}
            onEdit={(t) => {setEditingTransaction(t); setViewState('form');}}
            onDelete={(id) => setTransactions(prev => prev.filter(t => t.id !== id))}
            profile={businessProfile}
          />
        );

      case 'reports': return <Reports transactions={transactions} />;
      case 'converter': return <UnitConverter />;
      case 'data': return <DataManagement transactions={transactions} onImport={setTransactions} lastCloudSync={businessProfile.lastCloudSync} onSyncComplete={() => setBusinessProfile(p => ({...p, lastCloudSync: new Date().toISOString()}))} />;
      case 'settings': return <Settings profile={businessProfile} onUpdate={setBusinessProfile} />;
      default: return <Dashboard transactions={transactions} onAddInvoice={() => { setActiveTab('sales'); setViewState('form'); }} onNavigate={handleNavigation} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onNavigate={handleNavigation} user={currentUser} onLogout={handleLogout}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { IndianRupee, Download, ClipboardList, CheckCircle } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);

    const totalSales = sales.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const collected = sales
      .filter(t => t.status === 'PAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const outstandingSales = sales
      .filter(t => t.status === 'UNPAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    return { totalSales, collected, outstandingSales };
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Sales Reports</h1>
          <p className="text-slate-500 font-medium">Detailed analysis of your sales estimates and collections.</p>
        </div>
        <button 
          onClick={() => exportTransactionsToCSV(transactions, "Sales_Report")}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 text-xs uppercase tracking-widest"
        >
          <Download size={18} />
          Export All (CSV)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <ReportCard title="Total Sales" value={stats.totalSales} color="blue" icon={<ClipboardList size={20} />} />
        <ReportCard title="Total Collected" value={stats.collected} color="emerald" icon={<CheckCircle size={20} />} />
        <ReportCard title="Outstanding" value={stats.outstandingSales} color="rose" icon={<IndianRupee size={20} />} />
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50">
           <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">Collection Summary</h3>
        </div>
        <div className="p-6">
            <div className="space-y-4">
                <SummaryRow label="Total Estimates Count" value={transactions.filter(t => t.type === TransactionType.SALE).length.toString()} />
                <SummaryRow label="Total Cash Collected" value={`₹${stats.collected.toFixed(2)}`} />
                <SummaryRow label="Total Pending Receivables" value={`₹${stats.outstandingSales.toFixed(2)}`} />
                <SummaryRow label="Collection Percentage" value={`${stats.totalSales > 0 ? ((stats.collected / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
            </div>
        </div>
      </div>
    </div>
  );
};

const ReportCard = ({title, value, color, icon}: any) => {
    const colors: any = {
        blue: 'bg-blue-50 text-blue-700 border-blue-100',
        emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
        rose: 'bg-rose-50 text-rose-700 border-rose-100',
    };
    return (
        <div className={`p-8 rounded-3xl border ${colors[color]} flex flex-col justify-between h-40`}>
            <div className="flex justify-between items-start">
                 <h4 className="text-xs font-black uppercase tracking-widest opacity-80">{title}</h4>
                 <div className="p-2 bg-white/50 rounded-xl">{icon}</div>
            </div>
            <p className="text-3xl font-black mt-2">₹{value.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</p>
        </div>
    );
}

const SummaryRow = ({label, value}: any) => (
    <div className="flex justify-between items-center py-3 border-b border-slate-50 last:border-0">
        <span className="text-sm font-bold text-slate-500">{label}</span>
        <span className="text-sm font-black text-slate-900">{value}</span>
    </div>
);

