import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { 
  TrendingUp, 
  CheckCircle2,
  Clock,
  ShoppingCart,
  Wallet
} from 'lucide-react';
import { Transaction, TransactionType } from '../types';

interface DashboardProps {
  transactions: Transaction[];
  onAddInvoice: () => void;
  onNavigate: (tab: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ transactions, onAddInvoice, onNavigate }) => {
  const stats = useMemo(() => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);
    const purchases = transactions.filter(t => t.type === TransactionType.PURCHASE);

    const totalSales = sales.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const totalPurchases = purchases.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const collected = sales.filter(t => t.status === 'PAID').reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const pendingSales = sales.filter(t => t.status === 'UNPAID').reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const netBalance = totalSales - totalPurchases;

    return { totalSales, totalPurchases, collected, pendingSales, netBalance };
  }, [transactions]);

  const chartData = [
    { name: 'Total Sales', amount: stats.totalSales, color: '#2563eb' },
    { name: 'Purchases', amount: stats.totalPurchases, color: '#9333ea' },
    { name: 'Collected', amount: stats.collected, color: '#10b981' },
    { name: 'Outstanding', amount: stats.pendingSales, color: '#f43f5e' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Business Overview</h1>
          <p className="text-slate-500 font-medium">Tracking your cashflow and performance.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={onAddInvoice} className="bg-blue-600 text-white px-8 py-3 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 uppercase tracking-widest text-xs">
            New Sale
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Sales" amount={stats.totalSales} icon={<TrendingUp size={20} />} color="blue" />
        <StatCard title="Purchases" amount={stats.totalPurchases} icon={<ShoppingCart size={20} />} color="purple" />
        <StatCard title="Net Balance" amount={stats.netBalance} icon={<Wallet size={20} />} color={stats.netBalance >= 0 ? "emerald" : "rose"} />
        <StatCard title="Outstanding" amount={stats.pendingSales} icon={<Clock size={20} />} color="rose" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">Financial Snapshot</h3>
          </div>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ left: 0, right: 0, top: 10, bottom: 0 }}>
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontWeight: 'bold', fill: '#94a3b8', fontSize: 10 }} dy={10} />
                <Tooltip 
                  cursor={{ fill: '#f1f5f9' }} 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', padding: '12px' }}
                />
                <Bar dataKey="amount" radius={[8, 8, 0, 0]} barSize={60}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
           <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-8">Collection Insights</h3>
           <div className="space-y-6">
              <StatusProgress label="Recovery Rate" value={stats.collected} total={stats.totalSales} color="bg-emerald-500" />
              <StatusProgress label="Expense Ratio" value={stats.totalPurchases} total={stats.totalSales} color="bg-purple-500" />
              <div className="pt-6 border-t border-slate-100">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Profitability Analysis</p>
                 <div className="flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs">
                       <span className="text-slate-500">Operating Margin:</span>
                       <span className={`font-bold ${stats.netBalance >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                         {stats.totalSales > 0 ? ((stats.netBalance / stats.totalSales) * 100).toFixed(1) : 0}%
                       </span>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, amount, icon, color }: { title: string, amount: number, icon: any, color: 'blue' | 'emerald' | 'rose' | 'purple' }) => {
  const styles = {
    blue: 'bg-blue-600 text-white shadow-blue-200',
    emerald: 'bg-emerald-600 text-white shadow-emerald-200',
    rose: 'bg-rose-600 text-white shadow-rose-200',
    purple: 'bg-purple-600 text-white shadow-purple-200',
  };
  return (
    <div className={`p-6 rounded-3xl ${styles[color]} shadow-xl transition-transform hover:scale-[1.02] relative overflow-hidden group`}>
      <div className="relative z-10">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-[9px] font-black uppercase tracking-[0.2em] opacity-70">{title}</h3>
          <div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md">{icon}</div>
        </div>
        <p className="text-2xl font-black tracking-tighter">
          ₹{Math.abs(amount).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
        </p>
      </div>
      <div className="absolute top-0 right-0 p-4 opacity-5 transform group-hover:scale-110 transition-transform">
         {icon}
      </div>
    </div>
  );
};

const StatusProgress = ({ label, value, total, color }: any) => {
  const percentage = total > 0 ? Math.min((value / total) * 100, 100) : 0;
  return (
    <div className="space-y-2">
       <div className="flex justify-between items-center">
          <span className="text-[10px] font-bold text-slate-500 uppercase">{label}</span>
          <span className="text-[10px] font-black text-slate-900">{percentage.toFixed(0)}%</span>
       </div>
       <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full ${color} rounded-full`} style={{ width: `${percentage}%` }}></div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Trash2, ArrowLeft, Eye, EyeOff, Save, Tag, ShoppingCart } from 'lucide-react';
import { LineItem, Transaction, TransactionType, BusinessProfile } from '../types';
import { InvoicePreview } from './InvoicePreview';

interface TransactionFormProps {
  onSave: (transaction: Transaction) => void;
  onCancel: () => void;
  initialData?: Transaction | null;
  profile: BusinessProfile;
  type: TransactionType;
}

export const TransactionForm: React.FC<TransactionFormProps> = ({ onSave, onCancel, initialData, profile, type }) => {
  const [partyName, setPartyName] = useState('');
  const [billingAddress, setBillingAddress] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [items, setItems] = useState<LineItem[]>([
    { id: '1', description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }
  ]);
  const [status, setStatus] = useState<'PAID' | 'UNPAID'>('UNPAID');
  const [showPreview, setShowPreview] = useState(true);

  const isSale = type === TransactionType.SALE;
  const themeColor = isSale ? 'bg-blue-600' : 'bg-purple-600';
  const themeBorder = isSale ? 'focus:ring-blue-500' : 'focus:ring-purple-500';
  const themeText = isSale ? 'text-blue-600' : 'text-purple-600';
  const themeShadow = isSale ? 'shadow-blue-100' : 'shadow-purple-100';

  const CURRENCY_SYMBOL = profile.currencySymbol === '₹' ? '₹' : profile.currencySymbol;

  useEffect(() => {
    if (initialData) {
      setPartyName(initialData.partyName);
      setBillingAddress(initialData.billingAddress || '');
      setInvoiceNumber(initialData.invoiceNumber);
      setDate(initialData.date);
      setItems(initialData.items);
      setStatus(initialData.status);
    } else {
      const prefix = isSale ? 'EST' : 'PUR';
      setInvoiceNumber(`${prefix}-${Math.floor(1000 + Math.random() * 9000)}`);
      setStatus(profile.defaultStatus || 'UNPAID');
    }
  }, [initialData, profile.defaultStatus, isSale]);

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const updated = { ...item, [field]: value };
        const a = field === 'sizeA' ? Number(value) : Number(updated.sizeA);
        const b = field === 'sizeB' ? Number(value) : Number(updated.sizeB);
        const q = field === 'quantity' ? Number(value) : Number(updated.quantity);
        const r = field === 'rate' ? Number(value) : Number(updated.rate);

        updated.sqFt = Number((a * b * q).toFixed(2));
        updated.amount = Number((updated.sqFt * r).toFixed(2));
        return updated;
      }
      return item;
    }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Date.now().toString(), description: '', material: '', details: '', sizeA: 0, sizeB: 0, quantity: 1, sqFt: 0, rate: 0, amount: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(i => i.id !== id));
  };

  const totals = useMemo(() => {
    const subTotal = items.reduce((acc, item) => acc + (Number(item.amount) || 0), 0);
    return { subTotal, grandTotal: subTotal };
  }, [items]);

  const handleSave = () => {
    if (!partyName) { alert(`Please enter ${isSale ? 'Customer' : 'Supplier'} Name`); return; }
    if (!invoiceNumber) { alert("Please enter Reference Number"); return; }
    onSave({
      id: initialData?.id || Date.now().toString(),
      type: type,
      invoiceNumber,
      date,
      partyName,
      billingAddress,
      items,
      ...totals,
      status
    });
  };

  return (
    <div className="fixed inset-0 z-[60] bg-[#f8fafc] flex flex-col overflow-hidden text-slate-900">
      <div className="h-16 border-b border-slate-200 px-6 flex items-center justify-between shrink-0 bg-white">
        <div className="flex items-center gap-5">
          <button onClick={onCancel} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400 transition-colors">
            <ArrowLeft size={20} />
          </button>
          <div className="flex items-center gap-3">
             <div className={`p-2 rounded-lg text-white ${themeColor}`}>
                {isSale ? <Tag size={18} /> : <ShoppingCart size={18} />}
             </div>
             <div>
                <h2 className="text-sm font-black text-slate-900 leading-none">Record {isSale ? 'Sale Estimate' : 'Purchase Bill'}</h2>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Ref: {invoiceNumber}</p>
             </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => setShowPreview(!showPreview)} 
            className="hidden md:flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black border border-slate-200 text-slate-600 hover:bg-slate-50 transition-all uppercase tracking-widest"
          >
            {showPreview ? <EyeOff size={14}/> : <Eye size={14}/>}
            {showPreview ? 'Hide Preview' : 'Show Preview'}
          </button>
          <button 
            onClick={handleSave} 
            className={`flex items-center gap-2 text-white px-8 py-2.5 rounded-xl transition-all font-black shadow-lg text-[10px] uppercase tracking-widest ${themeColor} hover:brightness-110 ${themeShadow}`}
          >
            <Save size={14} />
            Save {isSale ? 'Estimate' : 'Purchase'}
          </button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className={`w-full ${showPreview ? 'lg:w-[40%] xl:w-[30%]' : 'max-w-3xl mx-auto'} overflow-y-auto bg-white p-6 border-r border-slate-200 custom-scrollbar`}>
          <div className="space-y-8">
            <div className="grid grid-cols-1 gap-6">
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{isSale ? 'Customer' : 'Supplier'} Name</label>
                <input 
                  type="text" 
                  value={partyName} 
                  onChange={(e) => setPartyName(e.target.value)} 
                  className={`w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-current focus:bg-white transition-all outline-none text-sm font-bold ${themeText}`} 
                  placeholder={isSale ? "Customer Name" : "Supplier Name"} 
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{isSale ? 'Estimate' : 'Bill'} No.</label>
                <input 
                  type="text" 
                  value={invoiceNumber} 
                  onChange={(e) => setInvoiceNumber(e.target.value)} 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white transition-all outline-none text-sm font-black" 
                  placeholder={isSale ? "EST-0000" : "PUR-0000"} 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Date</label>
                  <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none text-sm font-bold" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Status</label>
                  <select 
                    value={status} 
                    onChange={(e) => setStatus(e.target.value as any)} 
                    className={`w-full px-4 py-3 border rounded-xl text-sm font-black outline-none transition-all ${status === 'PAID' ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-rose-50 border-rose-100 text-rose-600'}`}
                  >
                    <option value="UNPAID">PENDING</option>
                    <option value="PAID">PAID</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Address / Notes</label>
              <textarea 
                value={billingAddress}
                onChange={(e) => setBillingAddress(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:bg-white outline-none text-sm min-h-[60px] resize-none font-medium"
                placeholder="Optional party address or bill notes..."
              />
            </div>

            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h3 className="text-[10px] font-black text-slate-900 uppercase tracking-[0.2em]">Line Items</h3>
                <button onClick={addItem} className={`text-[9px] font-black uppercase tracking-widest flex items-center gap-1.5 hover:underline ${themeText}`}>
                  <Plus size={14}/> Add Item
                </button>
              </div>

              <div className="space-y-4">
                {items.map((item) => (
                  <div key={item.id} className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm space-y-4 relative group hover:border-slate-300 transition-all">
                    {items.length > 1 && (
                      <button onClick={() => removeItem(item.id)} className="absolute top-4 right-4 text-slate-300 hover:text-rose-500 transition-colors">
                        <Trash2 size={16}/>
                      </button>
                    )}

                    <div className="space-y-3">
                      <div className="space-y-1">
                        <label className="text-[8px] font-bold text-slate-400 uppercase">Item Description</label>
                        <input type="text" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-[#1e293b] text-white rounded-lg px-3 py-2 text-xs outline-none focus:ring-1 focus:ring-blue-500 font-bold" placeholder="Description..." />
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                         <div className="space-y-1">
                            <label className="text-[8px] font-bold text-slate-400 uppercase">Material</label>
                            <select value={item.material} onChange={(e) => handleItemChange(item.id, 'material', e.target.value)} className="w-full bg-[#1e293b] text-white rounded-lg px-3 py-2 text-xs outline-none font-bold">
                               <option value="">Select Material</option>
                               {profile.materials.map(m => <option key={m} value={m}>{m}</option>)}
                            </select>
                         </div>
                         <div className="space-y-1">
                            <label className="text-[8px] font-bold text-slate-400 uppercase">Remarks</label>
                            <input type="text" value={item.details} onChange={(e) => handleItemChange(item.id, 'details', e.target.value)} className="w-full bg-[#1e293b] text-white rounded-lg px-3 py-2 text-xs outline-none font-bold" placeholder="Notes..." />
                         </div>
                      </div>

                      <div className="grid grid-cols-4 gap-3">
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase">Size (WxH)</label>
                          <div className="flex items-center gap-1">
                            <input type="number" value={item.sizeA} onChange={(e) => handleItemChange(item.id, 'sizeA', e.target.value)} className="w-full bg-[#1e293b] text-white rounded px-2 py-1.5 text-xs text-center font-bold" />
                            <input type="number" value={item.sizeB} onChange={(e) => handleItemChange(item.id, 'sizeB', e.target.value)} className="w-full bg-[#1e293b] text-white rounded px-2 py-1.5 text-xs text-center font-bold" />
                          </div>
                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase">Qty</label>
                          <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', e.target.value)} className="w-full bg-[#1e293b] text-white rounded px-2 py-1.5 text-xs text-center font-black" />
                        </div>
                        <div className="space-y-1">
                          <label className={`text-[8px] font-bold uppercase ${themeText}`}>SqFt</label>
                          <div className={`w-full px-2 py-1.5 text-[10px] font-black text-center rounded border ${isSale ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-purple-50 text-purple-600 border-purple-100'}`}>{item.sqFt}</div>
                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase">Rate</label>
                          <input type="number" value={item.rate} onChange={(e) => handleItemChange(item.id, 'rate', e.target.value)} className="w-full bg-[#1e293b] text-white rounded px-2 py-1.5 text-xs text-right font-black" />
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-8 flex flex-col items-end border-t border-slate-100">
               <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Bill Amount</div>
               <div className="text-4xl font-black text-slate-900 flex items-center tracking-tighter">
                 <span className="text-slate-400 font-bold text-lg mr-2">{CURRENCY_SYMBOL}</span>
                 {Number(totals.grandTotal || 0).toLocaleString('en-IN', { minimumFractionDigits: 2 })}
               </div>
            </div>
          </div>
        </div>

        {showPreview && (
          <div className="flex-1 bg-slate-100 flex items-start justify-center p-8 overflow-y-auto">
             <div className="scale-[0.85] origin-top shadow-2xl">
                <InvoicePreview 
                  transaction={{
                    ...initialData, 
                    type: type,
                    partyName, 
                    billingAddress,
                    date, 
                    invoiceNumber, 
                    items, 
                    ...totals, 
                    status
                  } as any} 
                  profile={profile} 
                />
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  Plus, Search, Filter, FileText, Download, Edit, Trash2, ClipboardCheck, XCircle, CheckCircle2, Clock, Tag, ShoppingCart
} from 'lucide-react';
import { Transaction, BusinessProfile, TransactionType } from '../types';
import { generateInvoicePDF } from '../utils/pdfGenerator';
import { exportTransactionsToCSV, copyTransactionsToClipboard } from '../utils/csvExporter';

interface TransactionListProps {
  transactions: Transaction[];
  onAdd: () => void;
  onEdit: (t: Transaction) => void;
  onDelete: (id: string) => void;
  profile: BusinessProfile;
  type: TransactionType;
}

export const TransactionList: React.FC<TransactionListProps> = ({ transactions, onAdd, onEdit, onDelete, profile, type }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [statusFilter, setStatusFilter] = useState<'ALL' | 'PAID' | 'UNPAID'>('ALL');

  const isSale = type === TransactionType.SALE;

  const filtered = transactions.filter(t => {
    const searchLower = searchTerm.toLowerCase();
    const matchSearch = t.partyName.toLowerCase().includes(searchLower) || t.invoiceNumber.toLowerCase().includes(searchLower);
    if (!matchSearch) return false;
    if (statusFilter !== 'ALL' && t.status !== statusFilter) return false;
    if (dateFrom && t.date < dateFrom) return false;
    if (dateTo && t.date > dateTo) return false;
    return true;
  });

  const clearFilters = () => {
    setDateFrom(''); setDateTo(''); setStatusFilter('ALL'); setSearchTerm('');
  };

  const handleDownload = async (e: React.MouseEvent, t: Transaction) => {
    e.stopPropagation();
    try { await generateInvoicePDF(t, profile); } catch (e) { alert("Failed to generate PDF."); }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            {isSale ? <Tag className="text-blue-600" /> : <ShoppingCart className="text-purple-600" />}
            {isSale ? 'Sales Estimates' : 'Purchase Bills'}
          </h1>
          <p className="text-slate-500 font-medium">History of all recorded {isSale ? 'sales' : 'purchase'} transactions.</p>
        </div>
        <button 
          onClick={onAdd}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl transition-all font-black shadow-lg text-white uppercase tracking-widest text-[10px] ${isSale ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-purple-600 hover:bg-purple-700 shadow-purple-200'}`}
        >
          <Plus size={18} />
          <span>New {isSale ? 'Estimate' : 'Bill'}</span>
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-5 border-b border-slate-100 bg-white flex flex-col md:flex-row gap-4 justify-between items-center">
           <div className="relative flex-1 w-full md:max-w-md">
             <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
             <input 
                type="text" 
                placeholder={`Search ${isSale ? 'customer' : 'supplier'} or number...`} 
                className="w-full pl-12 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 text-sm font-medium outline-none transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>

           <div className="flex gap-2 w-full md:w-auto">
             <button onClick={() => copyTransactionsToClipboard(filtered)} className="flex-1 md:flex-none p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:bg-slate-50 hover:text-emerald-600 transition-colors" title="Copy for Sheets">
                <ClipboardCheck size={20} />
             </button>
             <button onClick={() => exportTransactionsToCSV(filtered, isSale ? "Estimates_Export" : "Purchases_Export")} className="flex-1 md:flex-none p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:bg-slate-50 hover:text-blue-600 transition-colors" title="Export CSV">
                <FileText size={20} />
             </button>
             <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex items-center gap-2 px-6 py-2.5 border rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${showFilters || (dateFrom || dateTo || statusFilter !== 'ALL') ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}
             >
                <Filter size={14} /> Filter
             </button>
           </div>
        </div>

        {showFilters && (
          <div className="p-6 bg-slate-50 border-b border-slate-200 animate-in slide-in-from-top duration-300">
