import React, { useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { IndianRupee, Download, ClipboardList, CheckCircle, ShoppingCart, TrendingUp } from 'lucide-react';
import { exportTransactionsToCSV } from '../utils/csvExporter';

interface ReportsProps {
  transactions: Transaction[];
}

export const Reports: React.FC<ReportsProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const sales = transactions.filter(t => t.type === TransactionType.SALE);
    const purchases = transactions.filter(t => t.type === TransactionType.PURCHASE);

    const totalSales = sales.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const totalPurchases = purchases.reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);
    const profit = totalSales - totalPurchases;

    const collected = sales
      .filter(t => t.status === 'PAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    const outstandingSales = sales
      .filter(t => t.status === 'UNPAID')
      .reduce((acc, t) => acc + Number(t.grandTotal || 0), 0);

    return { totalSales, totalPurchases, profit, collected, outstandingSales };
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">Business Reports</h1>
          <p className="text-slate-500 font-medium">Detailed analysis of your sales, purchases, and cashflow.</p>
        </div>
        <button 
          onClick={() => exportTransactionsToCSV(transactions, "Full_Business_Report")}
          className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl hover:bg-blue-700 transition-all font-black shadow-lg shadow-blue-200 text-xs uppercase tracking-widest"
        >
          <Download size={18} />
          Export All (CSV)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <ReportCard title="Total Sales" value={stats.totalSales} color="blue" icon={<ClipboardList size={20} />} />
        <ReportCard title="Total Purchases" value={stats.totalPurchases} color="purple" icon={<ShoppingCart size={20} />} />
        <ReportCard title="Gross Profit" value={stats.profit} color={stats.profit >= 0 ? "emerald" : "rose"} icon={<TrendingUp size={20} />} />
        <ReportCard title="Outstanding" value={stats.outstandingSales} color="rose" icon={<IndianRupee size={20} />} />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-4 border-b border-slate-200 bg-slate-50">
             <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">Sales Analysis</h3>
          </div>
          <div className="p-6">
              <div className="space-y-4">
                  <SummaryRow label="Total Estimates Count" value={transactions.filter(t => t.type === TransactionType.SALE).length.toString()} />
                  <SummaryRow label="Total Cash Collected" value={`₹${stats.collected.toFixed(2)}`} />
                  <SummaryRow label="Total Pending Receivables" value={`₹${stats.outstandingSales.toFixed(2)}`} />
                  <SummaryRow label="Recovery Efficiency" value={`${stats.totalSales > 0 ? ((stats.collected / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
              </div>
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-4 border-b border-slate-200 bg-slate-50">
             <h3 className="font-black text-slate-800 uppercase tracking-widest text-xs">Expense Analysis</h3>
          </div>
          <div className="p-6">
              <div className="space-y-4">
                  <SummaryRow label="Total Purchase Bills" value={transactions.filter(t => t.type === TransactionType.PURCHASE).length.toString()} />
                  <SummaryRow label="Expenditure Value" value={`₹${stats.totalPurchases.toFixed(2)}`} />
                  <SummaryRow label="Operating Ratio" value={`${stats.totalSales > 0 ? ((stats.totalPurchases / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
                  <SummaryRow label="Net Operating Margin" value={`${stats.totalSales > 0 ? ((stats.profit / stats.totalSales) * 100).toFixed(1) : '0'}%`} />
              </div>
          </div>
        </div>
      </div>
    </div>
  );
};

